-- Poems batch 8
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('c49030cc-3a5e-496a-8cf0-563b2e45bd7a','出塞','鄭錫','唐','唐诗','tang','','[]','關山落葉秋，掩淚望營州。',48,'全唐诗/poet.tang.13000.json','["關山落葉秋，掩淚望營州。", "遼海雲沙暮，幽燕旌斾愁。", "戰餘能送陣，身老未封侯。", "去國三千里，歸心紅粉樓。"]'),
('d1f1f1a3-02d8-492e-b705-619b52b3c453','玉階怨','鄭錫','唐','唐诗','tang','','[]','長門寒水流，高殿曉風秋。',48,'全唐诗/poet.tang.13000.json','["長門寒水流，高殿曉風秋。", "昨夜鴛鴦夢，還陪豹尾游。", "前魚不解泣，共輦豈關羞。", "那及輕身燕，雙飛上玉樓。"]'),
('44b45785-981e-4b6c-815f-8c96bf89fe24','千里思','鄭錫','唐','唐诗','tang','','[]','渭水通胡苑，輪臺望漢關。',48,'全唐诗/poet.tang.13000.json','["渭水通胡苑，輪臺望漢關。", "帛書秋海斷，錦字夜機閑。", "旅夢蟲催曉，邊心雁帶還。", "惟餘兩鄉思，一夕度關山。"]'),
('a656f34a-7eaa-4396-94aa-198921d5610d','襄陽樂','鄭錫','唐','唐诗','tang','','[]','春生峴首東，先煖習池風。',48,'全唐诗/poet.tang.13000.json','["春生峴首東，先煖習池風。", "拂水初含綠，驚林未吐紅。", "渚邊游漢女，桑下問龐公。", "磨滅懷中刺，曾將示孔融。"]'),
('44c15bdc-51ad-4102-b71e-a136afafbd95','送客之江西','鄭錫','唐','唐诗','tang','','["\u9001\u522b"]','乘軺奉紫泥，澤國渺天涯。',48,'全唐诗/poet.tang.13000.json','["乘軺奉紫泥，澤國渺天涯。", "九派春潮滿，孤帆暮雨低。", "草深鶯斷續，花落水東西。", "更有高唐處，知君路不迷。"]'),
('30baa31d-a7ae-4e3a-bd63-bd0bb2d9602b','望月','鄭錫','唐','唐诗','tang','','[]','高堂新月明，虛殿夕風清。',48,'全唐诗/poet.tang.13000.json','["高堂新月明，虛殿夕風清。", "素影紗窗霽，浮涼羽扇輕。", "稍隨微露滴，漸逐曉參橫。", "遙憶雲中詠，蕭條空復情。"]'),
('1b8bb182-515f-4f05-826e-455f0bb635aa','出塞曲','鄭錫','唐','唐诗','tang','','[]','校尉徵兵出塞西，別營分騎過龍溪。',64,'全唐诗/poet.tang.13000.json','["校尉徵兵出塞西，別營分騎過龍溪。", "沙平虜跡風吹盡，霧失烽煙道易迷。", "玉靶半開鴻已落，金河欲渡馬連嘶。", "會當繫取天驕入，不使軍書夜刺閨。"]'),
('a3c557ea-2e73-4d65-87a2-0f19744db796','秦人謠','古之奇','唐','唐诗','tang','','[]','微生祖龍代，却思堯舜道。',72,'全唐诗/poet.tang.13000.json','["微生祖龍代，却思堯舜道。", "何人仕帝庭，拔殺指佞草。", "姦臣弄民柄，天子恣衷抱。", "上下一相蒙，馬鹿遂顛倒。", "中國既板蕩，骨肉安可保。", "人生貴年壽，吾恨死不早。"]'),
('00734d59-0333-4186-aa31-5a036d2315f0','阮客舊居','李陽冰','唐','唐诗','tang','','[]','阮客身何在，仙雲洞口橫。',24,'全唐诗/poet.tang.13000.json','["阮客身何在，仙雲洞口橫。", "人間不到處，今日此中行。"]'),
('cac5c9c8-bdb3-4b45-8902-8ad630c32ca0','酬耿拾遺題贈','嚴維','唐','唐诗','tang','','[]','掩扉常自靜，驛吏忽傳呼。',48,'全唐诗/poet.tang.13000.json','["掩扉常自靜，驛吏忽傳呼。", "水巷驚馴鳥，藜牀起病軀。", "顧身悲欲老，戒子力爲儒。", "明日公西去，煙霞復作徒。"]'),
('62bc9c98-db76-48ad-810d-6cfb2541d2da','酬王侍御西陵渡見寄','嚴維','唐','唐诗','tang','','[]','前年萬里別，昨日一封書。',48,'全唐诗/poet.tang.13000.json','["前年萬里別，昨日一封書。", "郢曲西陵渡，秦官使者車。", "柳塘薰晝日，花水溢春渠。", "若不嫌雞黍，先令掃弊廬。"]'),
('b4b371df-388a-4eac-9f57-1e11c451ffed','酬劉員外見寄','嚴維','唐','唐诗','tang','','[]','蘇耽佐郡時，近出白雲司。',48,'全唐诗/poet.tang.13000.json','["蘇耽佐郡時，近出白雲司。", "藥補清羸疾，窗吟絕妙詞。", "柳塘春水慢，花塢夕陽遲。", "欲識懷君意，明朝訪檝師。"]'),
('5e87f174-5f75-4b2c-9a6a-3858ead274d4','同韓員外宿雲門寺','嚴維','唐','唐诗','tang','','[]','小嶺路難近，仙郎此夕過。',48,'全唐诗/poet.tang.13000.json','["小嶺路難近，仙郎此夕過。", "潭空觀月定，澗靜見雲多。", "竹翠煙深鎖，松聲雨點和。", "萬緣俱不有，對境自垂蘿。"]'),
('1d413c37-f370-4d3e-ab48-0b6137b83ba8','酬諸公宿鏡水宅','嚴維','唐','唐诗','tang','','[]','幸免低頭向府中，貴將藜藿與君同。',64,'全唐诗/poet.tang.13000.json','["幸免低頭向府中，貴將藜藿與君同。", "陽雁呌霜來枕上，寒山映月在湖中。", "詩書何德名夫子，草木推年長數公。", "聞道漢家偏尚少，此身那此訪芝翁。"]'),
('9a465599-72af-42d1-a4b6-5d242a2d4ab4','送薛尚書入蜀','嚴維','唐','唐诗','tang','','[]','卑情不敢論，拜首入轅門。',48,'全唐诗/poet.tang.13000.json','["卑情不敢論，拜首入轅門。", "列郡諸侯長，登朝八座尊。", "凝笳臨水發，行斾向風飜。", "幾許遺黎泣，同懷父母恩。"]'),
('2d0f08cd-47d0-455a-a70d-3754d57320d6','送李祕書往儋州','嚴維','唐','唐诗','tang','','[]','魑魅曾爲伍，蓬萊近拜郎。',48,'全唐诗/poet.tang.13000.json','["魑魅曾爲伍，蓬萊近拜郎。", "臣心瞻北闕，家事在南荒。", "莎草山城小，毛洲海驛長。", "玄成知必大，寧是泛滄浪。"]'),
('7dd0dbb6-40fa-4424-bea1-8650f7513987','送人入金華','嚴維','唐','唐诗','tang','','[]','明月雙溪水，清風八詠樓。',24,'全唐诗/poet.tang.13000.json','["明月雙溪水，清風八詠樓。", "昔年爲客處，今日送君遊。"]'),
('96977d5f-eb6e-4e4c-bcb9-0dc78604119c','送崔峒使往睦州兼寄薛司戶','嚴維','唐','唐诗','tang','','[]','如今相府用英髦，獨往南州肯告勞。',64,'全唐诗/poet.tang.13000.json','["如今相府用英髦，獨往南州肯告勞。", "冰水近開漁浦出，雪雲初卷定山高。", "木奴花映桐廬縣，青雀舟隨白露濤。", "使者應須訪廉吏，府中惟有范功曹。"]'),
('bd9d6696-ea76-4268-a241-99cd7cd1820f','送房元直赴北京','嚴維','唐','唐诗','tang','','[]','猶道樓蘭十萬師，書生匹馬去何之。',64,'全唐诗/poet.tang.13000.json','["猶道樓蘭十萬師，書生匹馬去何之。", "臨歧未斷歸家目，望月空吟出塞詩。", "常欲激昂論上策，不應憔悴老明時。", "遙知到日逢寒食，彩筆長裾會晉祠。"]'),
('567c5382-3b53-4cc8-8b8a-d87f8c7ddaee','荆溪館呈丘義興','嚴維','唐','唐诗','tang','','[]','失路荆溪上，依人忽暝投。',48,'全唐诗/poet.tang.13000.json','["失路荆溪上，依人忽暝投。", "長橋今夜月，陽羨古時州。", "野燒明山郭，寒更出縣樓。", "先生能館我，無事五湖遊。"]'),
('1b8d93ea-6e17-4694-ab77-6d7bd98c0037','一公新泉','嚴維','唐','唐诗','tang','','[]','山下新泉出，泠泠北去源。',48,'全唐诗/poet.tang.13000.json','["山下新泉出，泠泠北去源。", "落池纔有響，噴石未成痕。", "獨映孤松色，殊分衆鳥喧。", "唯當清夜月，觀此啓禪門。"]'),
('ff54523a-a05e-4c51-bbe4-bd848346b2c1','奉試水精環','嚴維','唐','唐诗','tang','','[]','王室符長慶，環中得水精。',72,'全唐诗/poet.tang.13000.json','["王室符長慶，環中得水精。", "任圓循不極，見素質仍貞。", "信是天然瑞，非因樸斲成。", "無瑕勝玉美，至潔過冰清。", "未肯齊珉價，寧同雜佩聲。", "能銜任黃雀，亦欲應時明。"]'),
('5c5e7185-6ddb-443f-81ed-e7d2d9d59460','自雲陽歸晚泊陸澧宅','嚴維','唐','唐诗','tang','','[]','天陰行易晚，前路故人居。',48,'全唐诗/poet.tang.13000.json','["天陰行易晚，前路故人居。", "孤棹所思久，寒林相見初。", "閑燈忘夜水，清漏任更疎。", "明發還須去，離家幾歲除。"]'),
('1ec1004b-ebea-4636-9fb6-9bd05737c70e','九日陪崔郎中北山讌','嚴維','唐','唐诗','tang','','[]','上客南臺至，重陽此會文。',48,'全唐诗/poet.tang.13000.json','["上客南臺至，重陽此會文。", "菊芳寒露洗，杯翠夕陽曛。", "務簡人同醉，溪閑鳥自羣。", "府中官最小，唯有孟參軍。"]'),
('d82e2190-3a65-468e-a56c-623ee94fe2aa','留別鄒紹劉長卿','嚴維','唐','唐诗','tang','','[]','中年從一尉，自笑此身非。',48,'全唐诗/poet.tang.13000.json','["中年從一尉，自笑此身非。", "道在甘微祿，時難耻息機。", "晨趨本郡府，書掩故山扉。", "待見干戈畢，何妨更採薇。"]'),
('118a0230-50a2-4ff3-9c3f-c4f33f4969f1','書情獻相公','嚴維','唐','唐诗','tang','','[]','年來白髮欲星星，誤却生涯是一經。',64,'全唐诗/poet.tang.13000.json','["年來白髮欲星星，誤却生涯是一經。", "魏闕望中何日見，商歌奏罷復誰聽。", "孤根獨棄慙山木，弱質無成狀水萍。", "今日更須詢哲匠，不應休去老巖扃。"]'),
('c178fad8-195b-4069-b641-c529af5dcc72','贈送朱放','嚴維','唐','唐诗','tang','','[]','昔年居漢水，日醉習家池。',48,'全唐诗/poet.tang.13000.json','["昔年居漢水，日醉習家池。", "道勝迹常在，名高身不知。", "欲依天目住，新自始寧移。", "生事曾無長，惟將白接䍦。"]'),
('5ab59e81-b943-4b03-b08a-a34e4cefeee8','剡中贈張卿侍御','嚴維','唐','唐诗','tang','','[]','辟疆年正少，公子貴初還。',72,'全唐诗/poet.tang.13000.json','["辟疆年正少，公子貴初還。", "早列月卿位，新參柱史班。", "千夫馳驛道，駟馬入家山。", "深巷烏衣盛，高門畫戟閑。", "逶迤天樂下，照耀剡溪間。", "自賤遊章句，空爲衰草顏。"]'),
('4f733ca9-4c37-4c5b-9e25-e39166c1cf16','贈萬經','嚴維','唐','唐诗','tang','','[]','萬公長慢世，昨日又隳官。',48,'全唐诗/poet.tang.13000.json','["萬公長慢世，昨日又隳官。", "縱酒真彭澤，論詩得建安。", "家山伯禹穴，別墅小長干。", "輙有時人至，窗前白眼看。"]'),
('fdfafd13-b5b9-4f27-abd2-c74089c71259','書情上李蘇州','嚴維','唐','唐诗','tang','','[]','東土苗人尚有殘，皇皇亞相出朝端。',64,'全唐诗/poet.tang.13000.json','["東土苗人尚有殘，皇皇亞相出朝端。", "手持國憲羣僚畏，口喻天慈百姓安。", "禮數自憐今日絕，風流空計往年歡。", "誤著青袍將十載，忍令漁浦却垂竿。"]'),
('acd23434-81a1-4c36-8196-e262f883e289','餘姚祗役奉簡鮑參軍','嚴維','唐','唐诗','tang','','[]','童年獻賦在皇州，方寸思量君與侯。',64,'全唐诗/poet.tang.13000.json','["童年獻賦在皇州，方寸思量君與侯。", "萬事無成新白首，兩春虛擲對滄流。", "歌詩盛賦文星動，簫管新亭晦日遊。", "知己欲依何水部，鄉人今正賤東丘。"]'),
('1143c442-058a-462d-b5cc-63b9947e4823','奉和獨孤中丞遊雲門寺','嚴維','唐','唐诗','tang','','[]','絕壑開花界，耶溪極上源。',96,'全唐诗/poet.tang.13000.json','["絕壑開花界，耶溪極上源。", "光輝三獨坐，登陟五雲門。", "深木鳴騶馭，晴山曜武賁。", "亂泉觀坐臥，疎磬發朝昏。", "蒼翠新秋色，莓苔積雨痕。", "上方看度鳥，後夜聽吟猿。", "異跡焚香對，新詩酌茗論。", "歸來還撫俗，諸老莫攀轅。"]'),
('ffed3e70-8753-466c-ac59-0fdb5894adfd','奉和皇甫大夫夏日遊花嚴寺','嚴維','唐','唐诗','tang','','[]','初第華嚴會，王家少長行。',48,'全唐诗/poet.tang.13000.json','["初第華嚴會，王家少長行。", "到宮龍節駐，禮塔雁行成。", "蓮界千峰靜，梅天一雨清。", "禪庭未可戀，聖主寄蒼生。"]'),
('07aef71c-f716-4736-b80e-7425ea8f00ba','宿法華寺','嚴維','唐','唐诗','tang','','[]','一夕雨沈沈，哀猨萬木陰。',48,'全唐诗/poet.tang.13000.json','["一夕雨沈沈，哀猨萬木陰。", "天龍來護法，長老密看心。", "魚梵空山靜，紗燈古殿深。", "無生久已學，白髮浪相侵。"]'),
('1f03841c-5cf1-43e3-9d96-d1768981de42','題茅山李尊師所居','嚴維','唐','唐诗','tang','','[]','天師百歲少如童，不到山中更不逢。',64,'全唐诗/poet.tang.13000.json','["天師百歲少如童，不到山中更不逢。", "洗藥每臨新瀑水，步虛時遶最高峰。", "籬根五月留殘雪，座右千年蔭古松。", "此去人寰知近遠，迴看路隔一重重。"]'),
('9f033648-d76a-4de4-ba1d-8c0298fa5c3d','送薛居士和州讀書','嚴維','唐','唐诗','tang','','[]','孤雲獨鶴共悠悠，萬卷經書一葉舟。',64,'全唐诗/poet.tang.13000.json','["孤雲獨鶴共悠悠，萬卷經書一葉舟。", "楚地巢城民舍少，煙村社樹鷺湖秋。", "蒿萊織妾晨炊黍，隅落耕童夕放牛。", "年少不應辭苦節，諸生若遇亦封侯。"]'),
('67c18ea1-db49-44b5-8b21-6176e4a86416','送李端','嚴維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u51ac\u5929", "\u53cb\u60c5", "\u9001\u522b", "\u4e94\u8a00\u5f8b\u8bd7", "\u4f24\u6000"]','故關衰草遍，離別正堪悲。',48,'全唐诗/poet.tang.13000.json','["故關衰草遍，離別正堪悲。", "路出寒雲外，人歸暮雪時。", "少孤爲客早，多難識君遲。", "揜泣空相向，風塵何所期。"]'),
('5112ca49-faea-4dcc-8589-6d0327799bc8','宿天竺寺','嚴維','唐','唐诗','tang','','[]','方外主人名道林，怕將水月淨身心。',32,'全唐诗/poet.tang.13000.json','["方外主人名道林，怕將水月淨身心。", "居然對我說無我，寂歷山深將夜深。"]'),
('8f9d60e5-bd15-4f2f-89e2-b6dcf8d26064','丹陽送韋參軍','嚴維','唐','唐诗','tang','','["\u601d\u5ff5", "\u9001\u522b", "\u53cb\u60c5"]','丹陽郭裏送行舟，一別心知兩地秋。',32,'全唐诗/poet.tang.13000.json','["丹陽郭裏送行舟，一別心知兩地秋。", "日晚江南望江北，寒鴉飛盡水悠悠。"]'),
('8d724eb7-febd-4169-aa23-a3917fda6ca7','入唐溪','嚴維','唐','唐诗','tang','','[]','嘯終萬籟起，吹去當溪雲。',48,'全唐诗/poet.tang.13000.json','["嘯終萬籟起，吹去當溪雲。", "環嶼或明昧，遠峯尚氛氳。", "雨新翠葉發，夜早玄象分。", "金澗流不盡，入山深更聞。"]'),
('c724c20d-b1a6-4044-af22-5cb1b6aba150','送桃巖成上人歸本寺','嚴維','唐','唐诗','tang','','[]','長老歸緣起，桃花憶舊巖。',48,'全唐诗/poet.tang.13000.json','["長老歸緣起，桃花憶舊巖。", "清晨雲抱石，深夜月籠杉。", "道具門人捧，齋粮谷鳥銜。", "餘生願依止，文字欲三緘。"]'),
('2049c49c-8641-4e79-9342-992de31f2a5e','酬普選二上人期相會見寄','嚴維','唐','唐诗','tang','','[]','本意宿東林，因聽子賤琴。',48,'全唐诗/poet.tang.13000.json','["本意宿東林，因聽子賤琴。", "遙知大小朗，已斷去來心。", "夜靜溪聲近，庭寒月色深。", "寧知塵外意，定後便成吟。"]'),
('a4fe62aa-8fa5-48ee-a40f-bedac42c701d','相里使君宅聽澄上人吹小管','嚴維','唐','唐诗','tang','','[]','秦僧吹竹閉秋城，早在梨園稱主情。',32,'全唐诗/poet.tang.13000.json','["秦僧吹竹閉秋城，早在梨園稱主情。", "今夕襄陽山太守，座中流淚聽商聲。"]'),
('a7d23b6d-1e99-4088-aa84-fb9f684d4f1c','贈別至弘上人','嚴維','唐','唐诗','tang','','[]','最稱弘偃少，早歲草茆居。',48,'全唐诗/poet.tang.13000.json','["最稱弘偃少，早歲草茆居。", "年老從僧律，生知解佛書。", "衲衣求壞帛，野飯拾春蔬。", "章句無求斷，時中學有餘。"]'),
('9aa3f5aa-d3a0-4650-afb2-6f9a79d01204','奉和劉祭酒傷白馬','嚴維','唐','唐诗','tang','','[]','沛艾如龍馬，來從上苑中。',96,'全唐诗/poet.tang.13000.json','["沛艾如龍馬，來從上苑中。", "棣華恩見賜，伯舅禮仍崇。", "鏡點黃金眼，花開白雪騣。", "性柔君子德，足逸大王風。", "色照鳴珂靜，聲連噴玉雄。", "食場恩未盡，過隟命旋終。", "練影依雲沒，銀鞍向月空。", "仍聞樂府唱，猶念代勞功。"]'),
('3c480b6c-f2a8-4726-8cdd-1e4c8c54f2d7','哭靈一上人','嚴維','唐','唐诗','tang','','[]','一公何不住，空有遠公名。',72,'全唐诗/poet.tang.13000.json','["一公何不住，空有遠公名。", "共說岑山路，今時不可行。", "舊房松更老，新塔草初生。", "經論傳緇侶，文章遍墨卿。", "禪林枝幹折，法宇棟梁傾。", "誰復修僧史，應知傳已成。"]'),
('f86ad791-a68e-43bf-903a-e9ee6dec7ee7','題鮑行軍小閣','嚴維','唐','唐诗','tang','','[]','宇下無留事，經營意獨新。',72,'全唐诗/poet.tang.13000.json','["宇下無留事，經營意獨新。", "文房已得地，相閣是推輪。", "席上招賢急，山陰對雪頻。", "虛明先旦暮，啓閉異冬春。", "談笑兵家法，逢迎幕府賓。", "還將負暄處，時借在陰人。"]'),
('e82c0c1d-2a56-453c-b97a-93ecb879035a','陪皇甫大夫謁禹廟','嚴維','唐','唐诗','tang','','[]','竹使羞殷薦，松龕拜夏祠。',48,'全唐诗/poet.tang.13000.json','["竹使羞殷薦，松龕拜夏祠。", "爲魚歌德後，舞羽降神時。", "文衛瞻如在，精靈信有期。", "夕陽陪醉止，塘上鳥咸遲。"]'),
('d3a08a51-e2b8-4ccc-8148-874714a1ade3','同王徴君湘中有懷','嚴維','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u5199\u666f", "\u6292\u60c5", "\u79cb\u5929", "\u601d\u4e61"]','八月洞庭秋，瀟湘水北流。',48,'全唐诗/poet.tang.13000.json','["八月洞庭秋，瀟湘水北流。", "還家萬里夢，爲客五更愁。", "不用看書帙，偏宜上酒樓。", "故人京洛滿，何日復同遊。"]'),
('90c4138c-584d-499f-b012-86d13061cbf8','奉和皇甫大夫祈雨應時雨降','嚴維','唐','唐诗','tang','','[]','致和知必感，歲旱未書災。',72,'全唐诗/poet.tang.13000.json','["致和知必感，歲旱未書災。", "伯禹明靈降，元戎禱請來。", "九成陳夏樂，三獻奉殷罍。", "掣曳旗交電，鏗鏘鼓應雷。", "行雲依蓋轉，飛雨逐車回。", "欲識皇天意，爲霖貺在哉。"]'),
('7fcb41d0-91d9-412c-aec6-bc4ff3a07ff8','贈別劉長卿時赴河南嚴中丞幕府','嚴維','唐','唐诗','tang','','[]','早見登郎署，同時跡下僚。',72,'全唐诗/poet.tang.13000.json','["早見登郎署，同時跡下僚。", "幾年江路永，今去國門遙。", "文變騷人體，官移漢帝朝。", "望山吟度日，接枕話通宵。", "萬里趨公府，孤帆恨信潮。", "匡時知已老，聖代耻逃堯。"]'),
('8089b494-c996-4702-86de-1edbbb136e75','晦日宴遊','嚴維','唐','唐诗','tang','','[]','晦日湔裾俗，春樓致酒時。',48,'全唐诗/poet.tang.13000.json','["晦日湔裾俗，春樓致酒時。", "出山還已醉，謝客舊能詩。", "溪柳薰晴淺，巖花待閏遲。", "爲邦久無事，比屋自熙熙。"]'),
('a7bd542a-0f04-4df6-9698-9890ca8068af','夏日納涼','嚴維','唐','唐诗','tang','','[]','山陰過野客，鏡裏接仙郎。',48,'全唐诗/poet.tang.13000.json','["山陰過野客，鏡裏接仙郎。", "盥漱臨寒水，褰闈入夏堂。", "杉松交日影，枕簟上湖光。", "衮衮承嘉話，清風納晚涼。"]'),
('5b7fc002-346c-4195-9624-74780a383faa','僧房避暑','嚴維','唐','唐诗','tang','','[]','支公好閑寂，庭宇愛林篁。',48,'全唐诗/poet.tang.13000.json','["支公好閑寂，庭宇愛林篁。", "幽曠無煩暑，恬和不可量。", "蕙風清水殿，荷氣雜天香。", "明月談空坐，怡然道術忘。"]'),
('048f51d2-fa75-4b76-96ec-d03a315e058b','九日登高','嚴維','唐','唐诗','tang','','[]','詩家九日憐芳菊，遲客高齋瞰浙江。',64,'全唐诗/poet.tang.13000.json','["詩家九日憐芳菊，遲客高齋瞰浙江。", "漢浦浪花搖素壁，西陵樹色入秋窗。", "木奴向熟懸金實，桑落新開瀉玉缸。", "四子醉時爭講德，笑論黃霸屈爲邦。"]'),
('f4df8fb5-828a-4fab-aad5-ffdb1f663a32','九月十日即事','嚴維','唐','唐诗','tang','','[]','家貧惟種竹，時幸故人看。',48,'全唐诗/poet.tang.13000.json','["家貧惟種竹，時幸故人看。", "菊度重陽少，林經閏月寒。", "宿酲猶落帽，華髮強扶冠。", "美景良難得，今朝更盡歡。"]'),
('1c7c7f60-f630-476e-9032-62caad68a0fc','送丘爲下第歸蘇州','嚴維','唐','唐诗','tang','','[]','滄江一身客，獻賦空十年。',60,'全唐诗/poet.tang.13000.json','["滄江一身客，獻賦空十年。", "明主豈能好，今人誰舉賢。", "國門稅征駕，旅食謀歸旋。", "皦日媚春水，綠蘋香客船。", "無媒既不達，余亦思歸田。"]'),
('0334bf67-5fb4-45a2-ab4a-ef7e2b24af02','送少微上人東南遊','嚴維','唐','唐诗','tang','','[]','舊遊多不見，師在翟公門。',48,'全唐诗/poet.tang.13000.json','["舊遊多不見，師在翟公門。", "瘴海空山熱，雷州白日昏。", "片心應爲法，萬里獨無言。", "人盡酬恩去，平生未感恩。"]'),
('a4e1db88-76e9-4bd6-bd20-53d8181703d8','贈送崔子向','嚴維','唐','唐诗','tang','','[]','旅食來江上，求名赴洛陽。',48,'全唐诗/poet.tang.13000.json','["旅食來江上，求名赴洛陽。", "新詩蹤謝守，內學似支郎。", "行怯秦爲客，心依越是鄉。", "何人作知己，送爾淚浪浪。"]'),
('abf81149-2dbe-4a75-9c7d-baeccd05e8fb','答劉長卿七里瀨重送','嚴維','唐','唐诗','tang','','[]','新安非欲枉帆過，海內如君有幾何。',32,'全唐诗/poet.tang.13000.json','["新安非欲枉帆過，海內如君有幾何。", "醉裏別時秋水色，老人南望一狂歌。"]'),
('10696671-649a-4453-a481-3b8682af5262','歲初喜皇甫侍御至','嚴維','唐','唐诗','tang','','[]','湖上新正逢故人，情深應不笑家貧。',32,'全唐诗/poet.tang.13000.json','["湖上新正逢故人，情深應不笑家貧。", "明朝別後門還掩，修竹千竿一老身。"]'),
('72d31482-f505-4dd5-9a47-cba85261a917','送舍弟','嚴維','唐','唐诗','tang','','[]','疎懶吾成性，才華爾自彊。',48,'全唐诗/poet.tang.13000.json','["疎懶吾成性，才華爾自彊。", "早稱眉最白，何事綬仍黃。", "時暑嗟于邁，家貧念聚糧。", "秪應宵夢裏，詩興屬池塘。"]'),
('a0ed0a84-8d36-421f-b6fa-3b9478cbb9a0','示外生','嚴維','唐','唐诗','tang','','[]','牽役非吾好，寬情爾在傍。',48,'全唐诗/poet.tang.13000.json','["牽役非吾好，寬情爾在傍。", "經過悲井邑，起坐倦舟航。", "相宅生應貴，逢時學可強。", "無輕吾未用，世事有行藏。"]'),
('0849cb37-6920-4dc6-9471-22a4e11b750c','詠孩子','嚴維','唐','唐诗','tang','','[]','嘉客會初筵，宜時魄再圓。',48,'全唐诗/poet.tang.13000.json','["嘉客會初筵，宜時魄再圓。", "衆皆含笑戲，誰不點頤憐。", "繡被花堪摘，羅繃色欲妍。", "將雛有舊曲，還入武城弦。"]'),
('4b28f85a-4497-40f0-b1c5-ed939c384dc2','酬謝侍御喜王宇及第見賀不遇之作','嚴維','唐','唐诗','tang','','[]','寂寞柴門掩，經過柱史榮。',48,'全唐诗/poet.tang.13000.json','["寂寞柴門掩，經過柱史榮。", "老夫寧有力，半子自成名。", "柳映三橋發，花連上道明。", "緘書到別墅，郢曲果先成。"]'),
('fcdeac12-ba53-435d-9137-cab33483451b','秋日與諸公文會天寺','嚴維','唐','唐诗','tang','','[]','相訪從吾道，因緣會爾時。',48,'全唐诗/poet.tang.13000.json','["相訪從吾道，因緣會爾時。", "龍盤餘帝宅，花界古人祠。", "明月虛空色，青林大小枝。", "還將經濟學，來問道安師。"]'),
('84d58e30-fe22-4b4d-85ca-69ed4df16837','荅劉長卿蛇浦橋月下重送','嚴維','唐','唐诗','tang','','[]','月色今宵最明，庭閑夜久天清。',56,'全唐诗/poet.tang.13000.json','["月色今宵最明，庭閑夜久天清。", "寂寞多年老宦，殷懃遠別深情。", "溪臨修竹煙色，風落高梧雨聲。", "耿耿相看不寐，遙聞曉柝山城。"]'),
('03f92cbe-8ae5-4323-b91d-0c9c52139fea','發桐廬寄劉員外','嚴維','唐','唐诗','tang','','[]','處處雲山無盡時，桐廬南望轉參差。',32,'全唐诗/poet.tang.13000.json','["處處雲山無盡時，桐廬南望轉參差。", "舟人莫道新安近，欲上潺湲行自遲。"]'),
('5ea7ca63-1262-4d0f-b8a3-5118cf831f28','秋夜船行','嚴維','唐','唐诗','tang','','[]','扁舟時屬暝，月上有餘輝。',48,'全唐诗/poet.tang.13000.json','["扁舟時屬暝，月上有餘輝。", "海燕秋還去，漁人夜不歸。", "中流何寂寂，孤棹也依依。", "一點前村火，誰家未掩扉。"]'),
('6ec7404c-2d83-4bea-ba67-d44ba4cfad06','遊灞陵山','嚴維','唐','唐诗','tang','','[]','入山未盡意，勝跡聊獨尋。',72,'全唐诗/poet.tang.13000.json','["入山未盡意，勝跡聊獨尋。", "方士去在昔，藥堂留至今。", "四隅白雲閑，一路清溪深。", "芳秀愜春目，高閑宜遠心。", "潭分化丹水，路遶昇仙林。", "此道人不悟，坐鳴松下琴。"]'),
('612c20bd-d582-4948-8258-314e3e0a04b1','重送新安劉員外','嚴維','唐','唐诗','tang','','[]','秋江渺渺水空波，越客孤舟欲榜歌。',32,'全唐诗/poet.tang.13000.json','["秋江渺渺水空波，越客孤舟欲榜歌。", "手折衰楊悲老大，故人零落已無多。"]'),
('8e06f0aa-507d-45c1-869f-85399284ef49','憶長安 五月','嚴維','唐','唐诗','tang','','[]','憶長安，五月時，君王避暑華池。',43,'全唐诗/poet.tang.13000.json','["憶長安，五月時，君王避暑華池。", "進膳甘瓜朱李，續命芳蘭綵絲。", "競處高明臺榭，槐陰柳色通逵。"]'),
('6fa6c414-ec2a-4b89-b082-051414b719dc','狀江南 季春','嚴維','唐','唐诗','tang','','[]','江南季春天，蓴葉細如弦。',24,'全唐诗/poet.tang.13000.json','["江南季春天，蓴葉細如弦。", "池邊草作逕，湖上葉如船。"]'),
('5856859c-215a-4d5c-87f2-e6cd19e2f699','句','嚴維','唐','唐诗','tang','','[]','五色驚綵鳳，千里象驄威。',48,'全唐诗/poet.tang.13000.json','["五色驚綵鳳，千里象驄威。", "三伏軒車動，堯心急諫官。", "名通內籍貴，立近御牀寒。", "波從少海息，雲自大風開。"]'),
('d0ed153d-6ed7-4f28-abbc-4bbe8eb5d0e7','琴歌','顧況','唐','唐诗','tang','','[]','琴調秋些，胡風遶雪。',20,'全唐诗/poet.tang.13000.json','["琴調秋些，胡風遶雪。", "峽泉聲咽，佳人愁些。"]'),
('647c2191-13dc-4fde-9001-b5f9e53ff337','上古之什補亡訓傳十三章','顧況','唐','唐诗','tang','','[]','遐哉上古，生棄與柱。',159,'全唐诗/poet.tang.13000.json','["遐哉上古，生棄與柱。", "句龍是生，乃有甫田。", "惟彼甫田，有萬斯年。", "開利之源，無乃塞源。", "一廛亦官，百廛亦官。", "嗇夫孔艱，浸兮暵兮，申有螽兮。", "惟馨祀是患，豈止餒與寒。", "嗇夫咨咨，䅎盛苗衰。", "耕之耰之，襏襫鋤犂。", "手胼足胝，水之蛭螾。", "吮喋我肌，我姑自思。", "胡不奮飛，東人利百。", "西人利百，有匪我心。", "胡爲不易，河水活活。", "萬人逐末，俾爾之愉悅兮。"]'),
('54e62729-dddd-41b4-ad1f-47736c4468d5','上古之什補亡訓傳十三章  一','顧況','唐','唐诗','tang','','[]','左車有慶，萬人猶病。',30,'全唐诗/poet.tang.13000.json','["左車有慶，萬人猶病。", "曷可去之，于黨孔盛。", "敏爾之生，胡爲波迸。"]'),
('a28c99da-a74a-4707-b44d-0e6090c9ca81','上古之什補亡訓傳十三章  二','顧況','唐','唐诗','tang','','[]','左車有赫，萬人毒螫。',30,'全唐诗/poet.tang.13000.json','["左車有赫，萬人毒螫。", "曷可去之，于黨孔碩。", "敏爾之生，胡爲草戚。"]'),
('b84ef815-694d-4b41-beb8-0fb0f95b704c','上古之什補亡訓傳十三章  一','顧況','唐','唐诗','tang','','[]','築城登登，于以作固。',42,'全唐诗/poet.tang.13000.json','["築城登登，于以作固。", "咨爾寺兮，發郊外冢墓。", "死而無知，猶或不可。", "若其有知，惟上帝是愬。"]'),
('feb009d9-0f2c-4d87-85ea-37c411abb9f8','上古之什補亡訓傳十三章  二','顧況','唐','唐诗','tang','','[]','築城奕奕，于以固敵。',42,'全唐诗/poet.tang.13000.json','["築城奕奕，于以固敵。", "咨爾寺兮，發郊外冢甓。", "死而無知，猶或不可。", "若其有知，惟上帝是謫。"]'),
('39a79599-09f4-4c4e-b098-b3094974890c','上古之什補亡訓傳十三章','顧況','唐','唐诗','tang','','[]','持斧持斧，無翦我松柏兮。',12,'全唐诗/poet.tang.13000.json','["持斧持斧，無翦我松柏兮。"]'),
('f889d018-d34f-4ccb-bcb8-25a8bfd1e95f','上古之什補亡訓傳十三章','顧況','唐','唐诗','tang','','[]','十月之郊，羣木肇生。',248,'全唐诗/poet.tang.13000.json','["十月之郊，羣木肇生。", "陽潛地中，舒達句萌。", "曀其蔚兮，不可以遊息。", "乃熂蒺藜，乃夷荆棘。", "乃繇彼曲直，匠氏度思。", "登斧以時，澤梁蓁蓁。", "無或夭枝，有巨根蔕。", "生混茫際，呼吸羣籟。", "萬人揮斤，坎坎有厲。", "陸遷水濟，百力殫弊。", "審方面勢，姑博其製。", "作爲公室，公室既成。", "禦燥濕風日，棟之斯厚。", "榱之斯密，如翼于飛。", "如鱗櫛比，繚以周墉。", "墄以崇階，俯而望之。", "矗與雲齊，嘯砆碔砆。", "藻井旋題，丹素之燝兮。", "椒挂之馥兮，高閣高閣。", "珠綴結絡，金鋪爛若。", "不集于鳥雀，繪事告畢。", "賓筵秩秩，乃命旨酒琴瑟。", "琴瑟在堂，莫不靜謐。", "周環掩闢，仰不漏日。"]'),
('31774c1e-3701-4961-9566-af53d6b8264f','上古之什補亡訓傳十三章','顧況','唐','唐诗','tang','','[]','燕燕于巢，綴葺維戊。',121,'全唐诗/poet.tang.13000.json','["燕燕于巢，綴葺維戊。", "甲兮乙兮，不宜有謬。", "飛龍在天，雲掩于斗。", "曷日于雨，乃曰庚午。", "彼日之差，亦孔斯醜。", "昔在羲和，湎淫不修。", "我筮我龜，莫我告繇。", "胤廼征之，彝倫九疇。", "君子授律，是禡是禷。", "三五不備，罔克攸遂。", "惠此蒸人，毋廢爾事。", "爾莫我從，維來者是冀。"]'),
('28078456-ebd0-44cb-845f-6a78150becc3','上古之什補亡訓傳十三章','顧況','唐','唐诗','tang','','[]','蘇方之赤，在胡之舶。',49,'全唐诗/poet.tang.13000.json','["蘇方之赤，在胡之舶。", "其利乃博，我土曠兮。", "我居闐兮，我衣不白兮。", "朱紫爛兮，傳瑞曄兮，相唐虞之維百兮。"]'),
('6a3a559e-a1aa-4867-b628-20cba5767840','上古之什補亡訓傳十三章','顧況','唐','唐诗','tang','','[]','陵霜之華，我心憂嗟。',99,'全唐诗/poet.tang.13000.json','["陵霜之華，我心憂嗟。", "陰之勝矣，而陽不加。", "坱軋陶鈞，乃帝乃神。", "乃舒乃屯，烈烈嚴秋。", "熙熙陽春，職生有倫。", "今華發非其辰，辰屬東方之仁。", "遐想三五，黃帝登雲。", "堯年百餘，二儀分位。", "六氣不渝，二景如璧，五星如珠。"]'),
('3c029b7a-1423-4dd5-9c4d-8ed194e455b5','上古之什補亡訓傳十三章','顧況','唐','唐诗','tang','','[]','囝生閩方，閩吏得之。',112,'全唐诗/poet.tang.13000.json','["囝生閩方，閩吏得之。", "乃絕其陽，爲臧爲獲。", "致金滿屋，爲髠爲鉗。", "如視草木，天道無知。", "我罹其毒，神道無知。", "彼受其福，郎罷別囝。", "吾悔生汝，及汝既生。", "人勸不舉，不從人言。", "果獲是苦，囝別郎罷。", "心催血下，隔地絕天。", "及至黃泉，不得在郎罷前。"]'),
('330852e0-cfb5-4d43-90d6-1ee236720b54','上古之什補亡訓傳十三章','顧況','唐','唐诗','tang','','[]','我行自東，山海其空。',60,'全唐诗/poet.tang.13000.json','["我行自東，山海其空。", "旅棘有叢，我行自西。", "壘與雲齊，雨雪淒淒。", "我行自南，烈火滿林。", "日中無禽，霧雨淫淫。", "我行自北，燭龍寡色。"]'),
('420ff7c9-d7da-47ea-bef9-131988809cc1','上古之什補亡訓傳十三章','顧況','唐','唐诗','tang','','[]','採採者蠟，于泉谷兮。',41,'全唐诗/poet.tang.13000.json','["採採者蠟，于泉谷兮。", "煌煌中堂，烈華燭兮。", "新歌善舞，弦柱促兮。", "荒巖之人，自取其毒兮。"]'),
('b544d20a-db4e-4f36-8f67-99edb5cab027','棄婦詞','顧況','唐','唐诗','tang','','[]','古人雖棄婦，棄婦有歸處。',204,'全唐诗/poet.tang.13000.json','["古人雖棄婦，棄婦有歸處。", "今日妾辭君，辭君欲何去。", "本家零落盡，慟哭來時路。", "憶昔未嫁君，聞君甚周旋。", "及與同結髮，值君適幽燕。", "孤魂託飛鳥，兩眼如流泉。", "流泉咽不燥，萬里關山道。", "及至見君歸，君歸妾已老。", "物情棄衰歇，新寵方妍好。", "拭淚出故房，傷心劇秋草。", "妾以憔悴捐，羞將舊物遠。", "餘生欲有寄，誰肯相留連。", "空牀對虛牖，不覺塵埃厚。", "寒水芙蓉花，秋風墮楊柳。", "記得初嫁君，小姑始扶牀。", "今日君棄妾，小姑如妾長。", "回頭語小姑，莫嫁如兄夫。"]'),
('87589e47-69eb-4b30-8204-5678cb0c8636','遊子吟','顧況','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u6292\u6000", "\u601d\u4e61", "\u5199\u666f", "\u58ee\u5fd7\u672a\u916c"]','故櫪思疲馬，故窠思迷禽。',288,'全唐诗/poet.tang.13000.json','["故櫪思疲馬，故窠思迷禽。", "浮雲蔽我鄉，躑躅遊子吟。", "遊子悲久滯，浮雲鬱東岑。", "客堂無絲桐，落葉如秋霖。", "艱哉遠遊子，所以悲滯淫。", "一爲浮雲詞，憤塞誰能禁。", "馳歸百年內，唯願展所欽。", "胡爲不歸歟，坐使年病侵。", "未老霜遶鬢，非狂火燒心。", "太行何難哉，北斗不可斟。", "夜靜星河出，耿耿辰與參。", "佳人敻青天，尺素重於金。", "泬寥羣動異，眇默諸境森。", "苔衣上閑階，蟋蟋催寒碪。", "立身計幾悞，道險無容針。", "三年不還家，萬里遺錦衾。", "夢魂無重阻，離憂罔古今。", "胡爲不歸歟，辜負匣中琴。", "腰下是何物，牽纏曠登尋。", "朝與名山期，夕宿楚水陰。", "楚水殊演漾，名山窅嶇嶔。", "客從洞庭來，婉孌瀟湘深。", "橘柚在南國，鴻雁遺秋音。", "下有碧草洲，上有青橘林。"]'),
('a9ffcb2d-3218-40d2-b123-c56fc0da3a6f','擬古三首 一','顧況','唐','唐诗','tang','','[]','龍劍昔藏影，送雄留其雌。',60,'全唐诗/poet.tang.13000.json','["龍劍昔藏影，送雄留其雌。", "人生阻歡會，神物亦別離。", "碧樹感秋落，佳人無還期。", "夜琴爲君咽，浮雲爲君滋。", "愛而傷不見，星漢徒參差。"]'),
('3585a5ca-2533-4780-aa25-d7a7484f4d49','擬古三首 二','顧況','唐','唐诗','tang','','[]','幽居盼天造，胡息運行機。',60,'全唐诗/poet.tang.13000.json','["幽居盼天造，胡息運行機。", "春葩妍既榮，秋葉瘁以飛。", "滔滔川之逝，日沒月光輝。", "所貴法乾健，于道悟入微。", "任彼聲勢徒，得志方誇毗。"]'),
('3255894f-5d4c-4452-8408-b183d6e48ed5','擬古三首 三','顧況','唐','唐诗','tang','','[]','浮生果何慕，老去羨介推。',48,'全唐诗/poet.tang.13000.json','["浮生果何慕，老去羨介推。", "陶令何足錄，彭澤歸已遲。", "空負漉酒巾，乞食形諸詩。", "吾惟抱貞素，悠悠白雲期。"]'),
('5d14ca80-d4d1-4aa7-8275-975cd901be7e','傷子','顧況','唐','唐诗','tang','','[]','老夫哭愛子，日暮千行血。',36,'全唐诗/poet.tang.13000.json','["老夫哭愛子，日暮千行血。", "聲逐斷猿悲，跡隨飛鳥滅。", "老夫已七十，不作多時別。"]'),
('144809ea-be89-4148-aa51-1cf4b44b1895','春遊曲 一','顧況','唐','唐诗','tang','','[]','遊童蘇合帶，倡女蒲葵扇。',48,'全唐诗/poet.tang.13000.json','["遊童蘇合帶，倡女蒲葵扇。", "初日映城時，相思忽相見。", "褰裳踏露草，理鬢回花面。", "薄暮不同歸，留情此芳甸。"]'),
('17872b06-a000-40e2-b592-e635ffe04c59','春遊曲 二','顧況','唐','唐诗','tang','','[]','柘彈連錢馬，銀鉤妥墮鬟。',48,'全唐诗/poet.tang.13000.json','["柘彈連錢馬，銀鉤妥墮鬟。", "採桑春陌上，踏草夕陽間。", "意合詞先露，心誠貌却閑。", "明朝若相憶，雲雨出巫山。"]'),
('1d752bcd-9001-440a-8cfe-8e681b2c4cd0','從軍行二首 一','顧況','唐','唐诗','tang','','[]','弭節結徒侶，速征赴龍城。',96,'全唐诗/poet.tang.13000.json','["弭節結徒侶，速征赴龍城。", "單于近突圍，烽燧屢夜驚。", "長弓挽滿月，劍華霜雪明。", "遠道百草殞，峭覺寒風生。", "風寒欲砭肌，爭奈裘襖輕。", "回首家不見，候雁空中鳴。", "笳奏遝以哀，肅肅趣嚴程。", "寄語塞外胡，擁騎休橫行。"]'),
('0387e52b-4a91-4bfb-b7b8-5f81e6c73d20','從軍行二首 二','顧況','唐','唐诗','tang','','[]','少年膽氣麁，好勇萬人敵。',72,'全唐诗/poet.tang.13000.json','["少年膽氣麁，好勇萬人敵。", "仗劍出門去，三邊正艱厄。", "怒目時一呼，萬騎皆辟易。", "殺人蓬麻輕，走馬汗血滴。", "醜虜何足清，天山坐寧謐。", "不有封侯相，徒負幽幷客。"]'),
('bc641892-8566-4ab8-93f1-e17dacc6aa88','塞上曲','顧況','唐','唐诗','tang','','[]','黠虜初南下，塵飛塞北境。',60,'全唐诗/poet.tang.13000.json','["黠虜初南下，塵飛塞北境。", "漢將懷不平，讐擾當遠屏。", "金革臥不暖，起舞霜月冷。", "點軍三十千，部伍嚴以整。", "酣戰祈成功，于焉罷邊釁。"]'),
('ea740956-e3f3-44a4-8a42-b51847344bfd','弋陽溪中望仙人城','顧況','唐','唐诗','tang','','[]','何草乏靈姿，無山不孤絕。',60,'全唐诗/poet.tang.13000.json','["何草乏靈姿，無山不孤絕。", "我行雖云蹇，偶勝聊換節。", "上界浮中流，光響洞明滅。", "晚禽曝霜羽，寒魚依石髮。", "自有無還心，隔波望松雪。"]'),
('f3f0de7a-1782-4161-a5f6-1ced4edb4cb2','嚴公釣臺作','顧況','唐','唐诗','tang','','[]','靈芝產遐方，威鳳家重宵。',72,'全唐诗/poet.tang.13000.json','["靈芝產遐方，威鳳家重宵。", "嚴生何耿潔，託志肩夷巢。", "漢后雖則貴，子陵不知高。", "糠粃當世道，長揖夔龍朝。", "掃門彼何人，升降不同朝。", "捨舟遂長往，山谷多清飆。"]'),
('169eb18c-5a15-4927-bd2a-96a622460b7e','蕭寺偃松','顧況','唐','唐诗','tang','','[]','淒淒百卉病，亭亭雙松逈。',48,'全唐诗/poet.tang.13000.json','["淒淒百卉病，亭亭雙松逈。", "直上古寺深，橫拂秋殿冷。", "輕響入龜目，片陰栖鶴頂。", "山中多好樹，可憐無比並。"]'),
('f5256a1a-2a7b-480c-a475-f42f705f7341','獨遊青龍寺','顧況','唐','唐诗','tang','','[]','春風入香剎，暇日獨游衍。',108,'全唐诗/poet.tang.13000.json','["春風入香剎，暇日獨游衍。", "曠然蓮花臺，作禮月光面。", "乘茲第八識，出彼超二見。", "擺落區中緣，無邊廣弘願。", "長廊朝雨畢，古木時禽囀。", "積翠曖遙原，雜英紛似霰。", "鳳城騰日窟，龍首橫天堰。", "蟻步避危階，蠅飛響深殿。", "大通智勝佛，幾刦道場現。"]'),
('46d56217-7555-4a85-99fd-2ef265de9b8d','初秋蓮塘歸','顧況','唐','唐诗','tang','','[]','秋光淨無跡，蓮消錦雲紅。',36,'全唐诗/poet.tang.13000.json','["秋光淨無跡，蓮消錦雲紅。", "只有溪上山，還識揚舲翁。", "如何白蘋花，幽渚笑涼風。"]'),
('e75b38bd-659f-4d46-9c7f-f4213be5f33f','從江西至彭蠡入浙西淮南界道中寄齊相公','顧況','唐','唐诗','tang','','[]','大賢舊丞相，作鎮江山雄。',276,'全唐诗/poet.tang.13000.json','["大賢舊丞相，作鎮江山雄。", "自鎮江山來，何人得如公。", "處士待徐孺，仙人期葛洪。", "一身控上遊，八郡趨下風。", "比屋除畏溺，林塘曳煙虹。", "生人罷虔劉，井稅均且充。", "大府肅無事，歡然接悲翁。", "心清百丈泉，目送孤飛鴻。", "數年鄱陽掾，抱責栖微躬。", "首陽及汨羅，無乃褊其衷。", "楊朱幷阮籍，未免哀途窮。", "四賢雖得仁，此怨何怱怱。", "老氏齊寵辱，於陵一窮通。", "本師留度門，平等冤親同。", "能依二諦法，了達三輪空。", "真境靡方所，出離內外中。", "無邊盡未來，定惠雙修功。", "蹇步慙寸進，餙裝隨轉蓬。", "朝行楚水陰，夕宿吳洲東。", "吳洲復白雲，楚水飄丹楓。", "晚霞燒廻潮，千里光曈曈。", "蓂開海上影，桂吐淮南叢。", "何當翼明庭，草木生春融。"]'),
('3e58f1b4-21c8-4f73-a641-cc0366ab1efd','寄上兵部韓侍郎奉呈李戶部盧刑部杜三侍郎','顧況','唐','唐诗','tang','','[]','道路五千里，門闌三十年。',183,'全唐诗/poet.tang.13000.json','["道路五千里，門闌三十年。", "當時攜手人，今日無半全。", "詠題官舍內，賦韻僧房前。", "公登略彴橋，況榜龍{舟卬}船。", "遠寺吐朱閣，春潮浮綠煙。", "鵷鴻翔鄧林，沙鴇飛吳田。", "諸子紛出祖，中宵久留連。", "坐客三千人，皆稱主人賢。", "國士分如此，家臣亦依然。", "身在薜蘿中，頭刺文案邊。", "故吏已重疊，門生從聯翩。", "得罪爲何名，無階問皇天。", "出門多岐路，命駕無由緣。", "伏承諸侍郎，顧念猶迍邅。", "聖代逢三宥，營魂空九遷。"]'),
('3fea7675-c16d-4354-8241-758c96ced6f7','長安竇明府後亭','顧況','唐','唐诗','tang','','[]','君爲長安令，我美長安政。',72,'全唐诗/poet.tang.13000.json','["君爲長安令，我美長安政。", "五日一朝天，南山對明鏡。", "鳥飛青苔院，水木相輝映。", "客至南雲鄉，絲桐展歌詠。", "吏人何蕭蕭，終歲無喧競。", "欲識明府賢，邑中多百姓。"]'),
('8a9195a1-6b5d-4054-b785-21350c64f373','謝王郎中見贈琴鶴','顧況','唐','唐诗','tang','','[]','此琴等焦尾，此鶴方胎生。',96,'全唐诗/poet.tang.13000.json','["此琴等焦尾，此鶴方胎生。", "赴節何徘徊，理感物自幷。", "獨立江海上，一彈天地清。", "朱弦動瑤華，白羽飄玉京。", "因想羨門輩，眇然四體輕。", "子喬翔鄧林，王母遊層城。", "忽如啓靈署，鸞鳳相和鳴。", "何由玉女牀，去食琅玕英。"]'),
('790414b6-6832-4006-a123-580c7950b198','和翰林吳舍人兄弟西齋','顧況','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','君家誠易知，易知復難同。',96,'全唐诗/poet.tang.13000.json','["君家誠易知，易知復難同。", "新裁尺一詔，早入明光宮。", "西齋何其高，上與星漢通。", "永懷洞庭石，春色相玲瓏。", "久懷巴峽泉，夜落君絲桐。", "信是怡神所，迢迢蔑華嵩。", "鳥飛晴雲滅，疊嶂盤虛空。", "君家誠易知，易知意難窮。"]'),
('d613d731-0abc-41a1-87dd-aecd74931800','望初月簡于吏部','顧況','唐','唐诗','tang','','[]','泬寥中秋夜，坐見如鉤月。',48,'全唐诗/poet.tang.13000.json','["泬寥中秋夜，坐見如鉤月。", "始從西南升，又欲西南沒。", "全移河上影，暫透林間缺。", "縱待三五時，終爲千里別。"]'),
('895967e5-676c-4238-a5a5-124e4260f76c','上湖至破山贈文周蕭元植','顧況','唐','唐诗','tang','','[]','一別二十年，依依過故轍。',60,'全唐诗/poet.tang.13000.json','["一別二十年，依依過故轍。", "湖上非往態，夢想頻虛結。", "二子伴我行，我行感徂節。", "後人應不識，前事寒泉咽。", "一別二十年，人堪幾回別。"]'),
('29818c31-5982-4c9f-8f9a-a227a04ca579','酬信州劉侍郎兄','顧況','唐','唐诗','tang','','[]','劉兄本知命，屈伸不介懷。',84,'全唐诗/poet.tang.13000.json','["劉兄本知命，屈伸不介懷。", "南州管靈山，可惜曠土棲。", "樵隱同一徑，竹樹薄西齋。", "鳥陵嶂合杳，月配波徘徊。", "薄宦修禮數，長景謝譚諧。", "願爲南州民，輸稅事鉏犁。", "胡爲走不止，風雨驚邅迴。"]'),
('c248881e-31d3-4a8a-aa4c-ef5591f27153','奉酬劉侍郎','顧況','唐','唐诗','tang','','[]','幾迴新秋影，壁滿蟾又缺。',48,'全唐诗/poet.tang.13000.json','["幾迴新秋影，壁滿蟾又缺。", "鏡破似傾臺，輪斜同覆轍。", "雖分上林桂，還照滄洲雪。", "暫伴顦顇人，歸華耿不滅。"]'),
('71edeeee-167f-4f20-8ed2-cb4571d54813','酬本部韋左司','顧況','唐','唐诗','tang','','[]','好鳥依佳樹，飛雨灑高城。',96,'全唐诗/poet.tang.13000.json','["好鳥依佳樹，飛雨灑高城。", "況與二三子，列坐分兩楹。", "文雅一何盛，林塘含餘清。", "府君未歸朝，遊子不待晴。", "白雲帝城遠，滄江楓葉鳴。", "却略欲一言，零淚和酒傾。", "寸心久摧折，別離重骨驚。", "安得凌風翰，肅肅賓天京。"]'),
('6534e63d-db2d-4c05-b47d-3a54352843b5','酬房杭州','顧況','唐','唐诗','tang','','[]','郡樓何其曠，亭亭廣而深。',96,'全唐诗/poet.tang.13000.json','["郡樓何其曠，亭亭廣而深。", "故人牧餘杭，留我披胸衿。", "滿篋閱新作，璧玉誕清音。", "流水入洞天，窅豁欲淩臨。", "闢險延北阜，薙道陟南岑。", "朝從山寺還，醒醉動笑吟。", "荷花十餘里，月色攢湖林。", "父老惜使君，却欲速華簪。"]'),
('15145fb4-20e1-44db-acf9-814a2d976452','酬漳州張九使君','顧況','唐','唐诗','tang','','[]','故人窮越徼，狂生起悲愁。',120,'全唐诗/poet.tang.13000.json','["故人窮越徼，狂生起悲愁。", "山海萬里別，草木十年秋。", "鞭馬廣陵橋，出祖張漳州。", "促膝墮簪珥，闢幌戛琳球。", "短題自茲簡，華篇詎能酬。", "無階承明庭，高步相追遊。", "南方榮桂枝，淩冬捨溫裘。", "猿唫郡齋中，龍靜檀欒流。", "薜鹿莫徭洞，網魚盧亭洲。", "心安處處安，處處思遐陬。"]'),
('d1d57a82-baf7-4776-854e-b99e5319ae87','在滁苦雨歸桃花崦傷親友略盡','顧況','唐','唐诗','tang','','[]','廢棄忝殘生，後來亦先夭。',72,'全唐诗/poet.tang.13000.json','["廢棄忝殘生，後來亦先夭。", "詩人感風雨，長夜何時曉。", "去國宦情無，近鄉歸夢少。", "庇身絕中授，甘靜忘外擾。", "麗景變重陰，洞山空木表。", "靈潮若可通，寄謝西飛鳥。"]'),
('507e9e38-02df-4eb1-a631-f001b909dcea','苦雨','顧況','唐','唐诗','tang','','[]','朝與佳人期，碧樹生紅蕚。',72,'全唐诗/poet.tang.13000.json','["朝與佳人期，碧樹生紅蕚。", "暮與佳人期，飛雨灑清閣。", "佳人窅何許，中夜心寂寞。", "試憶花正開，復驚葉初落。", "行騎飛泉鹿，臥聽雙海鶴。", "嘉願有所從，安得處其薄。"]'),
('38427d15-8d28-4ebb-b737-4d7a075f9b03','贈別崔十三長官','顧況','唐','唐诗','tang','','[]','真玉燒不熱，寶劍拗不折。',108,'全唐诗/poet.tang.13000.json','["真玉燒不熱，寶劍拗不折。", "欲別崔俠心，崔俠心如鐵。", "復如金剛鎖，無有功不徹。", "仍於直道中，行事不詆訐。", "崔俠兩兄弟，垂範繼芳烈。", "相識三十年，致書字不滅。", "我來宣城郡，飲水仰清潔。", "藹藹北阜松，峩峩南山雪。", "顧生歸山去，知作幾年別。"]'),
('e17e0ed9-da49-450a-9913-673d54476327','哭從兄萇','顧況','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭違鄂渚，嫋嫋秋風時。',180,'全唐诗/poet.tang.13000.json','["洞庭違鄂渚，嫋嫋秋風時。", "何人不客遊，獨與帝子期。", "黃鵠鎩飛翅，青雲歎沈姿。", "身終一騎曹，高蓋者爲誰。", "從駕至梁漢，金根復京師。", "皇恩溢九垠，不記屠沽兒。", "立身有高節，滿卷多好詩。", "赫赫承明庭，羣公默無詞。", "草木正搖落，哭兄鄱水湄。", "共居雲陽里，轗軻多別離。", "人生倏忽間，旅襯飄若遺。", "稚子新學拜，枯楊生一枝。", "人生倏忽間，精爽無不之。", "舊國數千里，家人由未知。", "人生倏忽間，安用才士爲。"]'),
('a0dd3eb4-28fd-495a-bf8e-eb8f65141e0a','華山西岡遊贈隱玄叟','顧況','唐','唐诗','tang','','[]','羣峰鬱初霽，潑黛若鬟沐。',84,'全唐诗/poet.tang.13000.json','["羣峰鬱初霽，潑黛若鬟沐。", "失風鼓唅呀，搖撼千灌木。", "木葉微墮黃，石泉淨停綠。", "危磴蘿薜牽，逈步入幽谷。", "我心寄青霞，世事慚蒼鹿。", "遂令巢許輩，于焉謝塵俗。", "想是悠悠雲，可契去留躅。"]'),
('dc52501e-3598-4ebf-bba8-7bf0c3a9a172','歸陽蕭寺有丁行者能修無生忍擔水施僧況歸命稽首作詩','顧況','唐','唐诗','tang','','[]','化佛示持帚，仲尼稱執鞭。',293,'全唐诗/poet.tang.13000.json','["化佛示持帚，仲尼稱執鞭。", "列生御風歸，飼豕如人焉。", "曹溪第六祖，踏碓逾三年。", "伊人自何方，長綬趨遙泉。", "開士行何苦，雙瓶胝兩肩。", "蕭寺百餘僧，東廚正揚煙。", "露足沙石裂，外形巾褐穿。", "若其有此身，豈得安穩眠。", "獨出違順境，不爲寒暑還。", "大聖於其中，領我心之虔。", "萬法常空滅，無生因忍全。", "一國一釋迦，一燈分百千。", "永願遺世知，現身彌勒前。", "潛容偏虛空，靈響不可傳。", "智慧舍利佛，神通自乾連。", "阿若楚系簡帛陳如，迦葉迦旜延。", "左右二菩薩，文殊幷普賢。", "身披六銖衣，億刦爲大僊。", "寶塔寶樓閣，重簷交梵天。", "譬如一明珠，共贊光白圓。", "天魔波[旬]等，降伏金剛堅。", "野叉羅剎鬼，亦赦塵垢纏。", "乃致金翅鳥，吞龍護洪淵。", "一十一衆中，身意皆快然。"]'),
('ea92a5e4-7f48-4141-b793-2572b5df86f0','大茅嶺東新居憶亡子從真','顧況','唐','唐诗','tang','','[]','谷鳥猶呼兒，山人夕霑襟。',180,'全唐诗/poet.tang.13000.json','["谷鳥猶呼兒，山人夕霑襟。", "懷哉隔生死，悵矣徒登臨。", "東門憂不入，西河遇亦深。", "古來失中道，偶向經中尋。", "大象無停輪，倏忽成古今。", "其夭非不幸，鍊形由太陰。", "凡欲攀雲階，譬如火鑄金。", "虛室留舊札，洞房掩閑琴。", "泉源登方諸，上有空青林。", "彷彿通寤寐，蕭寥邈微音。", "軟草被汀洲，鮮雲略浮沈。", "赬景宣疊麗，紺波響飄淋。", "石窟含雲巢，迢迢耿南岑。", "悲恨自茲斷，情塵詎能侵。", "真靜一時變，作起唯從心。"]'),
('b5fd5d58-7d49-4996-aaeb-3853a658fa67','烏啼曲二首 一','顧況','唐','唐诗','tang','','[]','玉房掣鎖聲翻葉，銀箭添泉遶霜堞。',72,'全唐诗/poet.tang.13000.json','["玉房掣鎖聲翻葉，銀箭添泉遶霜堞。", "畢逋撥刺月銜城，八九雛飛其母驚。", "此是天上老鵶鳴，人間老鵶無此聲。", "搖風雜佩耿華燭，夜聽羽人彈此曲。", "東方曈曈赤日旭。"]'),
('667e8be7-4629-4c05-8463-da20b021205a','烏啼曲二首 二','顧況','唐','唐诗','tang','','[]','月出江林西，江林寂寂城鵶啼。',46,'全唐诗/poet.tang.13000.json','["月出江林西，江林寂寂城鵶啼。", "昔人何處爲此曲，今人何處聽不足。", "城寒月曉馳思深，江上青草爲誰綠。"]'),
('5f193404-a54b-4d12-9806-99609b76beca','幽居弄','顧況','唐','唐诗','tang','','[]','苔衣生，花露滴，月入西林蕩東壁。',64,'全唐诗/poet.tang.13000.json','["苔衣生，花露滴，月入西林蕩東壁。", "扣商占角兩三聲，洞戶谿窗一冥寂。", "獨去滄洲無四鄰，身嬰世網此何身。", "關情命曲寄惆悵，久別山南山裏人。"]'),
('ad6b6b38-8143-4f5c-af5a-d68264e12a8e','公子行','顧況','唐','唐诗','tang','','[]','輕薄兒，面如玉，紫陌春風纏馬足。',96,'全唐诗/poet.tang.13000.json','["輕薄兒，面如玉，紫陌春風纏馬足。", "雙𩍐懸金縷鶻飛，長衫刺雪生犀束。", "綠槐夾道陰初成，珊瑚幾節敵流星。", "紅肌拂拂酒光獰，當街背拉金吾行。", "朝遊鼕鼕鼓聲發，暮遊鼕鼕鼓聲絕。", "入門不肯自升堂，美人扶踏金階月。"]'),
('f980c17f-9772-4c08-a3be-bce750284ae1','古離別','顧況','唐','唐诗','tang','','[]','西江上，風動麻姑嫁時浪。',28,'全唐诗/poet.tang.13000.json','["西江上，風動麻姑嫁時浪。", "西山爲水水爲塵，不是人間離別人。"]'),
('bba479ed-b4a3-43d6-8487-e268da7913aa','長安道','顧況','唐','唐诗','tang','','[]','長安道，人無衣，馬無草，何不歸來山中老。',20,'全唐诗/poet.tang.13000.json','["長安道，人無衣，馬無草，何不歸來山中老。"]'),
('7cf536fe-b955-47a0-aa04-d5b039a829dc','龍宮操','顧況','唐','唐诗','tang','','[]','龍宮月明光參差，精衛銜石東飛時。',48,'全唐诗/poet.tang.13000.json','["龍宮月明光參差，精衛銜石東飛時。", "鮫人織綃採藕絲，翻江倒海傾吳蜀。", "漢女江妃杳相續，龍王宮中水不足。"]'),
('12c438e6-a5a5-4c4c-9820-4ccad6bf6338','梁廣畫花歌','顧況','唐','唐诗','tang','','[]','王母欲過劉徹家，飛瓊夜入雲軿車。',76,'全唐诗/poet.tang.13000.json','["王母欲過劉徹家，飛瓊夜入雲軿車。", "紫書分付與青鳥，却向人間求好花。", "上元夫人最小女，頭面端正能言語。", "手把梁生畫花看，凝嚬掩笑心相許。", "心相許，爲白阿孃從嫁與。"]'),
('1b34ea02-c7d3-491f-af4f-a3166c6b6e22','送別日晚歌','顧況','唐','唐诗','tang','','[]','日窅窅兮下山，望佳人兮不還。',52,'全唐诗/poet.tang.13000.json','["日窅窅兮下山，望佳人兮不還。", "花落兮屋上，草生兮堦間。", "日日兮春風，芳菲兮欲歇。", "老不可兮更少，君何爲兮輕別。"]'),
('ee096afe-357e-40fd-bc25-19361ea20a08','行路難三首 一','顧況','唐','唐诗','tang','','[]','君不見擔雪塞井空用力，炊砂作飯豈堪食。',97,'全唐诗/poet.tang.13000.json','["君不見擔雪塞井空用力，炊砂作飯豈堪食。", "一生肝膽向人盡，相識不如不相識。", "冬青樹上挂凌霄，歲晏花凋樹不凋。", "凡物各自有根本，種禾終不生荳苗。", "行路難，行路難，何處是平道。", "中心無事當富貴，今日看君顏色好。"]'),
('eca48934-83a4-469e-aaec-495e4224aa82','行路難三首 二','顧況','唐','唐诗','tang','','[]','君不見少年頭上如雲髮，少壯如雲老如雪。',99,'全唐诗/poet.tang.13000.json','["君不見少年頭上如雲髮，少壯如雲老如雪。", "豈知灌頂有醍醐，能使清涼頭不熱。", "呂梁之水挂飛流，黿鼉蛟蜃不敢遊。", "少年恃險若平地，獨倚長劍凌清秋。", "行路難，行路難，昔少年，今已老。", "前朝竹帛事皆空，日暮牛羊占城草。"]'),
('d580d0a3-5dc1-429b-9273-3608f6194c5b','行路難三首 三','顧況','唐','唐诗','tang','','[]','君不見古人燒水銀，變作北邙山上塵。',95,'全唐诗/poet.tang.13000.json','["君不見古人燒水銀，變作北邙山上塵。", "藕絲掛在虛空中，欲落不落愁殺人。", "睢水英雄多血刃，建章宮闕成煨燼。", "淮王身死桂樹折，徐福一去音書絕。", "行路難，行路難，生死皆由天。", "秦皇漢武遭不脫，汝獨何人學神仙。"]'),
('a413aab8-b859-42a8-a490-d4c0ca2002a3','悲歌 一','顧況','唐','唐诗','tang','','[]','邊城路，今人犂田昔人墓。',56,'全唐诗/poet.tang.13000.json','["邊城路，今人犂田昔人墓。", "岸上沙，昔日江水今人家。", "今人昔人共長歎，四氣相催節廻換。", "明月皎皎入華池，白雲離離渡霄漢。"]'),
('7a1d94ae-6617-47c5-933b-202a7dfa48a4','悲歌 二','顧況','唐','唐诗','tang','','[]','我欲昇天天隔霄，我欲渡水水無橋。',64,'全唐诗/poet.tang.13000.json','["我欲昇天天隔霄，我欲渡水水無橋。", "我欲上山山路險，我欲汲井井泉遙。", "越人翠被今何夕，獨立沙邊江草碧。", "紫燕西飛欲寄書，白雲何處逢來客。"]'),
('f79d9f65-cb2f-4ddb-a60e-3ef126825f09','悲歌 三','顧況','唐','唐诗','tang','','[]','新繫青絲百尺繩，心在君家轆轤上。',32,'全唐诗/poet.tang.13000.json','["新繫青絲百尺繩，心在君家轆轤上。", "我心皎潔君不知，轆轤一轉一惆悵。"]'),
('838cb3d4-9d9f-4365-ba74-bd375234b052','悲歌 四','顧況','唐','唐诗','tang','','[]','何處春風吹曉幕，江南淥水通朱閣。',32,'全唐诗/poet.tang.13000.json','["何處春風吹曉幕，江南淥水通朱閣。", "美人二八面如花，泣向春風畏花落。"]'),
('731a76c4-8cb7-4c78-afc2-a062339c5034','悲歌 五','顧況','唐','唐诗','tang','','[]','臨春風，聽春鳥，別時多，見時少。',32,'全唐诗/poet.tang.13000.json','["臨春風，聽春鳥，別時多，見時少。", "愁人夜永不得眠，瑤井玉繩相對曉。"]'),
('487b1bf1-6f50-4f64-8e1d-2576534397fc','悲歌 六','顧況','唐','唐诗','tang','','[]','軒轅黃帝初得仙，鼎湖一去三千年。',56,'全唐诗/poet.tang.13000.json','["軒轅黃帝初得仙，鼎湖一去三千年。", "周流三十六洞天，洞中日月星辰聯。", "騎龍駕景遊八極，軒轅弓劍無人識，東海青童寄消息。"]'),
('e8a4d82d-65d0-447e-831c-353f52a38640','春草謠','顧況','唐','唐诗','tang','','[]','春草不解行，隨人上東城。',28,'全唐诗/poet.tang.13000.json','["春草不解行，隨人上東城。", "正月二月色綿綿，千里萬里傷人情。"]'),
('e4a4e5b5-fbe1-44fd-a2b8-f88cfc6b9216','苔蘚山歌','顧況','唐','唐诗','tang','','[]','野人夜夢江南山，江南山深松桂閑。',96,'全唐诗/poet.tang.13000.json','["野人夜夢江南山，江南山深松桂閑。", "野人覺後長歎息，帖蘚黏苔作山色。", "閉門無事任盈虛，終日欹眠觀四如。", "一如白雲飛出壁，二如飛雨巖前滴。", "三如騰虎欲咆哮，四如嬾龍遭霹靂。", "嶮峭嵌空潭洞寒，小兒兩手扶欄干。"]'),
('e46f7ede-7f44-4b64-b079-f0d85f7c3550','同裴觀察東湖望山歌','顧況','唐','唐诗','tang','','[]','浴鮮積翠栖靈異，石洞花宮橫半空。',64,'全唐诗/poet.tang.13000.json','["浴鮮積翠栖靈異，石洞花宮橫半空。", "夜光潭上明星啟，風雨壇邊樹如洗。", "水淹徐孺宅恆乾，繩墜洪崖井無底。", "主人載酒東湖陰，遙望西山三四岑。"]'),
('7ec7c911-60f3-460c-9a95-7b8236486892','八月五日歌','顧況','唐','唐诗','tang','','[]','四月八日明星出，摩耶夫人降前佛。',160,'全唐诗/poet.tang.13000.json','["四月八日明星出，摩耶夫人降前佛。", "八月五日佳氣新，昭成太后生聖人。", "開元九年燕公說，奉詔聽置千秋節。", "丹青廟裏貯姚宋，花蕚樓中宴岐薛。", "清樂靈香幾處聞，鸞歌鳳吹動祥雲。", "已於武庫見靈鳥，仍向晉山逢老君。", "率土普天無不樂，河清海晏窮寥廓。", "梨園第子傳法曲，張果先生進仙藥。", "玉座淒涼遊帝京，悲翁迴首望承明。", "雲韶九奏杳然遠，唯有五陵松柏聲。"]'),
('f646a1ae-7a3e-4cdb-96d4-8c2ab4fb899a','露青竹杖歌','顧況','唐','唐诗','tang','','[]','鮮于仲通正當年，章仇兼瓊在蜀川。',376,'全唐诗/poet.tang.13000.json','["鮮于仲通正當年，章仇兼瓊在蜀川。", "約束蜀兒採馬鞭，蜀兒採鞭不敢眠。", "橫截斜飛飛鳥邊，繩橋夜上層崖顛。", "頭插白雲跨飛泉，採得馬鞭長且堅。", "浮漚丁子珠聯聯，灰煮蠟楷光爛然。", "章仇兼瓊持上天，上天雨露何其偏。", "飛龍閑廄馬數千，朝飲吳江夕秣燕。", "紅塵撲轡汗濕韉，師子麒麟聊比肩。", "江面昆明洗刷牽，四蹄踏浪頭枿天。", "蛟龍稽顙河伯虔，拓羯胡雛脚手鮮。", "陳閎韓幹丹青妍，欲貌未貌眼欲穿。", "金鞍玉勒錦連乾，騎入桃花楊柳煙。", "十二樓中奏管絃，樓中美人奪神仙。", "爭愛大家把此鞭，祿山入關關破年。", "忽見揚州北邙前，秪有人還千一錢。", "亭亭筆直無皴節，磨捋形相一條鐵。", "市頭格是無人別，江海賤臣不拘絏。", "垂窗掛影西窗缺，稚子覓衣挑仰穴。", "家童拾薪幾拗折，玉潤猶沾玉壘雪。", "碧鮮似染萇弘血，蜀帝城邊子規咽。", "相如橋上文君絕，往年策馬降至尊。", "七盤九折橫劍門，穆王八駿超崑崙。", "安用冉冉孤生根，聖人不貴難得貨，金玉珊珊誰買恩。"]'),
('e6515ec6-ebf7-462b-968c-292bd85c3e80','金璫玉珮歌','顧況','唐','唐诗','tang','','[]','贈君金璫太霄之玉珮，金鎖禹步之流珠。',66,'全唐诗/poet.tang.13000.json','["贈君金璫太霄之玉珮，金鎖禹步之流珠。", "五嶽真君之秘籙，九天丈人之寶書。", "東井沐浴辰已畢，先進洞房上奔日。", "借問君欲何處來，黃姑織女機邊出。"]'),
('a6cdf4b0-8738-431f-8868-7b55e4449a6a','瑤草春','顧況','唐','唐诗','tang','','[]','瑤草春，杳容與，江南豔歌京西舞。',136,'全唐诗/poet.tang.13000.json','["瑤草春，杳容與，江南豔歌京西舞。", "執心輕子都，信節冠秋胡。", "議以腰支嫁，時論自有夫。", "蟬鬢蛾眉明井底，燕裙趙袂縈轆轤。", "李生聞之淚如綆，不忍回頭看此井。", "月中桂樹落一枝，池上鵁鶄唳孤影。", "露桃穠李自成谿，流水終天不向西。", "翠帳綠窗寒寂寂，錦茵羅薦夜淒淒。", "瑤草春，丹井遠，別後相思意深淺。"]'),
('ee466a7e-a7e8-4eda-a53f-1d7fdaaa5e62','蕭鄲草書歌','顧況','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','蕭子草書人不及，洞庭葉落秋風急。',64,'全唐诗/poet.tang.13000.json','["蕭子草書人不及，洞庭葉落秋風急。", "上林花開春露濕，花枝濛濛向水垂。", "見君數行之灑落，石上之松松下鶴。", "若把君書比仲將，不知誰在凌雲閣。"]'),
('476dd07c-f924-451d-a721-cbc3957438ca','范山人畫山水歌','顧況','唐','唐诗','tang','','[]','山崢嶸，水泓澄。',52,'全唐诗/poet.tang.13000.json','["山崢嶸，水泓澄。", "漫漫汗汗一筆耕，一草一木棲神明。", "忽如空中有物，物中有聲。", "復如遠道望鄉客，夢遶山川身不行。"]'),
('6582ae44-7ca2-4d8e-b3c4-434d3ad6a38a','嵇山道芬上人畫山水歌','顧況','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','鏡中真僧白道芬，不服朱審李將軍。',48,'全唐诗/poet.tang.13000.json','["鏡中真僧白道芬，不服朱審李將軍。", "淥汗平鋪洞庭水，筆頭點出蒼梧雲。", "且看八月十五夜，月下看山盡如畫。"]'),
('6045a96b-444d-4bc2-adb7-84baa1d21591','杜秀才畫立走水牛歌','顧況','唐','唐诗','tang','','[]','崑崙兒，騎白象，時時鎖著師子項。',96,'全唐诗/poet.tang.13000.json','["崑崙兒，騎白象，時時鎖著師子項。", "奚奴跨馬不搭鞍，立走水牛驚漢官。", "江村小兒好誇騁，脚踏牛頭上牛領。", "淺草平田攃過時，大蟲著鈍幾落井。", "杜生知我戀滄州，畫作一障張牀頭。", "八十老婆拍手笑，妬他織女嫁牽牛。"]'),
('ce013b49-2360-4975-868d-51f326a07115','梁司馬畫馬歌','顧況','唐','唐诗','tang','','[]','畫精神，畫筋骨，一團旋風瞥滅沒。',80,'全唐诗/poet.tang.13000.json','["畫精神，畫筋骨，一團旋風瞥滅沒。", "仰秣如上賀蘭山，低頭欲飲長城窟。", "此馬昂然獨此羣，阿爺是龍飛入雲。", "黃沙枯磧無寸草，一日行過千里道。", "展處把筆欲描時，司馬一騧賽傾倒。"]'),
('0ebd6191-3d23-4144-81f6-7fb50f261225','丘小府小鼓歌','顧況','唐','唐诗','tang','','[]','地盤山鷄猶可像，坎坎砰砰隨手長。',32,'全唐诗/poet.tang.13000.json','["地盤山鷄猶可像，坎坎砰砰隨手長。", "夜半高樓沈醉時，萬里踏橋亂山響。"]'),
('5d35a08f-2e94-4820-b998-df34d276838e','宜城放琴客歌','顧況','唐','唐诗','tang','','[]','佳人玉立生此方，家住邯鄲不是倡。',160,'全唐诗/poet.tang.13000.json','["佳人玉立生此方，家住邯鄲不是倡。", "頭髻䰀鬌手爪長，善撫琴瑟有文章。", "新妍籠裙雲母光，朱絃綠水喧洞房。", "忽聞斗酒初決絕，日暮浮雲古離別。", "巴猿啾啾峽泉咽，淚落羅衣顏色暍。", "不知誰家更張設，絲履牆偏釵股折。", "南山闌干千丈雪，七十非人不暖熱。", "人情厭薄古共然，相公心在持事堅。", "上善若水任方圓，憶昨好之今棄捐。", "服藥不如獨自眠，從他更嫁一少年。"]'),
('df89d483-be68-42c9-aeae-dde37afb8667','李供奉彈箜篌歌','顧況','唐','唐诗','tang','','[]','國府樂手彈箜篌，赤黃條索金鎝頭。',376,'全唐诗/poet.tang.13000.json','["國府樂手彈箜篌，赤黃條索金鎝頭。", "早晨有敕鴛鴦殿，夜靜遂歌明月樓。", "起坐可憐能抱撮，大指調絃中指撥。", "腕頭花落舞製裂，手下鳥驚飛撥剌。", "珊瑚席，一聲一聲鳴錫錫。", "羅綺屏，一絃一絃如撼鈴。", "急彈好，遲亦好，宜遠聽，宜近聽。", "左手低，右手舉，易調移音天賜與。", "大絃似秋雁，聯聯度隴關。", "小絃似春燕，喃喃向人語。", "手頭疾，腕頭軟，來來去去如風卷。", "聲清泠泠鳴索索，垂珠碎玉空中落。", "美女爭窺玳瑁簾，聖人卷上真珠箔。", "大絃長，小絃短，小絃緊快大絃緩。", "初調鏘鏘似鴛鴦水上弄新聲，入深似太清仙鶴遊秘館。", "李供奉，儀容質，身才稍稍六尺一。", "在外不曾輙敎人，內裏聲聲不遣出。", "指剝葱，腕削玉，饒鹽饒醬五味足。", "弄調人間不識名，彈盡天下崛奇曲。", "胡曲漢曲聲皆好，彈着曲髓曲肝腦。", "往往從空入戶來，瞥瞥隨風落春草。", "草頭只覺風吹入，風來草即隨風立。", "草亦不知風到來，風亦不知聲緩急。", "爇玉燭，點銀燈，光照手，實可憎。"]'),
('0f7ccc3d-418a-4e51-a5c5-5e22c163b042','劉禪奴彈琵琶歌','顧況','唐','唐诗','tang','','[]','樂府只傳橫吹好，琵琶寫出關山道。',96,'全唐诗/poet.tang.13000.json','["樂府只傳橫吹好，琵琶寫出關山道。", "羈雁出塞繞黃雲，邊馬仰天嘶白草。", "明妃愁中漢使迴，蔡琰愁處胡笳哀。", "鬼神知妙欲收響，陰風切切四面來。", "李陵寄書別蘇武，自有生人無此苦。", "當時若值霍驃姚，滅盡烏孫奪公主。"]'),
('8ad3aa19-2d64-4a45-b0bc-12522587addb','李湖州孺人彈箏歌','顧況','唐','唐诗','tang','','[]','武帝昇天留法曲，淒清掩仰絃柱促。',96,'全唐诗/poet.tang.13000.json','["武帝昇天留法曲，淒清掩仰絃柱促。", "上陽宮人怨青苔，此夜想夫憐碧玉。", "思婦高樓刺壁窺，愁猿呌月鸚呼兒。", "寸心十指有長短，妙入神處無人知。", "獨把梁州凡幾拍，風沙對面胡秦隔。", "聽中忘却前溪碧，醉後猶疑邊草白。"]'),
('ac28499c-b62a-41e9-91cb-02da03af5253','鄭女彈箏歌','顧況','唐','唐诗','tang','','[]','鄭女八歲能彈箏，春風吹落天上聲。',72,'全唐诗/poet.tang.13000.json','["鄭女八歲能彈箏，春風吹落天上聲。", "一聲雍門淚承睫，兩聲赤鯉露鬐鬣。", "二聲白猿臂拓頰，鄭女出參丈人時。", "落花惹斷遊空絲，高樓不掩許聲出，羞殺百舌黃鶯兒。"]'),
('6ed42af4-01fa-47fe-88cf-d33e0e8aa90d','諒公洞庭孤橘歌','顧況','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','不種自生一株橘，誰敎渠向堦前出。',84,'全唐诗/poet.tang.13000.json','["不種自生一株橘，誰敎渠向堦前出。", "不羨江陵千木奴，下生白蟻子，上生青雀雛。", "飛花簷蔔旃檀香，結實如綴摩尼珠。", "洞庭橘樹籠煙碧，洞庭波月連沙白。", "待取天公放恩赦，儂家定作湖中客。"]'),
('ff924b90-45ee-4a80-adf9-d5c1645b03bd','送行歌','顧況','唐','唐诗','tang','','[]','送行人，歌一曲，何者爲泥何者玉？年華已向秋草裏，春夢猶傳故山綠。',32,'全唐诗/poet.tang.13000.json','["送行人，歌一曲，何者爲泥何者玉？年華已向秋草裏，春夢猶傳故山綠。"]'),
('5cc1becd-3500-4ff9-aba2-6c2282dc1f16','險竿歌','顧況','唐','唐诗','tang','','[]','宛陵女兒擘飛手，長竿橫空上下走。',144,'全唐诗/poet.tang.13000.json','["宛陵女兒擘飛手，長竿橫空上下走。", "已能輕險若平地，豈肯身爲一家婦。", "宛陵將士天下雄，一下定却長稍弓。", "翻身挂影恣騰蹋，反綰頭髻盤旋風。", "盤旋風，撇飛鳥，驚猿遶，樹枝褭。", "頭上打鼓不聞時，手蹉脚跌蜘蛛絲。", "忽雷掣斷流星尾，矐睒劃破蚩尤旗。", "若不隨仙作仙女，即應嫁賊生賊兒。", "中丞方略通變化，外戶不扃從女嫁。"]'),
('0af079ae-7cf1-4b44-b0c7-6731fc9b484d','洛陽行送洛陽韋七明府','顧況','唐','唐诗','tang','','[]','始上龍門望洛川，洛陽桃李豔陽天。',48,'全唐诗/poet.tang.13000.json','["始上龍門望洛川，洛陽桃李豔陽天。", "最好當年二三月，上陽宮樹千花發。", "疏家父子錯掛冠，梁鴻夫妻虛適越。"]'),
('5ff6466d-aa4d-4978-bac7-247b638b675f','黃鵠樓歌送獨孤助','顧況','唐','唐诗','tang','','[]','故人西去黃鵠樓，西江之水上天流，黃鵠杳杳江悠悠。',52,'全唐诗/poet.tang.13000.json','["故人西去黃鵠樓，西江之水上天流，黃鵠杳杳江悠悠。", "黃鵠徘徊故人別，離壺酒盡清絲絕。", "綠嶼沒餘煙，白沙連曉月。"]'),
('2205cb99-73fb-4acc-976f-5f2eeb381baa','廬山瀑布歌送李顧','顧況','唐','唐诗','tang','','["\u5e90\u5c71"]','飄白霓，挂丹梯。',72,'全唐诗/poet.tang.13000.json','["飄白霓，挂丹梯。", "應從織女機邊落，不遣潯陽湖向西。", "火雷劈山珠噴日，五老峰前九江溢。", "九江悠悠萬古情，古人行盡今人行。", "老人也欲上山去，上箇深山無姓名。"]'),
('4cd896dd-b8bb-4fe0-aafd-c0058b1887a7','朝上清歌','顧況','唐','唐诗','tang','','[]','潔眼朝上清，綠景開紫霞。',177,'全唐诗/poet.tang.13000.json','["潔眼朝上清，綠景開紫霞。", "皇皇紫微君，左右皆靈娥。", "曼聲流睇，和清歌些。", "至陽無諼，其樂多些。", "旌蓋颯沓，簫鼓和些。", "金鳳玉麟，鬱駢羅些。", "反風名香，香氣遐些。", "瓊田瑤草，壽無涯些。", "君着玉衣，升玉車些。", "欲降瓊宮，玉女家些。", "其桃千年，始着花些。", "蕭寥天清而滅雲，目瓊瓊兮情感。", "珮隨香兮夜聞，肅肅兮愔愔。", "啓天和兮洞靈心，和爲丹兮雲爲馬。", "君乘之觴于瑤池之上兮，三光羅列而在下。"]'),
('2a5a6e41-856a-4163-a050-ba97ce750635','剡紙歌','顧況','唐','唐诗','tang','','[]','雲門路上山陰雪，中有玉人持玉節。',96,'全唐诗/poet.tang.13000.json','["雲門路上山陰雪，中有玉人持玉節。", "宛委山裏禹餘糧，石中黃子黃金屑。", "剡溪剡紙生剡藤，噴水搗後爲蕉葉。", "欲寫金人金口經，寄與山陰山裏僧。", "手把山中紫羅筆，思量點畫龍蛇出。", "政是垂頭蹋翼時，不免向君求此物。"]'),
('8324e261-29c5-4995-ac3e-5b68ff76e411','洛陽早春','顧況','唐','唐诗','tang','','[]','何地避春愁，終年憶舊遊。',48,'全唐诗/poet.tang.13000.json','["何地避春愁，終年憶舊遊。", "一家千里外，百舌五更頭。", "客路偏逢雨，鄉山不入樓。", "故園桃李月，伊水向東流。"]'),
('8b558bc9-b3a5-4d04-96df-8ba26bc1f7dd','步虛詞','顧況','唐','唐诗','tang','','[]','逈步遊三洞，清心禮七真。',48,'全唐诗/poet.tang.13000.json','["逈步遊三洞，清心禮七真。", "飛符超羽翼，焚火醮星辰。", "殘藥沾雞犬，靈香出鳳麟。", "壺中無窄處，願得一容身。"]'),
('ba5f612b-efda-4052-8b01-f002c60dd1a6','鄱陽大雲寺一公房','顧況','唐','唐诗','tang','','[]','盡日陪遊處，斜陽竹院清。',48,'全唐诗/poet.tang.13000.json','["盡日陪遊處，斜陽竹院清。", "定中觀有漏，言外證無生。", "色界聊傳法，空門不用情。", "欲知相去近，鐘鼓兩聞聲。"]'),
('5ead7ca2-00ff-4485-aa33-17ce5b155139','送友失意南歸','顧況','唐','唐诗','tang','','[]','衣揮京洛塵，完璞伴歸人。',48,'全唐诗/poet.tang.13000.json','["衣揮京洛塵，完璞伴歸人。", "故國青山徧，滄江白髮新。", "鄰荒收酒幔，屋古布苔茵。", "不用通名姓，漁樵共主賓。"]'),
('62a0d80d-580b-497d-a998-a3de540a96e5','南歸','顧況','唐','唐诗','tang','','[]','老病力難任，猶多鏡雪侵。',48,'全唐诗/poet.tang.13000.json','["老病力難任，猶多鏡雪侵。", "鱸魚消宦況，鷗鳥識歸心。", "急雨江帆重，殘更驛樹深。", "鄉關殊可望，漸漸入吳音。"]'),
('5b5e79ce-17e3-44a2-9d9c-a5b3fe6e91b5','閑居自述','顧況','唐','唐诗','tang','','[]','榮辱不關身，誰爲疎與親。',48,'全唐诗/poet.tang.13000.json','["榮辱不關身，誰爲疎與親。", "有山堪結屋，無地可容塵。", "白髮偏添壽，黃花不笑貧。", "一樽朝暮醉，陶令果何人。"]'),
('0f79f502-4ed9-4cc1-8e7b-f063efa714a0','題歙山棲霞寺','顧況','唐','唐诗','tang','','[]','明徵君舊宅，陳後主題詩。',48,'全唐诗/poet.tang.13000.json','["明徵君舊宅，陳後主題詩。", "跡在人亡處，山空月滿時。", "寶瓶無破響，道樹有低枝。", "已是傷離客，仍逢靳尚祠。"]'),
('56e61fa9-cd16-47ec-bd76-daeec6588b9a','經廢寺','顧況','唐','唐诗','tang','','[]','不知何世界，有處似南朝。',48,'全唐诗/poet.tang.13000.json','["不知何世界，有處似南朝。", "石路無人掃，松門被火燒。", "斷幡猶挂剎，故板尚搘橋。", "數卷殘經在，多年字欲銷。"]'),
('553cbee8-d141-4bc0-bd1f-ac6e536c307c','送李道士','顧況','唐','唐诗','tang','','[]','人境年虛擲，仙源日未斜。',48,'全唐诗/poet.tang.13000.json','["人境年虛擲，仙源日未斜。", "羨君乘竹杖，辭我隱桃花。", "鳥去寧知路，雲飛似憶家。", "莫愁客鬢改，自有紫河車。"]'),
('cee61b1f-420b-47cc-a342-8ee07e2431cd','酬唐起居前後見寄二首 一','顧況','唐','唐诗','tang','','[]','愁人空望國，驚鳥不歸林。',48,'全唐诗/poet.tang.13000.json','["愁人空望國，驚鳥不歸林。", "莫話彈冠事，誰知結襪心。", "霜凋樹吹斷，土蝕劍痕深。", "欲作懷沙賦，明時恥自沈。"]'),
('9e1b461c-9625-4e7c-8da4-1874c7350f77','酬唐起居前後見寄二首 二','顧況','唐','唐诗','tang','','[]','何處弔靈均，江邊一老人。',50,'全唐诗/poet.tang.13000.json','["何處弔靈均，江邊一老人。", "漢儀君已接，楚奏我空頻。", "直道其如命，平生不負神。", "自傷庚子日，[鵩]鳥上承塵。"]'),
('559f34ec-f51c-4f98-bf67-6133cb2f64a6','奉酬茅山贈賜幷簡綦毋正字','顧況','唐','唐诗','tang','','[]','玉帝居金闕，靈山幾處朝。',48,'全唐诗/poet.tang.13000.json','["玉帝居金闕，靈山幾處朝。", "簡書猶有畏，神理詎能超。", "鶴廟新家近，龍門舊國遙。", "離懷結不斷，玉洞一吹簫。"]'),
('b247d865-f336-48cd-add3-e6dedf0f7739','白蘋洲送客','顧況','唐','唐诗','tang','','[]','莫信梅花發，由來謾報春。',48,'全唐诗/poet.tang.13000.json','["莫信梅花發，由來謾報春。", "不才充野客，扶病送朝臣。", "闕下搖青珮，洲邊採白蘋。", "臨流不痛飲，鷗鳥也欺人。"]'),
('e8e4d534-83c4-407e-94c2-9f04d2fba5d0','春鳥詞送元秀才入京','顧況','唐','唐诗','tang','','[]','春來繡羽齊，暮向竹林栖。',48,'全唐诗/poet.tang.13000.json','["春來繡羽齊，暮向竹林栖。", "禁苑銜花出，河橋隔樹啼。", "尋聲知去遠，顧影念飛低。", "別有無巢燕，猶窺幕上泥。"]'),
('143a6266-dd4e-4886-b45b-34c0f86c56b5','別江南','顧況','唐','唐诗','tang','','[]','江城吹曉角，愁殺遠行人。',48,'全唐诗/poet.tang.13000.json','["江城吹曉角，愁殺遠行人。", "漢將猶防虜，吳官欲向秦。", "布帆輕白浪，錦帶入紅塵。", "將底求名宦，平生但任真。"]'),
('d3049ded-bdb2-4b61-a1c4-348994e5ce98','空梁落燕泥','顧況','唐','唐诗','tang','','[]','卷幕參差燕，常銜濁水泥。',48,'全唐诗/poet.tang.13000.json','["卷幕參差燕，常銜濁水泥。", "爲黏珠履跡，未等畫梁齊。", "舊點痕猶淺，新巢緝尚低。", "不緣頻上落，那得此飛棲。"]'),
('dd52aa19-bfdc-4169-9aca-f3cccb0e993c','上元夜憶長安','顧況','唐','唐诗','tang','','[]','滄州老一年，老去憶秦川。',48,'全唐诗/poet.tang.13000.json','["滄州老一年，老去憶秦川。", "處處逢珠翠，家家聽管絃。", "雲車龍闕下，火樹鳳樓前。", "今夜滄州夜，滄州夜月圓。"]'),
('a717b666-8ab4-4505-bed2-5445f6c07ba3','酬揚州白塔寺永上人','顧況','唐','唐诗','tang','','[]','塔上是何緣，香燈續細煙。',48,'全唐诗/poet.tang.13000.json','["塔上是何緣，香燈續細煙。", "松枝當麈尾，柳絮替蠶綿。", "浮草經行徧，空花義趣圓。", "我來雖爲法，暫借一牀眠。"]'),
('92a96883-6408-4218-a9df-e077f72c16c5','送韋秀才赴舉','顧況','唐','唐诗','tang','','[]','鄱陽中酒地，楚老獨醒年。',48,'全唐诗/poet.tang.13000.json','["鄱陽中酒地，楚老獨醒年。", "芳桂君應折，沈灰我不然。", "洛橋浮逆水，關樹接非煙。", "唯有殘生夢，猶能到日邊。"]'),
('d7067d91-3467-4176-a227-444c90d9ce6d','送使君','顧況','唐','唐诗','tang','','[]','天中洛陽道，海上使君歸。',48,'全唐诗/poet.tang.13000.json','["天中洛陽道，海上使君歸。", "拂霧趨金殿，焚香入璅闈。", "山亭傾別酒，野服間朝衣。", "他日思朱鷺，知從小苑飛。"]'),
('ab9d8948-13f5-45a7-9a53-03f615c31f4b','歷陽苦雨','顧況','唐','唐诗','tang','','[]','襄城秋雨晦，楚客不歸心。',48,'全唐诗/poet.tang.13000.json','["襄城秋雨晦，楚客不歸心。", "亥市風煙接，隋宮草路深。", "離憂翻獨笑，用事感浮陰。", "夜夜空堦響，唯餘蚯蚓吟。"]'),
('f865e685-cc9b-4edc-b254-6326223ef92c','傷大理謝少卿','顧況','唐','唐诗','tang','','["\u6cf0\u5c71"]','舊館絕逢迎，新詩何處呈。',48,'全唐诗/poet.tang.13000.json','["舊館絕逢迎，新詩何處呈。", "空留封禪草，已作岱宗行。", "柳蠹風吹析，堦崩雪遶平。", "無因重來此，剩哭兩三聲。"]'),
('0866f21e-3339-4a9e-9084-ba36856743e6','經徐侍郎墓作','顧況','唐','唐诗','tang','','[]','不知山吏部，墓作石橋東。',48,'全唐诗/poet.tang.13000.json','["不知山吏部，墓作石橋東。", "宅兆鄉關異，平生翰墨空。", "夜泉無曉日，枯樹足悲風。", "更想幽冥事，唯應有夢同。"]'),
('e7e831b4-2a6a-437e-996c-1a2df9fbb761','酅公合祔挽歌','顧況','唐','唐诗','tang','','[]','草露前朝事，荆茅聖主封。',48,'全唐诗/poet.tang.13000.json','["草露前朝事，荆茅聖主封。", "空傳餘竹帛，永絕舊歌鐘。", "清鏡無雙影，窮泉有幾重。", "笳簫最悲處，風入九原松。"]'),
('b7a6df80-82b4-4185-ba56-134e852b20a3','相國晉公挽歌二首 一','顧況','唐','唐诗','tang','','[]','玉節朝天罷，洪爐造化新。',48,'全唐诗/poet.tang.13000.json','["玉節朝天罷，洪爐造化新。", "中和方作聖，太素忽收神。", "盛德橫千古，高標出四鄰。", "欲知言不盡，處處有遺塵。"]'),
('646066df-3633-448c-aee8-b5d8eedace98','相國晉公挽歌二首 二','顧況','唐','唐诗','tang','','[]','凝笳催曉奠，丹旐向青山。',48,'全唐诗/poet.tang.13000.json','["凝笳催曉奠，丹旐向青山。", "夕照新塋近，秋風故吏還。", "本朝光漢代，從此掃胡關。", "今日天難問，浮雲滿世間。"]'),
('a5301061-dc9b-4a5b-b5ec-55cb5c2feb65','晉公魏國夫人柳氏挽歌','顧況','唐','唐诗','tang','','[]','魚軒海上遙，鸞影月中銷。',48,'全唐诗/poet.tang.13000.json','["魚軒海上遙，鸞影月中銷。", "雙劍來時合，孤桐去日凋。", "夕陽迷隴隧，秋雨咽笳簫。", "畫翣無留影，銘旌已度橋。"]'),
('25ab4e52-dd05-421d-aadf-df596f6af0fb','義川公主挽詞','顧況','唐','唐诗','tang','','[]','弄玉吹簫後，湘靈鼓瑟時。',48,'全唐诗/poet.tang.13000.json','["弄玉吹簫後，湘靈鼓瑟時。", "月邊丹桂落，風底白楊悲。", "雜珮分泉戶，餘香出繐帷。", "夜臺飛鏡匣，偏共掩蛾眉。"]'),
('c4b98c6a-b5a2-4f87-b870-e72a11a73af6','憶山中','顧況','唐','唐诗','tang','','[]','春還不得還，家在最深山。',48,'全唐诗/poet.tang.13000.json','["春還不得還，家在最深山。", "蕙圃泉澆濕，松窗月映閑。", "薄田臨谷口，小職向人間。", "去處但無事，重門深閉關。"]'),
('912f6639-a774-4d02-8c17-07f6bc3b1d63','送大理張卿','顧況','唐','唐诗','tang','','[]','春色依依惜解攜，月卿今夜泊隋堤。',64,'全唐诗/poet.tang.13000.json','["春色依依惜解攜，月卿今夜泊隋堤。", "白沙洲上江籬長，綠樹村邊謝豹啼。", "遷客比來無倚仗，故人相去隔雲泥。", "越禽唯有南枝分，目送孤鴻飛向西。"]'),
('d7732963-08cf-49ca-b903-6e954401ea56','宿湖邊山寺','顧況','唐','唐诗','tang','','[]','羣峰過雨澗淙淙，松下扉扃白鶴雙。',64,'全唐诗/poet.tang.13000.json','["羣峰過雨澗淙淙，松下扉扃白鶴雙。", "香透經窗籠檜栢，雲生梵宇濕旛幢。", "蒲團僧定風過席，葦岸漁歌月墮江。", "誰悟此生同寂滅，老禪慧力得心降。"]'),
('c1a4211f-4bca-4693-b6a0-9c1e59eacffd','湖南客中春望','顧況','唐','唐诗','tang','','[]','鳴雁嘹嘹北向頻，淥波何處是通津。',64,'全唐诗/poet.tang.13000.json','["鳴雁嘹嘹北向頻，淥波何處是通津。", "風塵海內憐雙鬢，涕淚天涯慘一身。", "故里音書應望絕，異鄉景物又更新。", "便拋印綬從歸隱，吳渚香蓴漫吐春。"]'),
('9b813348-a5e1-4f1e-a814-6dfe8b8a09a9','閑居懷舊','顧況','唐','唐诗','tang','','[]','日長鼓腹愛吾廬，洗竹澆花興有餘。',64,'全唐诗/poet.tang.13000.json','["日長鼓腹愛吾廬，洗竹澆花興有餘。", "騷客空傳成相賦，晉人已負絕交書。", "貧居謫所誰推轂，仕向侯門恥曳裾。", "今日思來總皆罔，汗青功業又何如。"]'),
('b85270f0-f1a5-49c5-b3be-21f62190dcda','寄江南鶴林寺石冰上人','顧況','唐','唐诗','tang','','[]','山川重復出，心地闇相逢。',72,'全唐诗/poet.tang.13000.json','["山川重復出，心地闇相逢。", "忽憶秋江月，如聞古寺鐘。", "湖平南北岸，雲抱兩三峰。", "定力超香象，真言攝毒龍。", "風中何處鶴，石上幾年松。", "爲報煙霞道，人間共不容。"]'),
('acc7bfd0-3b97-48a6-bdb9-eff5990d496f','樂府','顧況','唐','唐诗','tang','','[]','暖谷春光至，宸遊近甸榮。',144,'全唐诗/poet.tang.13000.json','["暖谷春光至，宸遊近甸榮。", "雲隨天仗轉，風入御簾輕。", "翠蓋浮佳氣，朱樓倚太清。", "朝臣冠劍退，宮女管絃迎。", "細草承雕輦，繁花入幔城。", "文房開聖藻，武衛宿天營。", "玉醴隨觴至，銅壺逐漏行。", "五星含土德，萬姓徹中聲。", "親祀先崇典，躬推示勸耕。", "國風新正樂，農器近消兵。", "道德關河固，刑章日月明。", "野人同鳥獸，率舞感昇平。"]'),
('656c812a-f04c-4282-b01b-412200c4017e','送從兄使新羅','顧況','唐','唐诗','tang','','[]','六氣銅渾轉，三光玉律調。',288,'全唐诗/poet.tang.13000.json','["六氣銅渾轉，三光玉律調。", "河宮清奉賮，海嶽晏來朝。", "地絕提封入，天平賜貢饒。", "揚威輕破虜，柔服恥征遼。", "曙色黃金闕，寒聲白鷺潮。", "樓船非習戰，驄馬是嘉招。", "帝女飛銜石，鮫人賣淚綃。", "管寧雖不偶，徐市儻相邀。", "獨島緣空翠，孤霞上泬寥。", "蟾蜍同漢月，螮蝀異秦橋。", "水豹橫吹浪，花鷹逈拂霄。", "晨裝凌莽渺，夜泊記招搖。", "幾路通員嶠，何山是沃焦。", "颶風晴汨起，陰火暝潛燒。", "鬢髮成新髻，人參長舊苗。", "扶桑銜日近，析木帶津遙。", "夢向愁中積，魂當別處銷。", "臨川思結網，見彈欲求鴞。", "共散羲和曆，誰差甲子朝。", "滄波伏忠信，譯語辨謳謠。", "疊鼓鯨鱗隱，陰帆鷁首飄。", "南溟垂大翼，西海飲文鰩。", "指景尋靈草，排雲聽洞簫。", "封侯萬里外，未肯後班超。"]'),
('8aec2246-5d1e-4a0d-87f5-69d4ec66321f','山居即事','顧況','唐','唐诗','tang','','[]','下泊降茅仙，蕭閑隱洞天。',72,'全唐诗/poet.tang.13000.json','["下泊降茅仙，蕭閑隱洞天。", "楊君閑上法，司命駐流年。", "崦合桃花水，窗分柳谷煙。", "抱孫堪種樹，倚杖問耘田。", "世事休相擾，浮名任一邊。", "由來謝安石，不解飲靈泉。"]'),
('c69e3e27-af82-404b-9a10-7c1525da1176','題盧道土房','顧況','唐','唐诗','tang','','[]','秋砧響落木，共坐茅君家。',72,'全唐诗/poet.tang.13000.json','["秋砧響落木，共坐茅君家。", "唯見兩童子，門外汲井花。", "空壇靜白日，神鼎飛丹砂。", "麈尾拂霜草，金鈴搖霽霞。", "上章塵世隔，看弈桐陰斜。", "稽首問仙要，黃精堪餌花。"]'),
('0eaa8b3b-92d7-413b-ad72-8c9ac3bd4f80','夢後吟','顧況','唐','唐诗','tang','','[]','醉中還有夢，身外已無心。',24,'全唐诗/poet.tang.13000.json','["醉中還有夢，身外已無心。", "明鏡唯知老，青山何處深。"]'),
('34f50cc0-405e-4928-b678-b798c6a1f918','題靈山寺','顧況','唐','唐诗','tang','','[]','覺地本隨身，靈山重結因。',24,'全唐诗/poet.tang.13000.json','["覺地本隨身，靈山重結因。", "如何戰鳥佛，不化捕魚人。"]'),
('d3162017-25c7-4031-9ad0-67d9815e79f8','題元陽觀舊讀書房贈李範','顧況','唐','唐诗','tang','','[]','此觀十年遊，此房千里宿。',24,'全唐诗/poet.tang.13000.json','["此觀十年遊，此房千里宿。", "還來舊窗下，更取君書讀。"]'),
('241d7f69-6f6d-4e96-8912-e36cfde5b3c6','永嘉','顧況','唐','唐诗','tang','','[]','東甌傳舊俗，風日江邊好。',24,'全唐诗/poet.tang.13000.json','["東甌傳舊俗，風日江邊好。", "何處樂神聲，夷歌出煙島。"]'),
('b8f54472-64d2-4fcb-8683-645283ded31f','青弋江','顧況','唐','唐诗','tang','','[]','淒清回泊夜，淪波激石響。',24,'全唐诗/poet.tang.13000.json','["淒清回泊夜，淪波激石響。", "村邊草市橋，月下罟師網。"]'),
('440821cb-eda0-4881-8f6a-3d7708c6c939','聽山鷓鴣','顧況','唐','唐诗','tang','','[]','誰家無春酒，何處無春鳥。',24,'全唐诗/poet.tang.13000.json','["誰家無春酒，何處無春鳥。", "夜宿桃花村，踏歌接天曉。"]'),
('a3ff9642-7681-4ab7-8cfc-347a97ca7609','山逕柳','顧況','唐','唐诗','tang','','[]','宛轉若遊絲，淺深栽綠崦。',24,'全唐诗/poet.tang.13000.json','["宛轉若遊絲，淺深栽綠崦。", "年年立春後，即被啼鶯占。"]'),
('8db96758-49ae-4251-afa8-2ec0cf0eaf66','石上藤','顧況','唐','唐诗','tang','','[]','空山無鳥跡，何物如人意。',24,'全唐诗/poet.tang.13000.json','["空山無鳥跡，何物如人意。", "委曲結繩文，離披草書字。"]'),
('1c3b38ef-9c86-4971-8fe5-6234163dce8f','薜荔庵','顧況','唐','唐诗','tang','','[]','薜荔作禪庵，重疊庵邊樹。',24,'全唐诗/poet.tang.13000.json','["薜荔作禪庵，重疊庵邊樹。", "空山徑欲絕，也有人知處。"]'),
('974d29ec-068c-4022-81f5-ebdf6d8c4bc8','芙蓉榭','顧況','唐','唐诗','tang','','[]','風擺蓮衣乾，月背鳥巢寒。',24,'全唐诗/poet.tang.13000.json','["風擺蓮衣乾，月背鳥巢寒。", "文魚翻亂葉，翠羽上危欄。"]'),
('e98e72c8-c907-48b3-b776-24e4509cef4d','欹松漪','顧況','唐','唐诗','tang','','[]','湛湛碧漣漪，老松欹側臥。',24,'全唐诗/poet.tang.13000.json','["湛湛碧漣漪，老松欹側臥。", "悠揚綠蘿影，下拂波紋破。"]'),
('2279418a-3ec1-46f2-beae-accd316bdf70','焙茶塢','顧況','唐','唐诗','tang','','[]','新茶已上焙，舊架憂生醭。',24,'全唐诗/poet.tang.13000.json','["新茶已上焙，舊架憂生醭。", "旋旋續新烟，呼兒劈寒木。"]'),
('0fd65cf5-17cc-4e5c-91b3-390c249f056f','彈琴谷','顧況','唐','唐诗','tang','','[]','谷中誰彈琴，琴響谷冥寂。',24,'全唐诗/poet.tang.13000.json','["谷中誰彈琴，琴響谷冥寂。", "因君扣商調，草蟲驚暗壁。"]'),
('e2f0865f-ffe5-4671-9af7-8bd0f36df8fc','白鷺汀','顧況','唐','唐诗','tang','','[]','靃靡汀草碧，淋森鷺毛白。',24,'全唐诗/poet.tang.13000.json','["靃靡汀草碧，淋森鷺毛白。", "夜起沙月中，思量捕魚策。"]'),
('e3f9a129-2459-4f81-bb53-efff3e35b551','千松嶺','顧況','唐','唐诗','tang','','[]','終日吟天風，有時天籟止。',24,'全唐诗/poet.tang.13000.json','["終日吟天風，有時天籟止。", "問渠何旨意，恐落凡人耳。"]'),
('71d9f2b6-dfd3-4ee9-8e0e-cbd31c2829e0','黃菊灣','顧況','唐','唐诗','tang','','[]','時菊凝曉露，露華滴秋灣。',24,'全唐诗/poet.tang.13000.json','["時菊凝曉露，露華滴秋灣。", "仙人釀酒熟，醉裏飛空山。"]'),
('bfccdbbd-1901-4bcb-a4fa-ee2ade092dd6','臨平湖','顧況','唐','唐诗','tang','','[]','采藕平湖上，藕泥封藕節。',24,'全唐诗/poet.tang.13000.json','["采藕平湖上，藕泥封藕節。", "船影入荷香，莫衝蓮柄折。"]'),
('519750da-fa09-4e97-a520-42a78269efaf','山春洞','顧況','唐','唐诗','tang','','[]','引燭踏仙泥，時時亂乳燕。',24,'全唐诗/poet.tang.13000.json','["引燭踏仙泥，時時亂乳燕。", "不知何道士，手把靈書卷。"]'),
('cf76ed00-9869-4859-893e-e63418e21d3e','石竇泉','顧況','唐','唐诗','tang','','[]','吹沙復噴石，曲折仍圓旋。',24,'全唐诗/poet.tang.13000.json','["吹沙復噴石，曲折仍圓旋。", "野客漱流時，杯黏落花片。"]'),
('7f16896a-462b-4830-a159-b81ca3323bf1','古仙壇','顧況','唐','唐诗','tang','','[]','遠山誰放燒，疑是壇邊醮。',24,'全唐诗/poet.tang.13000.json','["遠山誰放燒，疑是壇邊醮。", "仙人錯下山，拍手壇邊笑。"]'),
('308cac64-243c-4581-8e4a-3274bb13e10c','題山頂寺','顧況','唐','唐诗','tang','','[]','遙聞林下語，知是經行所。',24,'全唐诗/poet.tang.13000.json','["遙聞林下語，知是經行所。", "日暮香風時，諸天散花雨。"]'),
('8e7fcf3a-7b42-4ce0-8c84-aba8902c6d50','天寶題壁','顧況','唐','唐诗','tang','','[]','五十餘年別，伶俜道不行。',24,'全唐诗/poet.tang.13000.json','["五十餘年別，伶俜道不行。", "却來書處在，惆悵似前生。"]'),
('b24aaa0c-a199-45dd-a584-37b6b2582933','哭李別駕','顧況','唐','唐诗','tang','','[]','故人行跡滅，秋草向南悲。',24,'全唐诗/poet.tang.13000.json','["故人行跡滅，秋草向南悲。", "不欲頻回步，孀妻正哭時。"]'),
('cf395d16-5365-4b0f-91d0-adeadd0ffc7c','春雨不聞百舌','顧況','唐','唐诗','tang','','[]','百舌春來啞，愁人共待晴。',24,'全唐诗/poet.tang.13000.json','["百舌春來啞，愁人共待晴。", "不關秋水事，飲恨亦無聲。"]'),
('57801b63-5db7-44fa-af5b-09a496781815','憶鄱陽舊遊','顧況','唐','唐诗','tang','','[]','悠悠南國思，夜向江南泊。',24,'全唐诗/poet.tang.13000.json','["悠悠南國思，夜向江南泊。", "楚客斷腸時，月明楓子落。"]'),
