('08d7b6c7-7471-422c-8bdc-353b98ddf6ea','贈僧二首 二','顧況','唐','唐诗','tang','','[]','出頭皆是新年少，何處能容老病翁。',32,'全唐诗/poet.tang.13000.json','["出頭皆是新年少，何處能容老病翁。", "更把浮榮喻生滅，世間無事不虛空。"]'),
('068ebef7-dc84-4cbd-bb7e-77a9d4cebd4b','登樓望水','顧況','唐','唐诗','tang','','["\u6101\u7eea", "\u601d\u4e61", "\u5199\u666f"]','鳥啼花發柳含煙，擲却風光憶少年。',32,'全唐诗/poet.tang.13000.json','["鳥啼花發柳含煙，擲却風光憶少年。", "更上高樓望江水，故鄉何處一歸船。"]'),
('4c0957b5-dd32-4391-b11c-cef4e57019c3','湖中','顧況','唐','唐诗','tang','','[]','青草湖邊日色低，黃茅嶂裏鷓鴣啼。',32,'全唐诗/poet.tang.13000.json','["青草湖邊日色低，黃茅嶂裏鷓鴣啼。", "丈夫飄蕩今如此，一曲長歌楚水西。"]'),
('b64c656c-1346-4fce-9667-57d2472ab4f2','歲日作','顧況','唐','唐诗','tang','','[]','不覺老將春共至，更悲攜手幾人全。',32,'全唐诗/poet.tang.13000.json','["不覺老將春共至，更悲攜手幾人全。", "還丹寂寞羞明鏡，手把屠蘇讓少年。"]'),
('27b254dd-2016-446f-98cf-d55786e671b0','山中贈客','顧況','唐','唐诗','tang','','[]','山中好處無人別，澗梅僞作山中雪。',32,'全唐诗/poet.tang.13000.json','["山中好處無人別，澗梅僞作山中雪。", "野客相逢夜不眠，山中童子燒松節。"]'),
('a430fc14-8402-4e73-a6c6-b46041986d07','王郎中妓席五詠 箜篌','顧況','唐','唐诗','tang','','[]','玉作搔頭金步搖，高張苦調響連宵。',32,'全唐诗/poet.tang.13000.json','["玉作搔頭金步搖，高張苦調響連宵。", "欲知寫盡相思夢，度水尋雲不用橋。"]'),
('e0526a65-b0e0-47d4-b141-43443bc76606','王郎中妓席五詠 舞','顧況','唐','唐诗','tang','','[]','汗浥新裝畫不成，絲催急節舞衣輕。',32,'全唐诗/poet.tang.13000.json','["汗浥新裝畫不成，絲催急節舞衣輕。", "落花遶樹疑無影，回雪從風暗有情。"]'),
('aa28008b-e95f-4b32-a869-12a16f34d987','王郎中妓席五詠 歌','顧況','唐','唐诗','tang','','[]','柳拂青樓花滿衣，能歌宛轉世應稀。',32,'全唐诗/poet.tang.13000.json','["柳拂青樓花滿衣，能歌宛轉世應稀。", "空中幾處聞清響，欲遶行雲不遣飛。"]'),
('d1f5c7c4-3fe6-408c-8865-db6c31ab518b','王郎中妓席五詠 箏','顧況','唐','唐诗','tang','','[]','秦聲楚調怨無窮，隴水胡笳咽復通。',32,'全唐诗/poet.tang.13000.json','["秦聲楚調怨無窮，隴水胡笳咽復通。", "莫遣黃鶯花裏囀，參差撩亂妬春風。"]'),
('f228b77d-1c21-478f-a6f1-59ed877adc14','王郎中妓席五詠 笙','顧況','唐','唐诗','tang','','[]','欲寫人間離別心，須聽鳴鳳似龍吟。',32,'全唐诗/poet.tang.13000.json','["欲寫人間離別心，須聽鳴鳳似龍吟。", "江南曲盡歸何處，洞水山雲知淺深。"]'),
('50defe07-70d9-4bea-8dc8-f6258bbec03e','送李山人還玉溪','顧況','唐','唐诗','tang','','[]','好鳥共鳴臨水樹，幽人獨欠買山錢。',32,'全唐诗/poet.tang.13000.json','["好鳥共鳴臨水樹，幽人獨欠買山錢。", "若爲種得千竿竹，引取君家一眼泉。"]'),
('797eb1a3-4a26-4075-adb0-52b09464228b','送少微上人還鹿門','顧況','唐','唐诗','tang','','[]','少微不向吳中隱，爲箇生緣在鹿門。',32,'全唐诗/poet.tang.13000.json','["少微不向吳中隱，爲箇生緣在鹿門。", "行入漢江秋月色，襄陽耆舊幾人存。"]'),
('2a44af03-7327-40d4-88c0-f09fb6bbd5db','宿昭應','顧況','唐','唐诗','tang','','[]','武帝祈靈太乙壇，新豐樹色繞千官。',32,'全唐诗/poet.tang.13000.json','["武帝祈靈太乙壇，新豐樹色繞千官。", "那知今夜長生殿，獨閉山門月影寒。"]'),
('05dcdf54-0d4d-4d22-a2c8-916b38ba00e4','題琅邪上方','顧況','唐','唐诗','tang','','[]','東晉王家在此溪，南朝樹色隔窗低。',32,'全唐诗/poet.tang.13000.json','["東晉王家在此溪，南朝樹色隔窗低。", "碑沈字滅昔人遠，谷鳥猶向寒花啼。"]'),
('1b75367f-b4bb-48da-a7fa-6d98d3d95322','安仁港口望仙人城','顧況','唐','唐诗','tang','','[]','樓臺采翠遠分明，聞說仙家在此城。',32,'全唐诗/poet.tang.13000.json','["樓臺采翠遠分明，聞說仙家在此城。", "欲上仙城無路上，水邊花裏有人聲。"]'),
('22936d54-909d-468d-bbb0-c5268bbdf0d6','寄祕書包監','顧況','唐','唐诗','tang','','[]','一別長安路幾千，遙知舊日主人憐。',32,'全唐诗/poet.tang.13000.json','["一別長安路幾千，遙知舊日主人憐。", "賈生只是三年謫，獨自無才已四年。"]'),
('cf75254e-a399-47c0-b188-79c3b0be396b','小孤山','顧況','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','古廟楓林江水邊，寒鴉接飯雁橫天。',32,'全唐诗/poet.tang.13000.json','["古廟楓林江水邊，寒鴉接飯雁橫天。", "大孤山遠小孤出，月照洞庭歸客船。"]'),
('3d46a51d-3295-440e-88f0-1a2985aae729','送李秀才遊嵩山','顧況','唐','唐诗','tang','','[]','嵩山石壁挂飛流，無限神仙在上頭。',32,'全唐诗/poet.tang.13000.json','["嵩山石壁挂飛流，無限神仙在上頭。", "采得新詩題石壁，老人惆悵不同遊。"]'),
('9559b3b8-a288-47a0-9494-2be54f934ab5','從剡溪至赤城','顧況','唐','唐诗','tang','','[]','靈溪宿處接靈山，窈映高樓向月閑。',32,'全唐诗/poet.tang.13000.json','["靈溪宿處接靈山，窈映高樓向月閑。", "夜半鶴聲殘夢裏，猶疑琴曲洞房閒。"]'),
('65c4e93c-38d0-4247-a7cc-b19c6ee77743','葉上題詩從苑中流出','顧況','唐','唐诗','tang','','[]','花落深宮鶯亦悲，上陽宮女斷腸時。',32,'全唐诗/poet.tang.13000.json','["花落深宮鶯亦悲，上陽宮女斷腸時。", "君恩不閉東流水，葉上題詩寄與誰。"]'),
('74cd7154-770a-41c4-b55d-1e27ac1ba628','崦裏桃花','顧況','唐','唐诗','tang','','[]','崦裏桃花逢女冠，林間杏葉落仙壇。',32,'全唐诗/poet.tang.13000.json','["崦裏桃花逢女冠，林間杏葉落仙壇。", "老人方授上清籙，夜聽步虛山月寒。"]'),
('c3186f0a-f6a1-4d01-81a2-f3533de1826d','聽子規','顧況','唐','唐诗','tang','','[]','棲霞山中子規鳥，口邊血出啼不了。',32,'全唐诗/poet.tang.13000.json','["棲霞山中子規鳥，口邊血出啼不了。", "山僧後夜初出定，聞似不聞山月曉。"]'),
('7343f60d-c51e-44a0-9b6d-30fb63783ab0','竹枝曲','顧況','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','帝子蒼梧不復歸，洞庭葉下荆雲飛。',32,'全唐诗/poet.tang.13000.json','["帝子蒼梧不復歸，洞庭葉下荆雲飛。", "巴人夜唱竹枝後，腸斷曉猿聲漸稀。"]'),
('ee152d89-4839-4572-b606-46d8c3a1d744','尋僧二首 一','顧況','唐','唐诗','tang','','[]','方丈玲瓏花竹閑，已將心印出人閒。',32,'全唐诗/poet.tang.13000.json','["方丈玲瓏花竹閑，已將心印出人閒。", "家家門外長安道，何處相逢是寶山。"]'),
('6e310a1e-e27f-4316-854a-0a0543fa9e85','尋僧二首 二','顧況','唐','唐诗','tang','','[]','彌天釋子本高情，往往山中獨自行。',32,'全唐诗/poet.tang.13000.json','["彌天釋子本高情，往往山中獨自行。", "莫怪狂人游楚國，蓮花只在淤泥生。"]'),
('02430665-d8b1-4830-8b51-744091ebcc22','桃花曲','顧況','唐','唐诗','tang','','[]','魏帝宮人舞鳳樓，隋家天子泛龍舟。',32,'全唐诗/poet.tang.13000.json','["魏帝宮人舞鳳樓，隋家天子泛龍舟。", "君王夜醉春眠晏，不覺桃花逐水流。"]'),
('74e40685-01eb-443a-a7e7-e6d99f61bed8','贈遠','顧況','唐','唐诗','tang','','[]','暫出河邊思遠道，却來窗下聽新鶯。',32,'全唐诗/poet.tang.13000.json','["暫出河邊思遠道，却來窗下聽新鶯。", "故人一別幾時見，春草還從舊處生。"]'),
('00ede8d1-4ba1-4b59-9021-bddf471b00e4','早春思歸有唱竹枝歌者坐中下淚','顧況','唐','唐诗','tang','','[]','渺渺春生楚水波，楚人齊唱竹枝歌。',32,'全唐诗/poet.tang.13000.json','["渺渺春生楚水波，楚人齊唱竹枝歌。", "與君皆是思歸客，拭淚看花奈老何。"]'),
('d9bbd52c-6e49-44de-94c2-6b2ca60c265c','送郭秀才','顧況','唐','唐诗','tang','','[]','故人曾任丹徒令，買得青山擬獨耕。',32,'全唐诗/poet.tang.13000.json','["故人曾任丹徒令，買得青山擬獨耕。", "不作草堂招遠客，却將垂柳借啼鶯。"]'),
('5372fb27-5a56-4669-85c2-1c418a0f2330','宮詞','顧況','唐','唐诗','tang','','["\u65e0\u5948", "\u4e03\u8a00\u7edd\u53e5", "\u5bab\u6028", "\u5973\u5b50"]','長樂宮連上苑春，玉樓金殿豔歌新。',32,'全唐诗/poet.tang.13000.json','["長樂宮連上苑春，玉樓金殿豔歌新。", "君門一入無由出，唯有宮鶯得見人。"]'),
('78640ca3-a8de-4f88-bdf6-543291b41a66','悼稚','顧況','唐','唐诗','tang','','[]','稚子比來騎竹馬，猶疑只在屋東西。',32,'全唐诗/poet.tang.13000.json','["稚子比來騎竹馬，猶疑只在屋東西。", "莫言道者無悲事，曾聽巴猿向月啼。"]'),
('0f0fa394-0bb8-419b-8dd8-1e027ec081a3','山僧蘭若','顧況','唐','唐诗','tang','','[]','絕頂茅庵老此生，寒雲孤木伴經行。',32,'全唐诗/poet.tang.13000.json','["絕頂茅庵老此生，寒雲孤木伴經行。", "世人那得知幽徑，遙向青峰禮磬聲。"]'),
('47b0116c-2801-4d4c-a723-8ca10f1c4f92','句','顧況','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','崦合桃花水，窗鳴柳谷泉。',86,'全唐诗/poet.tang.13000.json','["崦合桃花水，窗鳴柳谷泉。", "頹垣化爲陂，陸地堪乘舟。", "汀洲渺渺江籬短，疑是疑非兩斷腸。", "巫峽朝雲暮不歸，洞庭春水晴空滿。", "龍吟四澤欲興雨，鳳引九雛警宿烏。", "新婦磯邊月明，女兒浦口潮平。"]'),
('8e61bd73-2066-410f-88f8-ec41840eeee7','發南康夜泊灨石中','耿湋','唐','唐诗','tang','','["\u957f\u6c5f"]','倦客乘歸舟，春溪杳將暮。',96,'全唐诗/poet.tang.13000.json','["倦客乘歸舟，春溪杳將暮。", "羣林結暝色，孤泊有佳趣。", "夜山轉長江，赤月吐深樹。", "颯颯松上吹，泛泛花間露。", "險石俯潭渦，跳湍礙沿泝。", "豈唯垂堂戒，兼以臨深懼。", "稍出回雁峰，明登斬蛟柱。", "連雲向重山，杳未見鍾路。"]'),
('209afb70-f536-43bb-ae56-c7570238e31b','過王山人舊居','耿湋','唐','唐诗','tang','','[]','故宅春山中，來逢夕陽入。',48,'全唐诗/poet.tang.13000.json','["故宅春山中，來逢夕陽入。", "汲少井味變，開稀戶樞澀。", "樹朽鳥不栖，階閑雲自濕。", "先生何處去，惆悵空獨立。"]'),
('b8822c39-6342-4a93-beac-06eaad45d8f4','晚次昭應','耿湋','唐','唐诗','tang','','[]','落日向林路，東風吹麥隴。',48,'全唐诗/poet.tang.13000.json','["落日向林路，東風吹麥隴。", "藤草蔓古渠，牛羊下荒冢。", "驪宮戶久閉，溫谷泉長湧。", "爲問全盛時，何人最榮寵。"]'),
('d90307e8-fc70-4353-a2d4-cf008322dde7','聽早蟬歌','耿湋','唐','唐诗','tang','','[]','蟬鳴兮夕曛，聲和兮夏雲。',90,'全唐诗/poet.tang.13000.json','["蟬鳴兮夕曛，聲和兮夏雲。", "白日兮將短，秋意兮已滿。", "乍悲鳴兮欲長，猶嘶澀兮多斷。", "風蕭蕭兮轉清，韻嘒嘒兮初成。", "依婆娑之古樹，思遼落之荒城。", "閑院支頤，深林倚策。", "猶惆悵而無語，鬢星星而已白。"]'),
('2db18954-20bd-4410-b595-49d8f32b8d5e','蘆花動','耿湋','唐','唐诗','tang','','[]','連素穗，翻秋氣，細節疎莖任長吹。',28,'全唐诗/poet.tang.13000.json','["連素穗，翻秋氣，細節疎莖任長吹。", "共作月中聲，孤舟發鄉思。"]'),
('d6820c44-408f-46be-938f-dc372e44eb17','賦得寒蛩','耿湋','唐','唐诗','tang','','[]','爾誰造，鳴何早，趯趯連聲徧階草。',28,'全唐诗/poet.tang.13000.json','["爾誰造，鳴何早，趯趯連聲徧階草。", "復與夜雨和，遊人聽堪老。"]'),
('f10cccfc-93f2-45be-808c-7b327d8a5807','宣城逢張二南史','耿湋','唐','唐诗','tang','','[]','全家宛陵客，文雅世難逢。',48,'全唐诗/poet.tang.13000.json','["全家宛陵客，文雅世難逢。", "寄食年將老，干時計未從。", "秋來句曲水，雨後敬亭峯。", "西北長安遠，登臨恨幾重。"]'),
('64b9d6dd-2c1a-4cfe-a0e5-bc43e0b7f585','題童子寺','耿湋','唐','唐诗','tang','','[]','半偈留何處，全身棄此中。',48,'全唐诗/poet.tang.13000.json','["半偈留何處，全身棄此中。", "雨餘沙塔壞，月滿雪山空。", "聳剎臨回磴，朱樓間碧叢。", "朝朝日將暮，長對晉陽宮。"]'),
('9ac28964-b002-4665-a07d-3c04899ec754','夏日寄東溪隱者','耿湋','唐','唐诗','tang','','[]','日華浮野水，草色合遙空。',48,'全唐诗/poet.tang.13000.json','["日華浮野水，草色合遙空。", "處處山依舊，年年事不同。", "閑田孤壘外，暑雨片雲中。", "惆悵多塵累，無由訪釣翁。"]'),
('102f802b-bc9f-4d5b-becf-9484e98317eb','之江淮留別京親故','耿湋','唐','唐诗','tang','','[]','長雲迷一雁，漸遠向南聲。',48,'全唐诗/poet.tang.13000.json','["長雲迷一雁，漸遠向南聲。", "已帶千霜鬢，初爲萬里行。", "繁蟲滿夜草，連雨暗秋城。", "前路諸侯貴，何人重客卿。"]'),
('0d07749c-1d5d-4233-94f1-2780ee059be6','太原送許侍御出幕歸東都','耿湋','唐','唐诗','tang','','[]','昔隨劉越石，今日獨歸時。',48,'全唐诗/poet.tang.13000.json','["昔隨劉越石，今日獨歸時。", "汾水風煙冷，幷州花木遲。", "荒庭增別夢，野雨失行期。", "莫向山陽過，隣人夜笛悲。"]'),
('aff8feec-b805-46d8-ade9-9cf59570b91f','華州客舍奉和崔端公春城曉望','耿湋','唐','唐诗','tang','','[]','不語看芳徑，悲春嬾獨行。',48,'全唐诗/poet.tang.13000.json','["不語看芳徑，悲春嬾獨行。", "向人微月在，報雨早霞生。", "貧病催年齒，風塵掩姓名。", "賴逢驄馬客，郢曲緩羇情。"]'),
('8fdd485a-d24c-40b3-846c-8f4ebf79dcc4','題清蘿翁雙泉','耿湋','唐','唐诗','tang','','[]','側弁向清漪，門中夕照移。',48,'全唐诗/poet.tang.13000.json','["側弁向清漪，門中夕照移。", "異源生暗石，疊響落秋池。", "葉擁沙痕沒，流回草蔓隨。", "泠泠無限意，不獨遠公知。"]'),
('e32d79ae-1339-4a75-b9cd-fb3e2dc37d5d','酬李文','耿湋','唐','唐诗','tang','','[]','落照長楊苑，秋天渭水濱。',48,'全唐诗/poet.tang.13000.json','["落照長楊苑，秋天渭水濱。", "初飛萬木葉，又長一年人。", "貧病仍爲客，艱虞更問津。", "多慙惠然意，今日肯相親。"]'),
('f43953a9-cc58-4d6f-b3a4-4382e30c2f70','贈嚴維','耿湋','唐','唐诗','tang','','[]','許詢清論重，寂寞住山陰。',48,'全唐诗/poet.tang.13000.json','["許詢清論重，寂寞住山陰。", "野路接寒寺，閑門當古林。", "海田秋熟早，湖水夜漁深。", "世上窮通理，誰人奈此心。"]'),
('4ceed844-05e4-493f-a345-b26e9230b080','春日題苗發竹亭','耿湋','唐','唐诗','tang','','[]','春亭及策上，郎吏謝玄暉。',48,'全唐诗/poet.tang.13000.json','["春亭及策上，郎吏謝玄暉。", "閑詠疎篁近，高眠遠岫微。", "偏宜留野客，暫得解朝衣。", "猶憶東溪裏，雷雲掩故扉。"]'),
('a9dcb041-8bd0-4676-9c21-e8668bd4d033','題孝子陵','耿湋','唐','唐诗','tang','','[]','荒墳秋陌上，霜露正霏霏。',48,'全唐诗/poet.tang.13000.json','["荒墳秋陌上，霜露正霏霏。", "松柏自成拱，苫廬長不歸。", "浮埃積蓬鬢，流血在麻衣。", "何必曾參傳，千年至行稀。"]'),
('b4e7cec1-f391-4b59-a09e-7815b6675fff','題莊上人房','耿湋','唐','唐诗','tang','','[]','不語焚香坐，心知道已成。',48,'全唐诗/poet.tang.13000.json','["不語焚香坐，心知道已成。", "流年衰此世，定力見他生。", "暮雪餘春冷，寒燈續晝明。", "尋常五侯至，敢望下階迎。"]'),
('45047fc8-5ad9-4690-ba4b-7569476147b1','宋中','耿湋','唐','唐诗','tang','','[]','日暮黃雲合，年深白骨稀。',48,'全唐诗/poet.tang.13000.json','["日暮黃雲合，年深白骨稀。", "舊村喬木在，秋草遠人歸。", "廢井莓苔厚，荒田路徑微。", "唯餘近山色，相對似依依。"]'),
('8cdf127d-5b6d-4007-abf8-06b9c7519951','秋夜思歸','耿湋','唐','唐诗','tang','','[]','來時猶暑服，今已露漫漫。',48,'全唐诗/poet.tang.13000.json','["來時猶暑服，今已露漫漫。", "多雨逢初霽，深秋生夜寒。", "投人心似切，爲客事皆難。", "何處無留滯，誰能暫問看。"]'),
('11e7bd38-4c1f-44bc-a488-c1fd8ac4b9fa','送李端','耿湋','唐','唐诗','tang','','[]','世上許劉楨，洋洋風雅聲。',48,'全唐诗/poet.tang.13000.json','["世上許劉楨，洋洋風雅聲。", "客來空改歲，歸去未成名。", "遠近天初暮，關河雪半晴。", "空懷諫書在，回首戀承明。"]'),
('30927692-01e2-485b-9429-752ad939be03','送崔明府赴青城','耿湋','唐','唐诗','tang','','[]','清冬賓御出，蜀道翠微間。',48,'全唐诗/poet.tang.13000.json','["清冬賓御出，蜀道翠微間。", "遠霧開羣壑，初陽照近關。", "霜潭浮紫菜，雪棧繞青山。", "當似遺民去，柴桑政自閑。"]'),
('2c48ce10-3a5a-429d-9bda-9f9969467ce5','送王將軍出塞','耿湋','唐','唐诗','tang','','[]','漢家邊事重，竇憲出臨戎。',48,'全唐诗/poet.tang.13000.json','["漢家邊事重，竇憲出臨戎。", "絕漠秋山在，陽關舊路通。", "列營依茂草，吹角向高風。", "更就燕然石，行看奏虜功。"]'),
('37654f5b-fbaf-4436-96e5-3c35fd80c9ba','雨中留別','耿湋','唐','唐诗','tang','','[]','東西無定客，風雨未休時。',48,'全唐诗/poet.tang.13000.json','["東西無定客，風雨未休時。", "憫默此中別，飄零何處期。", "青山違舊隱，白髮入新詩。", "歲歲迷津路，生涯漸可悲。"]'),
('b244fa50-b7bf-4901-b030-464f18c1c455','送楊將軍','耿湋','唐','唐诗','tang','','[]','一身良將後，萬里討烏孫。',48,'全唐诗/poet.tang.13000.json','["一身良將後，萬里討烏孫。", "落日邊陲靜，秋風鼓角喧。", "遠山當磧路，茂草向營門。", "生死酬恩寵，功名豈敢論。"]'),
('ecbd9ad4-caee-4838-bbdf-0dee571d4a62','送夏侯審遊蜀','耿湋','唐','唐诗','tang','','[]','暮峰和玉壘，回望不通秦。',48,'全唐诗/poet.tang.13000.json','["暮峰和玉壘，回望不通秦。", "更問蜀城路，但逢巴語人。", "石林鶯囀曉，板屋月明春。", "若訪嚴夫子，無嫌卜肆貧。"]'),
('20f79063-78b0-4a87-a9cd-c196a9496474','送張侍御赴郴州別駕','耿湋','唐','唐诗','tang','','[]','佐郡人難料，分襟日復斜。',48,'全唐诗/poet.tang.13000.json','["佐郡人難料，分襟日復斜。", "一帆隨遠水，百口過長沙。", "明月江邊夜，平陵夢裏家。", "王孫對芳草，愁思杳無涯。"]'),
('c8d60923-6a4b-4d83-a8a4-357971ac8a9e','送苗贇赴陽翟丞','耿湋','唐','唐诗','tang','','[]','夕陽秋草上，去馬弟兄看。',48,'全唐诗/poet.tang.13000.json','["夕陽秋草上，去馬弟兄看。", "年少初辭闕，時危遠效官。", "山行獨夜雨，旅宿二陵寒。", "詩興生何處，嵩陽羽客壇。"]'),
('5f27426c-86f1-41bf-ab9f-91830376df53','送絳州郭參軍','耿湋','唐','唐诗','tang','','[]','遠事諸侯出，青山古晉城。',48,'全唐诗/poet.tang.13000.json','["遠事諸侯出，青山古晉城。", "連行麴水閣，獨入議中兵。", "夜雨新田濕，春風曙角鳴。", "人傳府公政，記室有參卿。"]'),
('612964e5-7287-489d-b2c2-5a5d40f3a7c4','常州留別','耿湋','唐','唐诗','tang','','[]','萬里南天外，求書禹穴間。',48,'全唐诗/poet.tang.13000.json','["萬里南天外，求書禹穴間。", "往來成白首，旦暮見青山。", "夜浦涼雲過，秋塘好月閑。", "殷勤陽羨桂，別此幾時攀。"]'),
('44bc39df-233c-4668-87af-6ad92c897c17','關山月','耿湋','唐','唐诗','tang','','[]','月明邊徼靜，戍客望鄉時。',48,'全唐诗/poet.tang.13000.json','["月明邊徼靜，戍客望鄉時。", "塞古柳衰盡，關寒榆發遲。", "蒼蒼萬里道，戚戚十年北。", "今夜青樓上，還應照所思。"]'),
('142a8072-b662-48d1-90b3-a11f6609c0db','代宋州將淮上乞師','耿湋','唐','唐诗','tang','','[]','脣齒幸相依，危亡故遠歸。',48,'全唐诗/poet.tang.13000.json','["脣齒幸相依，危亡故遠歸。", "身輕百戰出，家在數重圍。", "上將堅深壘，殘兵鬬落暉。", "常聞鐵劒利，早晚借餘威。"]'),
('2f675f38-47ce-4119-b846-d11723e25e95','秋晚臥疾寄司空拾遺曙盧少府綸','耿湋','唐','唐诗','tang','','[]','寒几坐空堂，疎髯似積霜。',48,'全唐诗/poet.tang.13000.json','["寒几坐空堂，疎髯似積霜。", "老醫迷舊疾，朽藥誤新方。", "晚果紅低樹，秋苔綠徧牆。", "慙非蔣生徑，不敢望求羊。"]'),
('7834bc02-d434-470f-8874-1f45a60707bc','贈海明上人','耿湋','唐','唐诗','tang','','[]','來自西天竺，持經奉紫微。',48,'全唐诗/poet.tang.13000.json','["來自西天竺，持經奉紫微。", "年深梵語變，行苦俗流歸。", "月上安禪久，苔生出院稀。", "梁間有馴鴿，不去復何依。"]'),
('2bdb947b-0c38-4be1-9b49-8c16e7ac46b8','津亭有懷','耿湋','唐','唐诗','tang','','[]','津亭一望鄉，淮海晚茫茫。',48,'全唐诗/poet.tang.13000.json','["津亭一望鄉，淮海晚茫茫。", "草沒棲洲鷺，天連暎浦檣。", "徃來通楚越，旦暮易漁商。", "惆悵緘書畢，何人向洛陽。"]'),
('67cea0fa-4c7b-456a-ae5d-574d1dc8a878','晚投江澤浦即事呈柳兵曹泥','耿湋','唐','唐诗','tang','','[]','落日過重霞，輕烟上遠沙。',48,'全唐诗/poet.tang.13000.json','["落日過重霞，輕烟上遠沙。", "移舟衝荇蔓，轉浦入蘆花。", "斷岸迂來客，連波漾去槎。", "故鄉何處在，更道向天涯。"]'),
('2936dc0e-efe5-40c0-a2f3-1ecd8d4653c0','東郊別業','耿湋','唐','唐诗','tang','','[]','東臯占薄田，耕種過餘年。',48,'全唐诗/poet.tang.13000.json','["東臯占薄田，耕種過餘年。", "護藥栽山刺，澆蔬引竹泉。", "晚雷期稔歲，重霧報晴天。", "若問幽人意，思齊沮溺賢。"]'),
('784480cb-7b1f-456d-bcd9-94ddad87a1b2','早朝','耿湋','唐','唐诗','tang','','[]','鐘鼓餘聲裏，千官向紫微。',48,'全唐诗/poet.tang.13000.json','["鐘鼓餘聲裏，千官向紫微。", "冒寒人語少，乘月燭來稀。", "清漏聞馳道，輕霞暎瑣闈。", "猶看嘶馬處，未啟掖垣扉。"]'),
('e954b172-6d23-4fac-afc4-98da31e1ca14','屏居盩厔','耿湋','唐','唐诗','tang','','[]','百年心不料，一卷日相知。',48,'全唐诗/poet.tang.13000.json','["百年心不料，一卷日相知。", "乘興偏難改，憂家是強爲。", "縣城寒寂寞，峰樹遠參差。", "自笑無謀者，秪應道在斯。"]'),
('edc07822-6fcc-44f0-836f-956c0ad2d4e8','進秋隼','耿湋','唐','唐诗','tang','','[]','豈悟因羅者，迎霜獻紫微。',48,'全唐诗/poet.tang.13000.json','["豈悟因羅者，迎霜獻紫微。", "夕陽分素臆，秋色上花衣。", "舉翅雲天近，回眸燕雀稀。", "應隨明主意，百中有光輝。"]'),
('22793c70-a745-46af-836a-fbb2a4318638','詠宣州筆','耿湋','唐','唐诗','tang','','[]','寒竹慙虛受，纖毫任幾重。',48,'全唐诗/poet.tang.13000.json','["寒竹慙虛受，纖毫任幾重。", "影端緣守直，心勁懶藏鋒。", "落紙驚風起，搖空見露濃。", "丹青與文事，捨此復何從。"]'),
('b20294e5-9995-40a2-bd83-242ccd62a87d','春日洪州即事','耿湋','唐','唐诗','tang','','[]','鍾陵春日好，春水滿南塘。',48,'全唐诗/poet.tang.13000.json','["鍾陵春日好，春水滿南塘。", "竹宇分朱閣，桐花間綠楊。", "蹉跎看鬢色，留滯惜年芳。", "欲問羇愁發，秦關道路長。"]'),
('2e743a29-04ae-416e-a014-6da19281a515','雪後宿王純池州草堂','耿湋','唐','唐诗','tang','','[]','宿君湖上宅，琴韻靜參差。',48,'全唐诗/poet.tang.13000.json','["宿君湖上宅，琴韻靜參差。", "夜雪入秋浦，孤城連貴池。", "流年看共老，銜酒發中悲。", "良會應難再，晨雞自有期。"]'),
('e05b6908-5d87-4a15-b58b-54fd0c59c00e','旅次漢故畤','耿湋','唐','唐诗','tang','','[]','我行過漢畤，寥落見孤城。',48,'全唐诗/poet.tang.13000.json','["我行過漢畤，寥落見孤城。", "邑里經多難，兒童識五兵。", "廣川桑遍綠，叢薄雉連鳴。", "惆悵蕭關道，終軍願請纓。"]'),
('3fe55c4a-6e98-4270-812d-df1aa1ae48a6','過三郊驛却寄楊評事時此子郭令公欲有表薦','耿湋','唐','唐诗','tang','','[]','冉冉青衫客，悠悠白髮人。',48,'全唐诗/poet.tang.13000.json','["冉冉青衫客，悠悠白髮人。", "亂山孤驛暮，長路百花新。", "終歲行他縣，全家望此身。", "更思君去就，早晚問平津。"]'),
('2c0f2bae-efe8-4bfc-a965-da116da2532e','隴西行','耿湋','唐','唐诗','tang','','[]','雪下陽關路，人稀隴戍頭。',48,'全唐诗/poet.tang.13000.json','["雪下陽關路，人稀隴戍頭。", "封狐猶未翦，邊將豈無羞。", "白草三冬色，黃雲萬里愁。", "因思李都尉，畢竟不封侯。"]'),
('ed801ef7-4f6e-4595-9b6d-b8a67a286472','巴陵逢洛陽鄰舍','耿湋','唐','唐诗','tang','','[]','因君知北事，流浪已忘機。',48,'全唐诗/poet.tang.13000.json','["因君知北事，流浪已忘機。", "客久多人識，年高衆病歸。", "連雲湖色遠，度雪雁聲稀。", "又說家林盡，悽傷淚滿衣。"]'),
('79c71c0a-9c78-4539-a075-4232fd83fc52','哭張融','耿湋','唐','唐诗','tang','','[]','早歲能文客，中年與世違。',48,'全唐诗/poet.tang.13000.json','["早歲能文客，中年與世違。", "有家孀婦少，無子弔人稀。", "繐帳塵空暗，銘旌雨不飛。", "依然舊鄉路，寂寞幾回歸。"]'),
('46f24b27-421f-4b6a-97a2-46af94aa53f5','送友貶嶺南','耿湋','唐','唐诗','tang','','[]','暮年從遠謫，落日別交親。',48,'全唐诗/poet.tang.13000.json','["暮年從遠謫，落日別交親。", "湖上北飛雁，天涯南去人。", "夢成湘浦夜，淚盡桂陽春。", "歲月茫茫意，何時雨露新。"]'),
('89799bab-6157-4af8-a292-46807a9ed427','春日即事二首 一','耿湋','唐','唐诗','tang','','[]','詩書成志業，嬾慢致蹉跎。',48,'全唐诗/poet.tang.13000.json','["詩書成志業，嬾慢致蹉跎。", "聖代丹霄遠，明時白髮多。", "淺謀堪自笑，窮巷憶誰過。", "寂寞前山暮，歸人樵採歌。"]'),
('0ac39c6f-d1cf-4035-bed4-261b94e653d2','春日即事二首 二','耿湋','唐','唐诗','tang','','[]','數畝東臯宅，青春獨屏居。',48,'全唐诗/poet.tang.13000.json','["數畝東臯宅，青春獨屏居。", "家貧僮僕慢，官罷友朋疎。", "強飲沽來酒，羞看讀了書。", "閑花開滿地，惆悵復何如。"]'),
('e19062de-ff75-4ab3-b6cc-453f45c32102','贈田家翁','耿湋','唐','唐诗','tang','','[]','老人迎客處，籬落稻畦間。',48,'全唐诗/poet.tang.13000.json','["老人迎客處，籬落稻畦間。", "蠶屋朝寒閉，田家晝雨閑。", "門閭新薙草，蹊徑舊諳山。", "自道誰相及，邀予試徃還。"]'),
('d8b7bb4f-ee25-40ad-b76c-40ec2539f6e4','贈韋山人','耿湋','唐','唐诗','tang','','[]','失意成逋客，終年獨掩扉。',48,'全唐诗/poet.tang.13000.json','["失意成逋客，終年獨掩扉。", "無機狎鷗慣，多病見人稀。", "流水知行藥，孤雲伴採薇。", "空齋莫閑笑，心事與時違。"]'),
('23233a8a-a13d-4319-86e7-b16d3dc0727c','濬公院懷舊','耿湋','唐','唐诗','tang','','[]','遠公傳敎畢，身沒向他方。',48,'全唐诗/poet.tang.13000.json','["遠公傳敎畢，身沒向他方。", "弔客來何見，門人閉影堂。", "紗燈臨古砌，塵札在空牀。", "寂寞疎鐘後，秋天有夕陽。"]'),
('be118ff0-566d-466d-ac07-0de6e6493419','雨中宿義興寺','耿湋','唐','唐诗','tang','','[]','遙夜宿東林，蟲聲階草深。',48,'全唐诗/poet.tang.13000.json','["遙夜宿東林，蟲聲階草深。", "高風初落葉，多雨未歸心。", "家國身猶負，星霜鬢已侵。", "滄洲縱不去，何處有知音。"]'),
('5025e96d-6151-4537-96ac-4535c1a2880f','送王祕書歸江東','耿湋','唐','唐诗','tang','','[]','迴首望知音，逶迤桑柘林。',48,'全唐诗/poet.tang.13000.json','["迴首望知音，逶迤桑柘林。", "人歸海郡遠，路入雨天深。", "萬木經秋葉，孤舟向暮心。", "唯餘江畔草，應見白頭吟。"]'),
('dc94daf6-9218-4db3-aae6-00c170182d44','渭上送李蔵器移家東都','耿湋','唐','唐诗','tang','','[]','求名雖有據，學稼又無田。',48,'全唐诗/poet.tang.13000.json','["求名雖有據，學稼又無田。", "故國三千里，新春五十年。", "移家還作客，避地莫知賢。", "洛浦今何處，風帆去渺然。"]'),
('c91e2fce-3d9c-42fa-9692-39d502521789','春尋柳先生','耿湋','唐','唐诗','tang','','[]','言是商山老，塵心莫問年。',48,'全唐诗/poet.tang.13000.json','["言是商山老，塵心莫問年。", "白髯垂策短，烏帽據梧偏。", "酒熟飛巴雨，丹成見海田。", "疎雲披遠水，景動石牀前。"]'),
('473617e8-f2d2-4f2a-a26d-df696f3c9890','題藏公院','耿湋','唐','唐诗','tang','','[]','古院林公住，疎篁近井桃。',48,'全唐诗/poet.tang.13000.json','["古院林公住，疎篁近井桃。", "俗年人見少，禪地自知高。", "藥草誠多喻，滄溟在一毫。", "仍悲次宗輩，塵事日爲勞。"]'),
('5ae4faa3-42b2-4a4f-8d19-c99aa13cb3af','夏夜西亭即事寄錢員外','耿湋','唐','唐诗','tang','','[]','高亭賓客散，暑夜醉相和。',48,'全唐诗/poet.tang.13000.json','["高亭賓客散，暑夜醉相和。", "細汗迎衣集，微涼待扇過。", "風還池色定，月晚樹陰多。", "遙想隨行者，珊珊動曉珂。"]'),
('8a6200cd-e631-44bb-8e03-3c16e29c675d','與清江上人及諸公宿李八昆季宅','耿湋','唐','唐诗','tang','','[]','湯公多外友，洛社自相依。',48,'全唐诗/poet.tang.13000.json','["湯公多外友，洛社自相依。", "遠客還登會，秋懷欲忘歸。", "驚風林果少，驟雨砌蟲稀。", "更過三張價，東遊愧陸機。"]'),
('af55f487-b2a8-4e2c-a3ab-406cd7a450fb','春日即事','耿湋','唐','唐诗','tang','','[]','鄰里朝光徧，披衣夜醉醒。',48,'全唐诗/poet.tang.13000.json','["鄰里朝光徧，披衣夜醉醒。", "庖廚非舊火，林木發新青。", "接果移天性，疎泉逐地形。", "清明來幾日，戴勝已堪聽。"]'),
('6b465cf8-9dac-4e2f-b97c-f294c49bd64e','秋夜會宿李永宅憶江南舊遊','耿湋','唐','唐诗','tang','','[]','偶宿俱南客，相看喜盡歸。',48,'全唐诗/poet.tang.13000.json','["偶宿俱南客，相看喜盡歸。", "湖山話不極，歲月念空違。", "子夜高梧冷，秋陰遠漏微。", "那無此良會，惜在謝家稀。"]'),
('c5710ddc-eaa3-4e16-9851-208d23381af0','冬夜尋李永因書事贈之','耿湋','唐','唐诗','tang','','[]','棲遑偏降志，疵賤倍修身。',48,'全唐诗/poet.tang.13000.json','["棲遑偏降志，疵賤倍修身。", "近覺多衰鬢，深知獨故人。", "天垂五夜月，霜覆九衢塵。", "不待逢沮溺，而今惡問津。"]'),
('5aac5703-ad15-4da8-84fb-ff0e68557569','立春日宴高陵任明府宅','耿湋','唐','唐诗','tang','','[]','春灰今變候，密雪又霏霏。',48,'全唐诗/poet.tang.13000.json','["春灰今變候，密雪又霏霏。", "坐客同心滿，流年此會稀。", "風成空處亂，素積夜來飛。", "且共銜盃酒，陶潛不得歸。"]'),
('78a2d26a-25e8-40ae-bb5d-796daf603296','春日遊慈恩寺寄暢當','耿湋','唐','唐诗','tang','','[]','浮世今何事，空門此諦真。',48,'全唐诗/poet.tang.13000.json','["浮世今何事，空門此諦真。", "死生俱是夢，哀樂詎關身。", "遠草光連水，春篁色離塵。", "當從庚中庶，詩客更何人。"]'),
('67af46ed-1859-45b9-b93b-294175a5ed33','晚秋過蘇少府','耿湋','唐','唐诗','tang','','[]','九江迷去住，羣吏且因依。',48,'全唐诗/poet.tang.13000.json','["九江迷去住，羣吏且因依。", "高木秋垂露，寒城暮掩扉。", "隨雲心自遠，看草伴應稀。", "肯信同年友，相望青瑣闈。"]'),
('133c8880-40d0-4ac2-94ab-4152c840112b','登鸛雀樓','耿湋','唐','唐诗','tang','','["\u534e\u5c71", "\u9ec4\u6cb3"]','久客心常醉，高樓日漸低。',48,'全唐诗/poet.tang.13000.json','["久客心常醉，高樓日漸低。", "黃河經海內，華嶽鎮關西。", "去遠千帆小，來遲獨鳥迷。", "終年不得意，空覺負東溪。"]'),
('fd8d3630-c13b-4436-8027-2458dfd49e85','賦得沙上雁','耿湋','唐','唐诗','tang','','[]','衡陽多道里，弱羽復哀音。',48,'全唐诗/poet.tang.13000.json','["衡陽多道里，弱羽復哀音。", "還塞知何日，驚弦亂此心。", "夜陰前侶遠，秋冷後湖深。", "獨立汀洲意，寧知霜霰侵。"]'),
('d55e8b51-c2db-4614-b294-13b24db753b9','夜尋盧處士','耿湋','唐','唐诗','tang','','[]','月高雞犬靜，門掩向寒塘。',48,'全唐诗/poet.tang.13000.json','["月高雞犬靜，門掩向寒塘。", "夜竹深茅宇，秋庭冷石牀。", "住山年已遠，服藥壽偏長。", "虛棄如吾者，逢君益自傷。"]'),
('40698af6-d701-4be1-b0c5-d2acfece61b8','邠州留別','耿湋','唐','唐诗','tang','','[]','終歲山川路，生涯總幾何。',48,'全唐诗/poet.tang.13000.json','["終歲山川路，生涯總幾何。", "艱難爲客慣，貧賤受恩多。", "暮角寒山色，秋風遠水波。", "無人見惆悵，垂鞚入煙蘿。"]'),
('13893404-3ea9-493b-af94-5ae0d21e557a','贈張將軍','耿湋','唐','唐诗','tang','','[]','寥落軍城暮，重門返照間。',48,'全唐诗/poet.tang.13000.json','["寥落軍城暮，重門返照間。", "鼓鼙經雨暗，士馬過秋閑。", "慣守臨邊郡，曾營近海山。", "關西舊業在，夜夜夢中還。"]'),
('761cde00-c315-40a8-81b0-8c4938ba1dc1','贈隱公','耿湋','唐','唐诗','tang','','[]','世間無近遠，定裏徧曾過。',48,'全唐诗/poet.tang.13000.json','["世間無近遠，定裏徧曾過。", "東海經長在，南朝寺最多。", "暮年聊化俗，初地即摧魔。", "今日忘塵慮，看心義若何。"]'),
('1cf347e4-c81e-4e5a-b5ae-033f271efc98','贈別安邑韓少府','耿湋','唐','唐诗','tang','','[]','子真能自在，江海意何如。',48,'全唐诗/poet.tang.13000.json','["子真能自在，江海意何如。", "門掩疎塵吏，心閑閱道書。", "古城寒欲雪，遠客暮無車。", "杳杳思前路，誰堪千里餘。"]'),
('0ae9d2fd-157e-4c85-9816-e8ff6cf6c112','送胡校書秩滿歸河中','耿湋','唐','唐诗','tang','','[]','古樹汾陰道，悠悠東去長。',48,'全唐诗/poet.tang.13000.json','["古樹汾陰道，悠悠東去長。", "位卑仍解印，身老又還鄉。", "河水平秋岸，關門向夕陽。", "音書須數附，莫學晉嵇康。"]'),
('9a67496c-9ed1-4be4-b7f3-2d2aca1afed5','送河中張胄曹往太原計會迴','耿湋','唐','唐诗','tang','','[]','北風長至遠，四牡向幽幷。',48,'全唐诗/poet.tang.13000.json','["北風長至遠，四牡向幽幷。", "衰木新田路，寒蕪故絳城。", "遙聽邊上信，遠計朔南程。", "料變當臨事，遙知外國情。"]'),
('0563bfad-8105-464d-93e5-e219665ee641','送郭正字歸郢上','耿湋','唐','唐诗','tang','','[]','濟江篇已出，書府俸猶貧。',48,'全唐诗/poet.tang.13000.json','["濟江篇已出，書府俸猶貧。", "積雪商山道，全家楚塞人。", "大堤逢落日，廣漢望通津。", "却別漁潭下，驚鷗那可親。"]'),
('c52011da-df42-4f09-a561-8ecff7f4068b','題李孝廉書房','耿湋','唐','唐诗','tang','','[]','野情專易外，一室向青山。',48,'全唐诗/poet.tang.13000.json','["野情專易外，一室向青山。", "業就三編絕，心通萬事閑。", "鶯稀春木上，草徧暮堦間。", "莫道歸繻在，來時棄故關。"]'),
('65e622da-1691-44d0-a29f-6cba13842ce1','酬暢當','耿湋','唐','唐诗','tang','','[]','同遊漆沮後，已是十年餘。',48,'全唐诗/poet.tang.13000.json','["同遊漆沮後，已是十年餘。", "幾度曾相夢，何時定得書。", "月高城影盡，霜重柳條疎。", "且對尊中酒，千般想未如。"]'),
('6bb47ff3-5956-4f1e-bd84-523447c91425','留別解縣韓明府','耿湋','唐','唐诗','tang','','[]','閑人州縣厭，賤士友朋譏。',48,'全唐诗/poet.tang.13000.json','["閑人州縣厭，賤士友朋譏。", "朔雪逢初下，秦關獨暮歸。", "寒茅下原淺，殘雪過風微。", "一路何相慰，唯君能政稀。"]'),
('32f67506-3cbd-4655-9a40-fc8ce7222f9e','遊鍾山紫芝觀','耿湋','唐','唐诗','tang','','[]','繫舟仙宅下，清磬落春風。',48,'全唐诗/poet.tang.13000.json','["繫舟仙宅下，清磬落春風。", "雨數芝田長，雲開石路重。", "古房清磴接，深殿紫烟濃。", "鶴駕何時去，遊人自不逢。"]'),
('8544c4dd-7019-4a69-9bc6-7676c21863cb','晚秋宿裴員外寺院','耿湋','唐','唐诗','tang','','[]','仲言多麗藻，晚水獨芙蓉。',48,'全唐诗/poet.tang.13000.json','["仲言多麗藻，晚水獨芙蓉。", "梁苑仍秋過，仁祠又夜逢。", "回林通暗竹，去雨帶寒鐘。", "願向空門裏，修持比晝龍。"]'),
('4ee196c3-b71a-4743-9033-fcc203f71005','秋夜喜盧司直嚴少府訪宿','耿湋','唐','唐诗','tang','','[]','寂寂閉層城，悠悠此夜情。',48,'全唐诗/poet.tang.13000.json','["寂寂閉層城，悠悠此夜情。", "早涼過鬢髮，秋思入柴荆。", "嚴子多高趣，盧公有盛名。", "還如杜陵下，暫拂蔣元卿。"]'),
('c5ccdc1f-1902-488b-b7de-d773ec7bb56c','下邽客舍喜叔孫主簿鄭少府見過','耿湋','唐','唐诗','tang','','[]','良宵復杪秋，把酒說羇遊。',48,'全唐诗/poet.tang.13000.json','["良宵復杪秋，把酒說羇遊。", "落木東西別，寒萍遠近流。", "蕭條旅館月，寂歷曙更籌。", "不是仇梅至，何人問百憂。"]'),
('96d8b98d-6b4a-4eb0-b915-988296f67cd3','盩厔客舍','耿湋','唐','唐诗','tang','','[]','寥寂荒壘下，客舍雨微微。',48,'全唐诗/poet.tang.13000.json','["寥寂荒壘下，客舍雨微微。", "門見苔生滿，心慙吏到稀。", "籬花看未發，海燕欲先歸。", "無限堪惆悵，誰家復搗衣。"]'),
('94209809-403f-4bb0-9fef-04b603bed685','宿韋員外宅','耿湋','唐','唐诗','tang','','[]','傳經韋相後，賜筆漢家郎。',48,'全唐诗/poet.tang.13000.json','["傳經韋相後，賜筆漢家郎。", "幽閣諸生會，寒宵幾刻長。", "座中燈泛酒，簷外月如霜。", "人事多飄忽，邀歡詎可忘。"]'),
('e9b8408c-490a-4ea1-a458-f3249bb7ddaf','登沃州山','耿湋','唐','唐诗','tang','','[]','沃州初望海，攜手盡時髦。',48,'全唐诗/poet.tang.13000.json','["沃州初望海，攜手盡時髦。", "小暑開鵬翼，新蓂長鷺濤。", "月如芳草遠，身比夕陽高。", "羊祜傷風景，誰云異我曹。"]'),
('79ebb031-490c-44b2-b892-b779ace88f3a','宿岐山姜明府廳','耿湋','唐','唐诗','tang','','[]','暝色休羣動，秋齋遠客情。',48,'全唐诗/poet.tang.13000.json','["暝色休羣動，秋齋遠客情。", "細風和雨氣，寒竹度簾聲。", "日覺蹉跎近，天敎嬾慢成。", "誰能謁卿相，朝夕筭浮榮。"]'),
('65d4f851-0627-49b5-b0b7-fdb4aefc4429','上巳日','耿湋','唐','唐诗','tang','','[]','共來修禊事，內顧一悲翁。',48,'全唐诗/poet.tang.13000.json','["共來修禊事，內顧一悲翁。", "玉鬢風塵下，花林絲管中。", "故山離水石，舊侶失鵷鴻。", "不及遊魚樂，裴回蓮葉東。"]'),
('c91a3ba5-cd49-4fa0-876c-19f4435c2071','登樂遊原','耿湋','唐','唐诗','tang','','[]','園廟何年廢，登臨有故丘。',48,'全唐诗/poet.tang.14000.json','["園廟何年廢，登臨有故丘。", "孤村連日靜，多雨及霖休。", "常與秦山對，曾經漢主遊。", "豈知千載後，萬事水東流。"]'),
('b47a1058-7706-4f5b-b110-c5078de3abd6','題惟幹上人房','耿湋','唐','唐诗','tang','','[]','繩牀茅屋下，獨坐味閑安。',48,'全唐诗/poet.tang.14000.json','["繩牀茅屋下，獨坐味閑安。", "苦行無童子，忘機避宰官。", "是非齊已久，夏臘比應難。", "更悟真如性，塵心稍自寬。"]'),
('50c82c67-0a34-4739-9fa6-6044377e75f4','會鳳翔張少尹南亭','耿湋','唐','唐诗','tang','','[]','遠過張正見，詩興自依依。',48,'全唐诗/poet.tang.14000.json','["遠過張正見，詩興自依依。", "西府軍城暮，南庭吏事稀。", "草簷宜日過，花圃任煙歸。", "更料重關外，羣僚候啟扉。"]'),
('c0fbc143-5b37-4eb0-a44d-543527754497','早春宴高陵滑少府','耿湋','唐','唐诗','tang','','[]','且寬沈簿領，應賴酒如澠。',48,'全唐诗/poet.tang.14000.json','["且寬沈簿領，應賴酒如澠。", "春夜霜猶下，東城月未昇。", "清言饒醉客，亂舞避寒燈。", "名字書仙籍，諸生病未能。"]'),
('a86232f7-8794-4b8e-8e40-e84b329e6720','寒蜂採菊蕊','耿湋','唐','唐诗','tang','','[]','遊颺下晴空，尋芳到菊叢。',48,'全唐诗/poet.tang.14000.json','["遊颺下晴空，尋芳到菊叢。", "帶聲來蕊上，連影在香中。", "去住霑餘霧，高低順過風。", "終慙異蝴蝶，不與夢魂通。"]'),
('4fdeec56-ef6e-4d64-895c-1ab3ea90125d','題楊著別業','耿湋','唐','唐诗','tang','','[]','柳巷向陂斜，回陽噪亂鵶。',48,'全唐诗/poet.tang.14000.json','["柳巷向陂斜，回陽噪亂鵶。", "農桑子雲業，書籍蔡邕家。", "暮葉初飜砌，寒池轉露沙。", "如何守儒行，寂寞過年華。"]'),
('fa2d3278-87d8-4be7-a9be-eaa04c23cd6a','送太僕寺李丞赴都到桃林塞','耿湋','唐','唐诗','tang','','[]','遠過桃林塞，休年自昔聞。',48,'全唐诗/poet.tang.14000.json','["遠過桃林塞，休年自昔聞。", "曲河隨暮草，重阜接閑雲。", "造父爲周御，詹嘉守晉軍。", "應多懷古思，落葉又紛紛。"]'),
('75c91d74-8d48-4fa9-b02e-9d057b44648a','宋中','耿湋','唐','唐诗','tang','','[]','百戰無軍食，孤城陷虜塵。',48,'全唐诗/poet.tang.14000.json','["百戰無軍食，孤城陷虜塵。", "爲傷多易子，翻弔淺爲臣。", "漫漫東流水，悠悠南陌人。", "空思前事往，向曉淚霑巾。"]'),
('5bdf85f9-6a19-4dc1-8469-72f0e1dedfe8','陪讌湖州公堂','耿湋','唐','唐诗','tang','','[]','謝公爲楚郡，坐客是瑤林。',48,'全唐诗/poet.tang.14000.json','["謝公爲楚郡，坐客是瑤林。", "文府重門奧，儒源積浪深。", "壺觴邀薄醉，笙磬發高音。", "末至才仍短，難隨白雪吟。"]'),
('dde38318-f7ee-49c7-a1c2-37a1ff7347e6','尋覺公因寄李二端司空十四曙','耿湋','唐','唐诗','tang','','[]','少年嘗昧道，無事日悠悠。',48,'全唐诗/poet.tang.14000.json','["少年嘗昧道，無事日悠悠。", "及至悟生死，尋僧已白頭。", "雲迴廬瀑雨，樹落給園秋。", "爲我謝宗許，塵中難久留。"]'),
('faad20a7-b49d-4cf1-8116-f5339b064b9a','送郭秀才赴舉','耿湋','唐','唐诗','tang','','[]','鄉賦鹿鳴篇，君爲貢士先。',48,'全唐诗/poet.tang.14000.json','["鄉賦鹿鳴篇，君爲貢士先。", "新經夢筆夜，纔比棄繻年。", "海雨沾隋柳，江潮赴楚船。", "相看南去雁，離恨倍潸然。"]'),
('ddf19855-c331-44a3-86b6-56b055e16037','送王閏','耿湋','唐','唐诗','tang','','[]','相送臨漢水，愴然望故關。',48,'全唐诗/poet.tang.14000.json','["相送臨漢水，愴然望故關。", "江蕪連夢澤，楚雪入商山。", "語我他年舊，看君此日還。", "因將自悲淚，一灑別離間。"]'),
('0f06a818-7cdf-4668-98f6-3f5595bdd369','送蜀客還','耿湋','唐','唐诗','tang','','[]','萬峯深積翠，路向此中難。',48,'全唐诗/poet.tang.14000.json','["萬峯深積翠，路向此中難。", "欲暮多羇思，因高莫遠看。", "卓家人寂寞，揚子業荒殘。", "唯見岷山水，悠悠帶月寒。"]'),
('df7de18c-8fcb-4984-942c-5c5f224af739','送海州盧錄事','耿湋','唐','唐诗','tang','','[]','之官逢計吏，風土問如何。',48,'全唐诗/poet.tang.14000.json','["之官逢計吏，風土問如何。", "海口朝陽近，青州春氣多。", "郊原鵬影到，樓閣蜃雲和。", "損益關從事，期聽勞者歌。"]'),
('e5042dcf-6cfb-4d33-9bd9-cd0784402a7e','登鍾山館','耿湋','唐','唐诗','tang','','[]','匹馬宜春路，蕭條背館心。',48,'全唐诗/poet.tang.14000.json','["匹馬宜春路，蕭條背館心。", "澗花寒夕雨，潭水黑朝林。", "野市魚鹽隘，江村竹葦深。", "子規何處發，青樹滿高岑。"]'),
('241f5a8b-91ab-4146-bf80-f0248dfbf3f5','秋日','耿湋','唐','唐诗','tang','','[]','照耀天山外，飛鵶幾共過。',48,'全唐诗/poet.tang.14000.json','["照耀天山外，飛鵶幾共過。", "微紅拂秋漢，片白透長波。", "影促寒汀薄，光殘古木多。", "金霞與雲氣，散漫復相和。"]'),
('f0cf3753-27a8-45f4-8797-7e1cc8dbef2b','贈苗員外','耿湋','唐','唐诗','tang','','[]','爲郎日賦詩，小謝少年時。',48,'全唐诗/poet.tang.14000.json','["爲郎日賦詩，小謝少年時。", "業繼儒門後，心多道者期。", "晚迴長樂殿，新出夜明祠。", "行樂西園暮，春風動柳絲。"]'),
('24a70c7d-e01e-46b4-9764-647153bf10d0','詣順公問道','耿湋','唐','唐诗','tang','','[]','此身知是妄，遠遠詣支公。',48,'全唐诗/poet.tang.14000.json','["此身知是妄，遠遠詣支公。", "何法住持後，能逃生死中。", "秋苔經古徑，蘀葉滿疎叢。", "方便如開誘，南宗與北宗。"]'),
('4d8691fc-fd80-43e0-8d36-761684e18479','廢慶寶寺','耿湋','唐','唐诗','tang','','[]','黃葉前朝寺，無僧寒殿開。',48,'全唐诗/poet.tang.14000.json','["黃葉前朝寺，無僧寒殿開。", "池晴龜出暴，松暝鶴飛迴。", "古井碑橫草，陰廊畫雜苔。", "禪宮亦銷歇，塵世轉堪哀。"]'),
('223bb467-399f-423d-8e76-1a6a2a30787e','赴許州留別洛中親故','耿湋','唐','唐诗','tang','','[]','淳風今變俗，末學誤爲文。',48,'全唐诗/poet.tang.14000.json','["淳風今變俗，末學誤爲文。", "幸免投湘浦，那辭近汝墳。", "山遮魏闕路，日隱洛陽雲。", "誰念聯翩翼，烟中獨失羣。"]'),
('e75cc2c9-545d-4604-a912-837abba0724e','送葉尊師歸處州','耿湋','唐','唐诗','tang','','[]','風馭南行遠，長山與夜江。',48,'全唐诗/poet.tang.14000.json','["風馭南行遠，長山與夜江。", "羣祆離分野，五嶽拜旌幢。", "石髓調金鼎，雲漿實玉缸。", "㹞㹞吠聲曉，洞府有仙厖。"]'),
('66f58c81-ba56-4a87-9544-df2374830e6f','酬張少尹秋日鳳翔西郊見寄','耿湋','唐','唐诗','tang','','[]','鼎氣孕河汾，英英濟舊勳。',120,'全唐诗/poet.tang.14000.json','["鼎氣孕河汾，英英濟舊勳。", "劉生曾任俠，張率自能文。", "官佐征西府，名齊將上軍。", "秋山遙出浦，野鶴暮離羣。", "遠恨邊笳起，勞歌騎吏聞。", "廢關人不到，荒戍日空曛。", "草木涼初變，陰晴景半分。", "疊蟬臨積水，亂燕入過雲。", "麗藻終思我，衰髯亦爲君。", "閑吟寡和曲，庭葉漸紛紛。"]'),
('8aa6132d-c61e-4218-af24-5d9009e6795d','春日書情寄元校書伯和相國元子','耿湋','唐','唐诗','tang','','[]','數歲平津邸，諸生出門時。',96,'全唐诗/poet.tang.14000.json','["數歲平津邸，諸生出門時。", "羇孤力行早，疎賤託身遲。", "芳草看無厭，青山到未期。", "貧居悲老大，春日上茅茨。", "衛玠瓊瑤色，玄成鼎鼐姿。", "友朋漢相府，兄弟謝家詩。", "律合聲雖應，勞歌調自悲。", "流年不可住，惆悵鏡中絲。"]'),
('57c7a9dd-fdba-4ae7-8e31-6ebbf1f7c024','奉送崔侍御和蕃','耿湋','唐','唐诗','tang','','[]','萬里華戎隔，風沙道路秋。',72,'全唐诗/poet.tang.14000.json','["萬里華戎隔，風沙道路秋。", "新恩明主啟，舊好使臣修。", "旌節隨邊草，關山見戍樓。", "俗殊人左袵，地遠水西流。", "日暮冰先合，春深雪未休。", "無論善長對，博望自封侯。"]'),
('a3dc1675-b12f-4c6f-8346-2f05a369528e','春日即事','耿湋','唐','唐诗','tang','','[]','芳菲那變易，年鬢自蹉跎。',72,'全唐诗/poet.tang.14000.json','["芳菲那變易，年鬢自蹉跎。", "室與千峯對，門唯二仲過。", "宦情知己少，生事託人多。", "草色微風長，鶯聲細雨和。", "幾時猶滯拙，終日望恩波。", "縱欲論相報，無如漂母何。"]'),
('5d8b0af7-e222-4396-b29a-511afca4b8e7','仙山行','耿湋','唐','唐诗','tang','','[]','深溪人不到，杖策獨緣源。',74,'全唐诗/poet.tang.14000.json','["深溪人不到，杖策獨緣源。", "花落尋無徑，雞鳴覺近村。", "數翁皆藉草，對[弈]復傾尊。", "看畢初爲局，歸逢幾世孫。", "雲迷入洞處，水引出山門。", "惆悵歸城郭，樵柯迹尚存。"]'),
('caf3d439-2a29-424a-8fad-501659965b59','得替後書懷上第五相公','耿湋','唐','唐诗','tang','','[]','誰語恓惶客，偏承顧盼私。',96,'全唐诗/poet.tang.14000.json','["誰語恓惶客，偏承顧盼私。", "應逾骨肉分，敢忘死生期。", "山縣唯荒壘，雲屯盡老師。", "庖人寧自代，食蘗謬相推。", "黃綬名空罷，青春鬢又衰。", "還來掃門處，猶未報恩時。", "獨立花飛滿，無言月下遲。", "不知丞相意，更欲遣何之。"]'),
('882976bf-5aa1-4234-95b4-bff65df45589','入塞曲','耿湋','唐','唐诗','tang','','[]','將軍帶十圍，重錦製戎衣。',72,'全唐诗/poet.tang.14000.json','["將軍帶十圍，重錦製戎衣。", "猿臂銷弓力，虬鬚長劒威。", "首登平樂宴，新破大宛歸。", "樓上誅姬笑，門前問客稀。", "暮烽玄兔急，秋草紫騮肥。", "未奉君王詔，高槐晝掩扉。"]'),
('c51992a8-b4a7-46a8-8bf1-43a71b4f4ad3','送姚校書因歸河中','耿湋','唐','唐诗','tang','','[]','十年相見少，一歲又還鄉。',72,'全唐诗/poet.tang.14000.json','["十年相見少，一歲又還鄉。", "去住人惆悵，東西路渺茫。", "古陂無茂草，高樹有殘陽。", "委棄秋來稻，彫疎採後桑。", "月輪生舜廟，河水出關牆。", "明日過閭里，光輝芸閣郎。"]'),
('6b78aaf7-4de0-4fc2-a524-8eaa6e66a244','題清源寺','耿湋','唐','唐诗','tang','','[]','儒墨兼宗道，雲泉隱舊廬。',72,'全唐诗/poet.tang.14000.json','["儒墨兼宗道，雲泉隱舊廬。", "盂城今寂寞，輞水自紆餘。", "內學銷多累，西林易故居。", "深房春竹老，細雨夜鐘疎。", "陳跡留金地，遺文在石渠。", "不知登座客，誰得蔡邕書。"]'),
('175b7fd0-26f3-4b13-8526-3348152fed32','奉送蔣尚書兼御史大夫東都留守','耿湋','唐','唐诗','tang','','[]','副相威名重，春卿禮樂崇。',72,'全唐诗/poet.tang.14000.json','["副相威名重，春卿禮樂崇。", "錫珪仍拜下，分命遂居東。", "高斾翻秋日，清鐃引細風。", "蟬稀金谷樹，草徧德陽宮。", "敎用儒門儉，兵依武庫雄。", "誰云千載後，周召獨爲公。"]'),
('07d6638d-5f87-4f48-aca5-a0ee639bc795','喜侯十七校書見訪','耿湋','唐','唐诗','tang','','[]','東城獨屏居，有客到吾廬。',72,'全唐诗/poet.tang.14000.json','["東城獨屏居，有客到吾廬。", "發廩因舂黍，開畦復翦蔬。", "許酣令乞酒，辭窶任無魚。", "徧出新成句，更通未悟書。", "藤絲秋不長，竹粉雨仍餘。", "誰爲須張燭，涼空有望舒。"]'),
('2b04a3a4-f013-41dd-a0b9-865d58781400','晚春青門林亭燕集','耿湋','唐','唐诗','tang','','[]','都門連騎出，東野柳如絲。',72,'全唐诗/poet.tang.14000.json','["都門連騎出，東野柳如絲。", "秦苑看山處，王孫逐草時。", "歡遊難再得，衰老是前期。", "林靜鶯啼遠，春深日過遲。", "落花今夕思，秉燭古人詩。", "對酒當爲樂，雙杯未可辭。"]'),
('88c06a24-ace5-4c54-85f6-dcd4b6893b3f','晚秋東遊寄猗氏第五明府解縣韓明府','耿湋','唐','唐诗','tang','','[]','步出青門去，疎鐘隔上林。',72,'全唐诗/poet.tang.14000.json','["步出青門去，疎鐘隔上林。", "四郊多難日，千里獨歸心。", "暮鳥聲偏苦，秋雲色易陰。", "亂墳松柏少，野徑草茅深。", "灞涘袁安履，汾南宓賤琴。", "何由聽白雪，秪益淚霑襟。"]'),
('ac51ade1-4a21-47ce-a063-2fe7c05a16fc','奉和元承杪秋憶終南舊居','耿湋','唐','唐诗','tang','','[]','白玉郎仍少，羊車上路平。',96,'全唐诗/poet.tang.14000.json','["白玉郎仍少，羊車上路平。", "秋風搖遠草，舊業起高情。", "亂樹通秦苑，重原接杜城。", "溪雲隨暮淡，野水帶寒清。", "廣樹留峯翠，閑門響葉聲。", "近樵應已燒，多稼又新成。", "解佩從休沐，承家豈退耕。", "恭侯有遺躅，何事學泉明。"]'),
('c1a460c1-660c-400c-81e8-c085877eb300','晚夏即事臨南居','耿湋','唐','唐诗','tang','','[]','何須學從宦，其奈本無機。',72,'全唐诗/poet.tang.14000.json','["何須學從宦，其奈本無機。", "蕙草芳菲歇，青山早晚歸。", "廣庭餘落照，高枕對閑扉。", "樹色迎秋老，蟬聲過雨稀。", "艱難逢事異，去就與時違。", "遙憶衡門外，蒼蒼三徑微。"]'),
('6915cdbf-d7ee-4708-a247-7c1b83d0b538','省試驪珠詩','耿湋','唐','唐诗','tang','','[]','是日重泉下，言探徑寸珠。',72,'全唐诗/poet.tang.14000.json','["是日重泉下，言探徑寸珠。", "龍鱗今不逆，魚目也應殊。", "掌上星初滿，盤中月正孤。", "酬恩光莫及，照乘色難踰。", "欲問投人否，先論按劒無。", "儻憐希代價，敢對此冰壺。"]'),
('57259261-28ad-4dde-a63f-e3bb6a9dd1a7','元日早朝','耿湋','唐','唐诗','tang','','[]','九陌朝臣滿，三朝候鼓賒。',120,'全唐诗/poet.tang.14000.json','["九陌朝臣滿，三朝候鼓賒。", "遠珂時接韻，攢炬偶成花。", "紫貝爲高闕，黃龍建大牙。", "參差萬戟合，左右八貂斜。", "羽扇紛朱檻，金鑪隔翠華。", "微風傳曙漏，曉日上春霞。", "環珮聲重疊，蠻夷服等差。", "樂和天易感，山固壽無涯。", "渥澤千年聖，車書四海家。", "盛明多在位，誰得守蓬麻。"]'),
('16c0e372-8785-479b-98a8-d88f25df6730','送歸中丞使新羅','耿湋','唐','唐诗','tang','','[]','遠國通王化，儒林得使臣。',96,'全唐诗/poet.tang.14000.json','["遠國通王化，儒林得使臣。", "六君成典冊，萬里奉絲綸。", "雲水連孤棹，恩私在一身。", "悠悠龍節去，渺渺蜃樓新。", "望裏行還暮，波中歲又春。", "昏明看日御，靈怪問舟人。", "城邑分華夏，衣裳擬縉紳。", "他時禮命畢，歸路勿迷津。"]'),
('1eaf1c55-1afe-42de-a6f5-d350c5f25296','贈興平鄭明府','耿湋','唐','唐诗','tang','','[]','海內兵猶在，關西賦未均。',120,'全唐诗/poet.tang.14000.json','["海內兵猶在，關西賦未均。", "仍勞持斧使，尚宰茂陵人。", "遙夜重城掩，清宵片月新。", "綠琴聽古調，白屋被深仁。", "跡與儒生合，心惟靜者親。", "深情先結契，薄宦早趨塵。", "貧病休何日，艱難過此身。", "悠悠行遠道，冉冉過良辰。", "明主知封事，長沮笑問津。", "棲遑忽相見，欲語淚霑巾。"]'),
('8fe1b9db-a556-4d82-8212-54f7137e63d9','和王懷州觀西營秋射','耿湋','唐','唐诗','tang','','[]','謝公親校武，草碧露漫漫。',72,'全唐诗/poet.tang.14000.json','["謝公親校武，草碧露漫漫。", "落葉停高駕，空林滿從官。", "迎籌皆疊鼓，揮箭或移竿。", "名借三軍勇，功推百中難。", "主皮山郡晚，飲筭柳營寒。", "明日開鈴閣，新詩雙玉盤。"]'),
('055ee674-3e13-4973-8a53-1bdc400abcf4','晚登虔州即事寄李侍御','耿湋','唐','唐诗','tang','','[]','章溪與貢水，何事會波瀾。',96,'全唐诗/poet.tang.14000.json','["章溪與貢水，何事會波瀾。", "萬里歸人少，孤舟行路難。", "春光浮曲浪，暮色隔連灘。", "花發從南早，江流向北寬。", "故交參盛府，新角聳危冠。", "楚劒期終割，隋珠惜未彈。", "酒醒愁轉極，別遠淚初乾。", "願保喬松質，青青過大寒。"]'),
('82caff2c-18ae-499b-9c2d-f5bab6dc2e54','奉和第五相公登鄱陽郡城西樓','耿湋','唐','唐诗','tang','','[]','茂德爲邦久，豐貂舊相尊。',156,'全唐诗/poet.tang.14000.json','["茂德爲邦久，豐貂舊相尊。", "發生傳雨露，均養助乾坤。", "曉肆登樓目，春銷戀闕魂。", "女牆分吏事，遠道啟津門。", "湓浦潮聲盡，鍾陵暮色繁。", "夕陽移夢土，芳草接湘源。", "封內羣甿復，兵間百賦存。", "童牛耕廢畝，壕木遶新村。", "野步漁聲溢，荒祠鼓舞喧。", "高齋成五字，遠岫發孤猨。", "一顧承英達，多榮及子孫。", "家貧仍受賜，身老未酬恩。", "屬和瑤華曲，堪將繫組綸。"]'),
('cca2e8c3-79be-4b43-a8c8-9448e3ee0927','甘泉詩','耿湋','唐','唐诗','tang','','[]','異井甘如醴，深仁遠未涯。',72,'全唐诗/poet.tang.14000.json','["異井甘如醴，深仁遠未涯。", "氣寒堪破暑，源淨自蠲邪。", "修綆懸冰甃，新桐蔭玉沙。", "帶星凝曉露，拂霧湧秋華。", "綠溢涵千仞，清泠飲萬家。", "何能葛洪宅，終日閉煙霞。"]'),
('ee861e07-c37b-47b9-a5b1-641d43834d15','發綿津驛','耿湋','唐','唐诗','tang','','[]','孤舟北去暮心傷，細雨東風春草長。',64,'全唐诗/poet.tang.14000.json','["孤舟北去暮心傷，細雨東風春草長。", "杳杳短亭分水陸，隆隆遠鼓集漁商。", "千叢野竹連湘浦，一派寒江下吉陽。", "欲問長安今遠近，初年塞雁有歸行。"]'),
('df7287a7-ee3f-4ef8-a4fa-e758745b0a5d','塞上曲','耿湋','唐','唐诗','tang','','[]','慣習干戈事鞍馬，初從少小在邊城。',64,'全唐诗/poet.tang.14000.json','["慣習干戈事鞍馬，初從少小在邊城。", "身微久屬千夫長，家遠多親五郡兵。", "嬾說疆場曾大獲，且悲年鬢老長征。", "寒鴻過盡殘陽裏，樓上悽悽暮角聲。"]'),
('807c4c41-ecef-403e-9d28-551399bd1f2f','路旁老人','耿湋','唐','唐诗','tang','','[]','老人獨坐倚官樹，欲語潸然淚便垂。',64,'全唐诗/poet.tang.14000.json','["老人獨坐倚官樹，欲語潸然淚便垂。", "陌上歸心無產業，城邊戰骨有親知。", "餘生尚在艱難日，長路多逢輕薄兒。", "綠水青山雖似舊，如今貧後復何爲。"]'),
('7a73a6b4-a6a3-4f6e-93e1-812ee4212ea4','贈別劉員外長卿','耿湋','唐','唐诗','tang','','[]','清如寒玉直如絲，世故多虞事莫期。',64,'全唐诗/poet.tang.14000.json','["清如寒玉直如絲，世故多虞事莫期。", "建德津亭人別夜，新安江水月明時。", "爲文易老皆知苦，謫宦無名倍足悲。", "不學朱雲能折檻，空羞獻納在丹墀。"]'),
('83db426c-3099-48f3-b939-b89ffcb8dd72','宿萬固寺因寄嚴補闕','耿湋','唐','唐诗','tang','','[]','曉隨樵客到青冥，因禮山僧宿化城。',64,'全唐诗/poet.tang.14000.json','["曉隨樵客到青冥，因禮山僧宿化城。", "鐘梵已休初入定，有無皆離本難名。", "雲開半夜千林靜，月上中峰萬壑明。", "爲報故人雷處士，塵心終日自勞生。"]'),
('eea4a079-7e65-4aa0-be8c-34dfd376efe3','岐陽客舍呈張明府','耿湋','唐','唐诗','tang','','[]','逸妻稚子應溝壑，歸路茫茫東去遙。',64,'全唐诗/poet.tang.14000.json','["逸妻稚子應溝壑，歸路茫茫東去遙。", "涼葉下時心悄悄，空齋夢裏雨蕭蕭。", "星霜漸見侵華髮，生長虛聞在聖朝。", "知己只今何處在，故山無事別漁樵。"]'),
('3e128a79-2faa-4ca7-836a-d206056ae268','奉和李觀察登河中白樓','耿湋','唐','唐诗','tang','','["\u9ec4\u6cb3"]','城上高樓飛鳥齊，從公一遂躡丹梯。',64,'全唐诗/poet.tang.14000.json','["城上高樓飛鳥齊，從公一遂躡丹梯。", "黃河曲盡流天外，白日輪輕落海西。", "玉樹九重長在夢，雲衢一望杳如迷。", "何心更和陽春奏，況復秋風聞戰鼙。"]'),
('7e8672d8-cbab-49dd-9dd1-13a17097b811','朝下寄韓舍人','耿湋','唐','唐诗','tang','','[]','侍臣鳴珮出西曹，鸞殿分階翊綵旄。',64,'全唐诗/poet.tang.14000.json','["侍臣鳴珮出西曹，鸞殿分階翊綵旄。", "瑞氣迴浮青玉案，日華遙上赤霜袍。", "花間焰焰雲旗合，鳥外亭亭露掌高。", "肯念萬年芳樹裏，隨風一葉在蓬蒿。"]'),
('e3d774e2-5c3f-4127-a82c-439c9af3529c','賀李觀察禱河神降雨','耿湋','唐','唐诗','tang','','[]','質明齋祭北風微，騶馭千羣擁廟扉。',64,'全唐诗/poet.tang.14000.json','["質明齋祭北風微，騶馭千羣擁廟扉。", "玉帛纔敷雲淡淡，笙鏞未撤雨霏霏。", "路邊五稼添膏長，河上雙旌帶溼歸。", "若出敬亭山下作，何人敢和謝玄暉。"]'),
('bfb88b6b-ee07-4359-ab0b-c9c5756383d7','上將行','耿湋','唐','唐诗','tang','','[]','蕭關掃定犬羊羣，閉閣層城白日曛。',64,'全唐诗/poet.tang.14000.json','["蕭關掃定犬羊羣，閉閣層城白日曛。", "櫪上驊騮嘶鼓角，門前老將識風雲。", "旌旗四面寒山暎，絲管千家靜夜聞。", "誰道古來多簡冊，功臣唯有衛將軍。"]'),
('de8243b7-914e-404a-afe4-4a4fd5dc03c3','許下書情寄張韓二舍人','耿湋','唐','唐诗','tang','','[]','謫宦軍城老更悲，近來頻夜夢丹墀。',64,'全唐诗/poet.tang.14000.json','["謫宦軍城老更悲，近來頻夜夢丹墀。", "銀杯乍滅心中火，金鑷唯多鬢上絲。", "繞院綠苔聞雁處，滿庭黃葉閉門時。", "故人高步雲衢上，肯念前程杳未期。"]'),
('38df8395-ef69-4307-8625-1b8b115699f6','九日','耿湋','唐','唐诗','tang','','[]','重陽寒寺滿秋梧，客在南樓顧老夫。',64,'全唐诗/poet.tang.14000.json','["重陽寒寺滿秋梧，客在南樓顧老夫。", "步蹇強登遊藻井，髮稀那更插茱萸。", "橫空過雨千峰出，大野新霜萬葉枯。", "更望尊中菊花酒，殷勤能得幾回沽。"]'),
('fa4996bf-9c69-42a4-a2be-9080ee3646bb','送大谷高少府','耿湋','唐','唐诗','tang','','[]','縣屬幷州北近胡，悠悠此別宦仍孤。',64,'全唐诗/poet.tang.14000.json','["縣屬幷州北近胡，悠悠此別宦仍孤。", "應知史筆思循吏，莫料轅門笑魯儒。", "古塞草青宜牧馬，春城月暗好啼烏。", "彫殘貴有親仁術，梅福何須去隱吳。"]'),
('b0aae2c5-e767-4de5-b119-6c9e7c8e6288','同李端春望','耿湋','唐','唐诗','tang','','[]','二毛羇旅尚迷津，萬井鶯花雨後春。',64,'全唐诗/poet.tang.14000.json','["二毛羇旅尚迷津，萬井鶯花雨後春。", "宮闕參差當晚日，山河迤邐靜纖塵。", "和風醉裏承恩客，芳草歸時失意人。", "南北東西各自去，年年依舊物華新。"]'),
('86c5a426-d42a-4f80-9971-9ded9328b779','嶽祠送薛近貶官','耿湋','唐','唐诗','tang','','[]','枯松老柏仙山下，白帝祠堂枕古逵。',64,'全唐诗/poet.tang.14000.json','["枯松老柏仙山下，白帝祠堂枕古逵。", "遷客無辜祝史告，神明有喜女巫知。", "遙思桂浦人空去，遠過衡陽雁不隨。", "度嶺梅花翻向北，回看不見樹南枝。"]'),
('331b3fff-8815-486a-9bf4-545ecb0774dd','送友人遊江南','耿湋','唐','唐诗','tang','','[]','遠別悠悠白髮新，江潭何處是通津。',64,'全唐诗/poet.tang.14000.json','["遠別悠悠白髮新，江潭何處是通津。", "潮聲偏懼初來客，海味唯甘久住人。", "漠漠煙光前浦晚，青青草色定山春。", "汀洲更有南迴雁，亂起聯翩北向秦。"]'),
('a233c8e0-8e9e-4790-a0b9-1aeaffe5de2d','長門怨','耿湋','唐','唐诗','tang','','[]','聞道昭陽宴，嚬蛾落葉中。',24,'全唐诗/poet.tang.14000.json','["聞道昭陽宴，嚬蛾落葉中。", "清歌逐寒月，遙夜入深宮。"]'),
('560558a6-9d96-4417-bf46-2a59bc451167','秋日','耿湋','唐','唐诗','tang','','[]','反照入閭巷，憂來與誰語。',24,'全唐诗/poet.tang.14000.json','["反照入閭巷，憂來與誰語。", "古道無人行，秋風動禾黍。"]'),
('3aedcdc5-251d-452f-973a-9bdfa441bd2f','秋夜','耿湋','唐','唐诗','tang','','[]','高秋夜分後，遠客雁來時。',24,'全唐诗/poet.tang.14000.json','["高秋夜分後，遠客雁來時。", "寂寞重門掩，無人問所思。"]'),
('b9424647-f65f-4a67-9ac7-5e266d7510bc','慈恩寺殘春','耿湋','唐','唐诗','tang','','[]','雙林花已盡，葉色占殘芳。',24,'全唐诗/poet.tang.14000.json','["雙林花已盡，葉色占殘芳。", "若問同遊客，高年最斷腸。"]'),
('33e9b1b3-6644-4366-8671-c763585e6fd6','早次眉縣界','耿湋','唐','唐诗','tang','','[]','匹馬曉路歸，悠悠渭川道。',24,'全唐诗/poet.tang.14000.json','["匹馬曉路歸，悠悠渭川道。", "晴山向孤城，秋日滿白草。"]'),
('be95f769-211b-4e8b-a1fe-9c2f6e99f613','路傍墓','耿湋','唐','唐诗','tang','','[]','石馬雙雙當古樹，不知何代公侯墓。',32,'全唐诗/poet.tang.14000.json','["石馬雙雙當古樹，不知何代公侯墓。", "墓前靡靡春草深，唯有行人看碑路。"]'),
('7b56280e-9c60-40db-acd2-83cb689eceda','代園中老人','耿湋','唐','唐诗','tang','','[]','傭賃難堪一身老，皤皤力役在青春。',32,'全唐诗/poet.tang.14000.json','["傭賃難堪一身老，皤皤力役在青春。", "林園手種唯吾事，桃李成陰歸別人。"]'),
('23c8ba39-a67c-435f-ab56-48667c25a85b','古意','耿湋','唐','唐诗','tang','','[]','雖言千騎上頭居，一世生離恨有餘。',32,'全唐诗/poet.tang.14000.json','["雖言千騎上頭居，一世生離恨有餘。", "葉下綺窗銀燭冷，含啼自草錦中書。"]'),
('d6e42084-08d8-44c4-9919-1e5d10dc1fb9','涼州詞','耿湋','唐','唐诗','tang','','[]','國使翻翻隨斾旌，隴西岐路足荒城。',32,'全唐诗/poet.tang.14000.json','["國使翻翻隨斾旌，隴西岐路足荒城。", "氈裘牧馬胡雛小，日暮蕃歌三兩聲。"]'),
('39470e42-9a99-4d04-bd7a-227124373888','安邑王校書居','耿湋','唐','唐诗','tang','','[]','秋來池館清，夜聞宮漏聲。',48,'全唐诗/poet.tang.14000.json','["秋來池館清，夜聞宮漏聲。", "迢遰玉山迥，泛灧銀河傾。", "琴上松風至，窗裏竹煙生。", "多君不家食，孰云事巖耕。"]'),
('a89dd426-d770-4203-87c8-544a6cdb5023','登總持寺閣','耿湋','唐','唐诗','tang','','[]','今日登高閣，三休忽自悲。',48,'全唐诗/poet.tang.14000.json','["今日登高閣，三休忽自悲。", "因知筋力減，不及徃年時。", "草樹還如舊，山河亦在茲。", "龍鍾兼老病，更有重來期。"]'),
('fe96e9b8-e190-46bb-b402-108c8b9342f0','寄錢起','耿湋','唐','唐诗','tang','','[]','草長花落樹，羸病強尋春。',48,'全唐诗/poet.tang.14000.json','["草長花落樹，羸病強尋春。", "無復少年意，空餘華髮新。", "青原高見水，白社靜逢人。", "寄謝南宮客，軒車不見親。"]'),
('845c5b71-0554-4e28-9333-3a4921d81bfe','宿青龍寺故曇上人院','耿湋','唐','唐诗','tang','','[]','年深宮院在，閒客自相逢。',48,'全唐诗/poet.tang.14000.json','["年深宮院在，閒客自相逢。", "閉戶臨寒竹，無人有夜鐘。", "降龍今已去，巢鶴竟何從。", "坐見繁星曉，淒涼識舊峯。"]'),
('870032c5-1d66-42d1-8614-3d470b63e8d2','新蟬','耿湋','唐','唐诗','tang','','[]','今朝蟬忽鳴，遷客若爲情。',48,'全唐诗/poet.tang.14000.json','["今朝蟬忽鳴，遷客若爲情。", "便覺一年謝，能令萬感生。", "微風方滿樹，落日稍沈城。", "爲問同懷者，淒涼聽幾聲。"]'),
('66711c88-d15e-4440-a51c-03447a294dee','秋中雨田園即事','耿湋','唐','唐诗','tang','','[]','漠漠重雲暗，蕭蕭密雨垂。',72,'全唐诗/poet.tang.14000.json','["漠漠重雲暗，蕭蕭密雨垂。", "爲霖淹古道，積日滿荒陂。", "五稼何時穫，孤村幾戶炊。", "亂流發通圃，腐葉著秋枝。", "暮爨新樵溼，晨漁舊浦移。", "空餘去年菊，花發在東籬。"]'),
('e5809c93-7c03-458e-b028-7c5f765c2302','拜新月','耿湋','唐','唐诗','tang','','["\u5199\u4eba", "\u6708\u4eae"]','開簾見新月，便即下堦拜。',24,'全唐诗/poet.tang.14000.json','["開簾見新月，便即下堦拜。", "細語人不聞，北風吹裙帶。"]'),
('c6a1a8f4-406e-47d3-af0a-f5448c5db710','客行贈人','耿湋','唐','唐诗','tang','','[]','旅行雖別路，日暮各思歸。',24,'全唐诗/poet.tang.14000.json','["旅行雖別路，日暮各思歸。", "欲下今朝淚，知君亦溼衣。"]'),
('bc193afd-aca5-403b-82ce-a34e4ef281e1','贈山老人','耿湋','唐','唐诗','tang','','[]','白首獨一身，青山爲四隣。',24,'全唐诗/poet.tang.14000.json','["白首獨一身，青山爲四隣。", "雖行故鄉陌，不見故鄉人。"]'),
('8043b134-3787-4442-8fe3-0144fd04131c','贈胡居士','耿湋','唐','唐诗','tang','','[]','孔融過五十，海內故人稀。',24,'全唐诗/poet.tang.14000.json','["孔融過五十，海內故人稀。", "相府恩猶在，知君未拂衣。"]'),
('7f768442-2cad-4923-923f-bfdd106c78ea','薦福寺送元偉','耿湋','唐','唐诗','tang','','[]','送客攀花後，尋僧坐竹時。',24,'全唐诗/poet.tang.14000.json','["送客攀花後，尋僧坐竹時。", "明朝莫回望，青草馬行遲。"]'),
('a81ecdd4-5048-464a-b30d-c10cc513ae0a','觀鄰老栽松','耿湋','唐','唐诗','tang','','[]','雖過老人宅，不解老人心。',24,'全唐诗/poet.tang.14000.json','["雖過老人宅，不解老人心。", "何事斜陽裏，栽松欲待陰。"]'),
('6a7cf7e6-88c9-48cf-8dee-3a39a0c86e67','哭麴象','耿湋','唐','唐诗','tang','','[]','憶昨秋風起，君曾歎逐臣。',24,'全唐诗/poet.tang.14000.json','["憶昨秋風起，君曾歎逐臣。", "何言芳草日，自作九泉人。"]'),
('3bcfa793-8eb9-4674-ab30-ce209f6086ee','哭苗垂','耿湋','唐','唐诗','tang','','[]','舊友無由見，孤墳草欲長。',24,'全唐诗/poet.tang.14000.json','["舊友無由見，孤墳草欲長。", "月斜鄰笛盡，車馬出山陽。"]'),
('8af2d4cd-7f0c-4fcf-8046-21b75d174476','題雲際寺故僧院','耿湋','唐','唐诗','tang','','[]','白髮悤悤色，青山草草心。',24,'全唐诗/poet.tang.14000.json','["白髮悤悤色，青山草草心。", "遠公仍下世，從此別東林。"]'),
('80966406-a627-47c7-93de-73f21d95baa0','句','耿湋','唐','唐诗','tang','','[]','高樹多涼吹，疎蟬足斷聲。',12,'全唐诗/poet.tang.14000.json','["高樹多涼吹，疎蟬足斷聲。"]'),
('b180804b-8079-4cf7-92f6-025638e2fd76','塞下曲 一','戎昱','唐','唐诗','tang','','[]','慘慘寒日沒，北風卷蓬根。',36,'全唐诗/poet.tang.14000.json','["慘慘寒日沒，北風卷蓬根。", "將軍領疲兵，却入古塞門。", "回頭指陰山，殺氣成黃雲。"]'),
('dba5c708-7802-4268-8581-078afa37f3e6','塞下曲 二','戎昱','唐','唐诗','tang','','["\u9ec4\u6cb3"]','上山望胡兵，胡馬馳驟速。',36,'全唐诗/poet.tang.14000.json','["上山望胡兵，胡馬馳驟速。", "黃河冰已合，意又向南牧。", "嫖姚夜出軍，霜雪割人肉。"]'),
('4e8b58fe-34f3-4856-a670-b919ca7f50f0','塞下曲 三','戎昱','唐','唐诗','tang','','[]','塞北無草木，烏鳶巢僵屍。',36,'全唐诗/poet.tang.14000.json','["塞北無草木，烏鳶巢僵屍。", "泱渀沙漠空，終日胡風吹。", "戰卒多苦辛，苦辛無四時。"]'),
('70156f7d-313f-4ac0-9091-6abbd2c78aa5','塞下曲 四','戎昱','唐','唐诗','tang','','[]','晚渡西海西，向東看日沒。',36,'全唐诗/poet.tang.14000.json','["晚渡西海西，向東看日沒。", "傍岸砂礫堆，半和戰兵骨。", "單于竟未滅，陰氣常勃勃。"]'),
('79d357d2-5678-4f6b-ae2e-940fea6f13b9','塞下曲 五','戎昱','唐','唐诗','tang','','[]','城上畫角哀，即知兵心苦。',36,'全唐诗/poet.tang.14000.json','["城上畫角哀，即知兵心苦。", "試問左右人，無言淚如雨。", "何意休明時，終年事鼙鼓。"]'),
('3adbd56c-6ec1-4cc4-b9a5-7bcb8a9abe30','塞下曲 六','戎昱','唐','唐诗','tang','','["\u8fb9\u585e", "\u5c06\u58eb", "\u548c\u5e73", "\u6e34\u671b"]','北風凋白草，胡馬日駸駸。',48,'全唐诗/poet.tang.14000.json','["北風凋白草，胡馬日駸駸。", "夜後戍樓月，秋來邊將心。", "鐵衣霜露重，戰馬歲年深。", "自有盧龍塞，煙塵飛至今。"]'),
('ac81bbb8-0470-4fd2-895f-012474058a1a','苦哉行五首 一','戎昱','唐','唐诗','tang','','[]','彼鼠侵我廚，縱貍授粱肉。',72,'全唐诗/poet.tang.14000.json','["彼鼠侵我廚，縱貍授粱肉。", "鼠雖爲君却，貍食自須足。", "冀雪大國恥，翻是大國辱。", "羶腥逼綺羅，磚瓦雜珠玉。", "登樓非騁望，目笑是心哭。", "何意天樂中，至今奏胡曲。"]'),
('1c7b01a4-e877-45cd-afd8-4c65e212b39e','苦哉行五首 二','戎昱','唐','唐诗','tang','','[]','官軍收洛陽，家住洛陽里。',72,'全唐诗/poet.tang.14000.json','["官軍收洛陽，家住洛陽里。", "夫壻與兄弟，目前見傷死。", "吞聲不許哭，還遣衣羅綺。", "上馬隨匈奴，數秋黃塵裏。", "生爲名家女，死作塞垣鬼。", "鄉國無還期，天津哭流水。"]'),
('2b384aaa-49e7-46c3-a17e-6c1e2b562868','苦哉行五首 三','戎昱','唐','唐诗','tang','','[]','登樓望天衢，目極淚盈睫。',72,'全唐诗/poet.tang.14000.json','["登樓望天衢，目極淚盈睫。", "彊笑無笑容，須妝舊花靨。", "昔年買奴僕，奴僕來碎葉。", "豈意未死間，自爲匈奴妾。", "一生忽至此，萬事痛苦業。", "得出塞垣飛，不如彼蜂蝶。"]'),
('9d4ae998-4e4a-4554-a3b8-55cd9b756d5e','苦哉行五首 四','戎昱','唐','唐诗','tang','','[]','妾家清河邊，七葉承貂蟬。',120,'全唐诗/poet.tang.14000.json','["妾家清河邊，七葉承貂蟬。", "身爲最小女，偏得渾家憐。", "親戚不相識，幽閨十五年。", "有時最遠出，秪到中門前。", "前年狂胡來，懼死翻生全。", "今秋官軍至，豈意遭戈鋋。", "匈奴爲先鋒，長鼻黃髮拳。", "彎弓獵生人，百步牛羊羶。", "脫身落虎口，不及歸黃泉。", "苦哉難重陳，暗哭蒼蒼天。"]'),
('8440d356-95c9-481f-ac60-e6dc2dba444a','苦哉行五首 五','戎昱','唐','唐诗','tang','','[]','可汗奉親詔，今月歸燕山。',72,'全唐诗/poet.tang.14000.json','["可汗奉親詔，今月歸燕山。", "忽如亂刀劒，攪妾心腸間。", "出戶望北荒，迢迢玉門關。", "生人爲死別，有去無時還。", "漢月割妾心，胡風凋妾顏。", "去去斷絕魂，呌天天不聞。"]'),
('a71077aa-b5b4-4c46-b426-3219e253958d','苦辛行','戎昱','唐','唐诗','tang','','[]','且莫奏短歌，聽余苦辛詞。',204,'全唐诗/poet.tang.14000.json','["且莫奏短歌，聽余苦辛詞。", "如今刀筆士，不及屠沽兒。", "少年無事學詩賦，豈意文章復相悞。", "東西南北少知音，終年竟歲悲行路。", "仰面訴天天不聞，低頭告地地不言。", "天地生我尚如此，陌上他人何足論。", "誰謂西江深，涉之固無憂。", "誰謂南山高，可以登之遊。", "險巇唯有世間路，一晌令人堪白頭。", "貴人立意不可測，等閑桃李成荆棘。", "風塵之士深可親，心如雞犬能依人。", "悲來却憶漢天子，不棄相如家舊貧。", "勸君且飲酒，酒能散羇愁。", "誰家有酒判一醉，萬事從他江水流。"]'),
('16cc1ffb-7a18-4903-ab86-35931a9c9620','長安秋夕','戎昱','唐','唐诗','tang','','[]','八月更漏長，愁人起常早。',48,'全唐诗/poet.tang.14000.json','["八月更漏長，愁人起常早。", "閉門寂無事，滿院生秋草。", "昨宵西窗夢，夢入荆南道。", "遠客歸去來，在家貧亦好。"]'),
('82a61610-8bbd-4df6-9406-883d3a05f1a9','羅江客舍','戎昱','唐','唐诗','tang','','[]','山縣秋雲闇，茅亭暮雨寒。',48,'全唐诗/poet.tang.14000.json','["山縣秋雲闇，茅亭暮雨寒。", "自傷庭葉下，誰問客衣單。", "有興時添酒，無聊嬾整冠。", "近來鄉國夢，夜夜到長安。"]'),
('2b563a63-b88a-4af9-99f8-d1840f235ce9','贈岑郎中','戎昱','唐','唐诗','tang','','[]','童年未解讀書時，誦得郎中數首詩。',64,'全唐诗/poet.tang.14000.json','["童年未解讀書時，誦得郎中數首詩。", "四海煙塵猶隔闊，十年魂夢每相隨。", "雖披雲霧逢迎疾，已恨趨風拜德遲。", "天下無人鑒詩句，不尋詩伯重尋誰。"]'),
('3270b9ea-88f8-4ee0-a1e2-f02c3ba7d133','聞笛','戎昱','唐','唐诗','tang','','[]','入夜思歸切，笛聲清更哀。',48,'全唐诗/poet.tang.14000.json','["入夜思歸切，笛聲清更哀。", "愁人不願聽，自到枕前來。", "風起寒雲斷，夜深關月開。", "平明獨惆悵，飛盡一庭梅。"]'),
('ce8bc386-6894-4e72-a15a-5ac5fe6776eb','漢上題韋氏莊','戎昱','唐','唐诗','tang','','[]','結茅同楚客，卜築漢江邊。',48,'全唐诗/poet.tang.14000.json','["結茅同楚客，卜築漢江邊。", "日落數歸鳥，夜深聞扣舷。", "水痕侵岸柳，山翠借廚煙。", "調笑提筐婦，春來蠶幾眠。"]'),
('d0e94887-b94b-45a0-951b-ce4ea165c595','閨情','戎昱','唐','唐诗','tang','','[]','側聽宮官說，知君寵尚存。',48,'全唐诗/poet.tang.14000.json','["側聽宮官說，知君寵尚存。", "未能開笑頰，先欲換愁魂。", "寶鏡窺妝影，紅衫裛淚痕。", "昭陽今再入，寧敢恨長門。"]'),
('2e31e980-e209-482d-8c9e-cf49429e366e','衡陽春日遊僧院','戎昱','唐','唐诗','tang','','[]','曾共劉諮議，同時事道林。',48,'全唐诗/poet.tang.14000.json','["曾共劉諮議，同時事道林。", "與君相掩淚，來客豈知心。", "堦雪凌春積，爐煙向暝深。", "依然舊童子，相送出花林。"]'),
('6a6032a2-4092-4d6b-befc-15119bdaebff','玉臺體題湖上亭','戎昱','唐','唐诗','tang','','[]','湖入縣西邊，湖頭勝事偏。',48,'全唐诗/poet.tang.14000.json','["湖入縣西邊，湖頭勝事偏。", "綠竿初長笋，紅顆未開蓮。", "蔽日高高樹，迎人小小船。", "清風長入坐，夏月似秋天。"]'),
('f10c2ed6-1350-49fb-83e1-c2b6bcea8a02','早梅','戎昱','唐','唐诗','tang','','["\u6885\u82b1", "\u548f\u7269", "\u548f\u7269\u8bd7"]','一樹寒梅白玉條，迥臨村路傍溪橋。',32,'全唐诗/poet.tang.14000.json','["一樹寒梅白玉條，迥臨村路傍溪橋。", "應緣近水花先發，疑是經春雪未銷。"]'),
('530667a7-76e4-49d1-83ac-50db8627d38a','移家別湖上亭','戎昱','唐','唐诗','tang','','[]','好是春風湖上亭，柳條藤蔓繫離情。',32,'全唐诗/poet.tang.14000.json','["好是春風湖上亭，柳條藤蔓繫離情。", "黃鶯久住渾相識，欲別頻啼四五聲。"]'),
('db7b46aa-a21b-48b6-a313-76af04709e52','客堂秋夕','戎昱','唐','唐诗','tang','','[]','隔窗螢影滅復流，北風微雨虛堂秋。',64,'全唐诗/poet.tang.14000.json','["隔窗螢影滅復流，北風微雨虛堂秋。", "蟲聲竟夜引鄉淚，蟋蟀何自知人愁。", "四時不得一日樂，以此方悲客遊惡。", "寂寂江城無所聞，梧桐葉上偏蕭索。"]'),
('99bfd98c-9520-4064-b151-3390901fbe59','湖南雪中留別','戎昱','唐','唐诗','tang','','[]','草草還草草，湖東別離早。',48,'全唐诗/poet.tang.14000.json','["草草還草草，湖東別離早。", "何處愁殺人，歸鞍雪中道。", "出門迷轍跡，雲水白浩浩。", "明日武陵西，相思鬢堪老。"]'),
('a2a74e95-00c2-4dce-a38e-6a4ec4a8923d','贈別張駙馬','戎昱','唐','唐诗','tang','','[]','上元年中長安陌，見君朝下欲歸宅。',208,'全唐诗/poet.tang.14000.json','["上元年中長安陌，見君朝下欲歸宅。", "飛龍騎馬三十匹，玉勒雕鞍照初日。", "數里衣香遙撲人，長衢雨歇無纖塵。", "從奴斜抱勑賜錦，雙雙蹙出金麒麟。", "天子愛壻皇后弟，獨步明時負權勢。", "一身扈蹕承殊澤，甲第朱門聳高戟。", "鳳凰樓上伴吹簫，鸚鵡杯中醉留客。", "泰去否來何足論，宮中晏駕人事翻。", "一朝負譴辭丹闕，五年待罪湘江源。", "冠冕淒涼幾遷改，眼看桑田變成海。", "華堂金屋別賜人，細眼黃頭總何在。", "渚宮相見寸心悲，嬾欲今時問昔時。", "看君風骨殊未歇，不用愁來雙淚垂。"]'),
('b9bdd400-a18e-4a57-b9ee-602eddfbaabe','涇州觀元戎出師','戎昱','唐','唐诗','tang','','[]','寒日征西將，蕭蕭萬馬叢。',96,'全唐诗/poet.tang.14000.json','["寒日征西將，蕭蕭萬馬叢。", "吹笳覆樓雪，祝纛滿旗風。", "遮虜黃雲斷，燒羌白草空。", "金鐃肅天外，玉帳靜霜中。", "朔野長城閉，河源舊路通。", "衛青師自老，魏絳賞何功。", "槍壘依沙迥，轅門壓塞雄。", "燕然如可勒，萬里願從公。"]'),
('5f82c2ab-c614-4a30-808a-450b07c8aa12','從軍行','戎昱','唐','唐诗','tang','','[]','昔從李都尉，雙鞬照馬蹄。',108,'全唐诗/poet.tang.14000.json','["昔從李都尉，雙鞬照馬蹄。", "擒生黑山北，殺敵黃雲西。", "太白沈虜地，邊草復萋萋。", "歸來邯鄲市，百尺青樓梯。", "感激然諾重，平生膽力齊。", "芳筵暮歌發，豔粉輕鬟低。", "半酣秋風起，鐵騎門前嘶。", "遠戍報烽火，孤城嚴鼓鼙。", "揮鞭望塵去，少婦莫含啼。"]'),
('5a3f1593-4234-4d3e-8c4b-3c870e9c85cd','古意','戎昱','唐','唐诗','tang','','[]','女伴朝來說，知君欲棄捐。',48,'全唐诗/poet.tang.14000.json','["女伴朝來說，知君欲棄捐。", "嬾梳明鏡下，羞到畫堂前。", "有淚霑脂粉，無情理管弦。", "不知將巧笑，更遣向誰憐。"]'),
('1bfe73b3-605e-4e42-9e57-49ad2696f716','聽杜山人彈胡笳','戎昱','唐','唐诗','tang','','[]','綠琴胡笳誰妙彈，山人杜陵名庭蘭。',254,'全唐诗/poet.tang.14000.json','["綠琴胡笳誰妙彈，山人杜陵名庭蘭。", "杜君少與山人友，山人沒來今已久。", "當時海內求知音，囑付胡笳入君手。", "杜陵攻琴四十年，琴聲在音不在弦。", "座中爲我奏此曲，滿堂蕭飋如窮邊。", "第一第二拍，淚盡蛾眉沒蕃客。", "更聞出塞入塞聲，穹廬氈帳難爲情。", "胡天雨雪四時下，五月不曾芳草生。", "須臾促軫變宮徵，一聲悲兮一聲喜。", "南看漢月雙眼明，却顧胡兒寸心死。", "迴鶻數年收洛陽，洛陽士女皆驅將。", "豈無父母與兄弟，聞此哀情皆斷腸。", "杜陵先生證此道，沈家祝家皆絕倒。", "如今世上雅風衰，若箇深知此聲好。", "世上愛箏不愛琴，則明此調難知音。", "今朝促軫爲君奏，不向俗流傳此心。"]'),
('fd16e4cc-0d3d-4994-8d40-6bbdc4876a01','詠史','戎昱','唐','唐诗','tang','','[]','漢家青史上，計拙是和親。',48,'全唐诗/poet.tang.14000.json','["漢家青史上，計拙是和親。", "社稷依明主，安危託婦人。", "豈能將玉貌，便擬靜胡塵。", "地下千年骨，誰爲輔佐臣。"]'),
('2f7f1998-5bf1-4c13-b713-5c1b6deef5c3','桂州臘夜','戎昱','唐','唐诗','tang','','["\u601d\u4e61", "\u6625\u8282"]','坐到三更盡，歸仍萬里賒。',48,'全唐诗/poet.tang.14000.json','["坐到三更盡，歸仍萬里賒。", "雪聲偏傍竹，寒夢不離家。", "曉角分殘漏，孤燈落碎花。", "二年隨驃騎，辛苦向天涯。"]'),
('20d3e19e-4980-4ebe-9bfe-f20fecc160d6','再赴桂州先寄李大夫','戎昱','唐','唐诗','tang','','[]','玷玉甘長棄，朱門喜再遊。',48,'全唐诗/poet.tang.14000.json','["玷玉甘長棄，朱門喜再遊。", "過因纔後重，恩合死前酬。", "養驥須憐瘦，栽松莫厭秋。", "今朝兩行淚，一半血和流。"]'),
('b050513c-bd96-4e75-90b5-1e2f0894e9ec','題招提寺','戎昱','唐','唐诗','tang','','[]','招提精舍好，石壁向江開。',48,'全唐诗/poet.tang.14000.json','["招提精舍好，石壁向江開。", "山影水中盡，鳥聲天上來。", "一燈傳歲月，深院長莓苔。", "日暮雙林磬，泠泠送客回。"]'),
('21d815f2-631f-4389-935e-f7054b2552e2','謫官辰州冬至日[有]懷','戎昱','唐','唐诗','tang','','[]','去年長至在長安，策杖曾簪獬豸冠。',64,'全唐诗/poet.tang.14000.json','["去年長至在長安，策杖曾簪獬豸冠。", "此歲長安逢至日，下堦遙想雪霜寒。", "夢隨行伍朝天去，身寄窮荒報國難。", "北望南郊消息斷，江頭唯有淚闌干。"]'),
('42f4f46e-3f2c-4762-9e90-d4ba21cf18dd','贈韋況徴君','戎昱','唐','唐诗','tang','','[]','身欲逃名名自隨，鳳銜丹詔降茅茨。',64,'全唐诗/poet.tang.14000.json','["身欲逃名名自隨，鳳銜丹詔降茅茨。", "苦節難違天子命，貞心唯有老松知。", "回看藥竈封題密，強入蒲輪引步遲。", "今日巢由舊冠帶，聖朝風化勝堯時。"]'),
('2ba60883-d111-4b28-a339-b5104acebe25','送吉州閻使君入道二首 一','戎昱','唐','唐诗','tang','','[]','聞道桃源去，塵心忽自悲。',72,'全唐诗/poet.tang.14000.json','["聞道桃源去，塵心忽自悲。", "余當從宦日，君是棄官時。", "金汞封仙骨，靈津嚥玉池。", "受傳三籙備，起坐五雲隨。", "洞裏花常發，人間鬢易衰。", "他年會相訪，莫作爛柯棊。"]'),
('9e1a45d7-2c65-48f9-9a1f-00c367958a4f','送吉州閻使君入道二首 二','戎昱','唐','唐诗','tang','','[]','廬陵太守近隳官，霞帔初朝五帝壇。',64,'全唐诗/poet.tang.14000.json','["廬陵太守近隳官，霞帔初朝五帝壇。", "風過鬼神延受籙，夜深龍虎衛燒丹。", "冰容入鏡纖埃靜，玉液添缾漱齒寒。", "莫遣桃花迷客路，千山萬水訪君難。"]'),
('80bda9d4-0954-4a61-964c-62cb5a890867','入劒門','戎昱','唐','唐诗','tang','','[]','劒門兵革後，萬事盡堪悲。',48,'全唐诗/poet.tang.14000.json','["劒門兵革後，萬事盡堪悲。", "鳥鼠無巢穴，兒童話別離。", "山川同昔日，荆棘是今時。", "征戰何年定，家家有畫旗。"]'),
('e55a255c-8b5a-4f5f-959d-31eacbd3289d','過商山','戎昱','唐','唐诗','tang','','[]','雨暗商山過客稀，路傍孤店閉柴扉。',32,'全唐诗/poet.tang.14000.json','["雨暗商山過客稀，路傍孤店閉柴扉。", "卸鞍良久茅簷下，待得巴人樵採歸。"]'),
('c81ec803-a9a8-44f3-bc37-b992472ccc27','閏春宴花溪嚴侍御莊','戎昱','唐','唐诗','tang','','[]','一團青翠色，云是子陵家。',48,'全唐诗/poet.tang.14000.json','["一團青翠色，云是子陵家。", "山帶新晴雨，溪留閏月花。", "瓶開巾漉酒，地坼筍抽芽。", "綵縟承顏面，朝朝賦白華。"]'),
('bd745b61-3218-4381-b884-413dbe96bfef','歲暮客懷','戎昱','唐','唐诗','tang','','[]','異鄉三十口，親老復家貧。',48,'全唐诗/poet.tang.14000.json','["異鄉三十口，親老復家貧。", "無事乾坤內，虛爲翰墨人。", "歲華南去後，愁夢北來頻。", "惆悵江邊柳，依依又欲春。"]'),
('56e70619-c664-4b02-a77d-a81a0282a48f','秋望興慶宮','戎昱','唐','唐诗','tang','','[]','先皇歌舞地，今日未遊巡。',48,'全唐诗/poet.tang.14000.json','["先皇歌舞地，今日未遊巡。", "幽咽龍池水，淒涼御榻塵。", "隨風秋樹棄，對月老宮人。", "萬事如桑海，悲來欲慟神。"]'),
('36116338-f1db-482b-b7bd-a5df09c7e21d','送鄭鍊師貶辰州','戎昱','唐','唐诗','tang','','[]','辰州萬里外，想得逐臣心。',48,'全唐诗/poet.tang.14000.json','["辰州萬里外，想得逐臣心。", "謫去刑名枉，人間痛惜深。", "誤將瑕指玉，遂使謾消金。", "計日西歸在，休爲澤畔吟。"]'),
('e7c246f6-8c50-43a0-b4ad-6a42a6cf6d7e','雲夢故城秋望','戎昱','唐','唐诗','tang','','[]','故國遺墟在，登臨想舊遊。',48,'全唐诗/poet.tang.14000.json','["故國遺墟在，登臨想舊遊。", "一朝人事變，千載水空流。", "夢渚鴻聲晚，荆門樹色秋。", "片雲凝不散，遙挂望鄉愁。"]'),
('68a790de-580a-426a-bd11-fafca4b1d2c7','秋日感懷','戎昱','唐','唐诗','tang','','[]','洛陽岐路信悠悠，無事辭家兩度秋。',64,'全唐诗/poet.tang.14000.json','["洛陽岐路信悠悠，無事辭家兩度秋。", "日下未馳千里足，天涯徒泛五湖舟。", "菏衣半浸緣鄉淚，玉貌潛銷是客愁。", "說向長安親與故，誰憐歲晚尚淹留。"]'),
('e337bde8-dbb3-4bdd-ab74-a54239fd336b','送王明府入道','戎昱','唐','唐诗','tang','','[]','何事陶彭澤，明時又挂冠。',48,'全唐诗/poet.tang.14000.json','["何事陶彭澤，明時又挂冠。", "爲耽泉石趣，不憚薜蘿寒。", "輕雪籠紗帽，孤猨傍醮壇。", "懸懸老松下，金竈夜燒丹。"]'),
('a319214b-ef7d-41c4-acbd-348c78de54bf','秋月','戎昱','唐','唐诗','tang','','[]','江干入夜杵聲秋，百尺疎桐挂斗牛。',32,'全唐诗/poet.tang.14000.json','["江干入夜杵聲秋，百尺疎桐挂斗牛。", "思苦自看明月苦，人愁不是月華愁。"]'),
('648b7a06-ca8e-44e6-9597-c7d25395b78b','賦得鐵馬鞭','戎昱','唐','唐诗','tang','','[]','成器雖因匠，懷剛本自天。',48,'全唐诗/poet.tang.14000.json','["成器雖因匠，懷剛本自天。", "爲憐持寸節，長擬靜三邊。", "未入英髦用，空存鐵石堅。", "希君剖腹取，還解抱龍泉。"]'),
('1f660a6c-8ebf-427c-b772-e1bb7f90b1ed','聞顔尚書陷賊中','戎昱','唐','唐诗','tang','','[]','聞說征南沒，那堪故吏聞。',48,'全唐诗/poet.tang.14000.json','["聞說征南沒，那堪故吏聞。", "能持蘇武節，不受馬超勳。", "國破無家信，天秋有鴈羣。", "同榮不同辱，今日負將軍。"]'),
('7e6c09bc-04e4-487b-b201-43aaf6955c73','送蘇參軍','戎昱','唐','唐诗','tang','','["\u957f\u6c5f"]','憶昨青襟醉裏分，酒醒迴首愴離羣。',64,'全唐诗/poet.tang.14000.json','["憶昨青襟醉裏分，酒醒迴首愴離羣。", "舟移極浦城初掩，山束長江日早曛。", "客來有恨空思德，別後誰人更議文。", "常歎蘇生官太屈，應緣才似鮑參軍。"]'),
('52327ac2-b9b2-42d7-9fe3-4e8e20e96b34','成都元十八侍御','戎昱','唐','唐诗','tang','','[]','不見元生已數朝，浣花溪路去菲遙。',64,'全唐诗/poet.tang.14000.json','["不見元生已數朝，浣花溪路去菲遙。", "客舍早知渾寂寞，交情豈謂更蕭條。", "空有寸心思會面，恨無單酌遣相邀。", "驊驄幸自能馳驟，何惜揮鞭過柞橋。"]'),
('0d73235b-89f8-4e98-87bc-fe4ce5d21836','觀衛尚書九日對中使射破的','戎昱','唐','唐诗','tang','','[]','盛宴傾黃菊，殊私降紫泥。',72,'全唐诗/poet.tang.14000.json','["盛宴傾黃菊，殊私降紫泥。", "月營開射圃，霜斾拂晴霓。", "出將三朝貴，彎弓五善齊。", "腕迴金鏃滿，的破綠弦低。", "勇氣干牛斗，歡聲震鼓鼙。", "忠臣思報國，更欲取關西。"]'),
('834231ba-8f35-4174-b0e2-673a064b18e1','辰州聞大駕還宮','戎昱','唐','唐诗','tang','','[]','聞道鑾輿歸魏闕，望雲西拜喜成悲。',64,'全唐诗/poet.tang.14000.json','["聞道鑾輿歸魏闕，望雲西拜喜成悲。", "寧知隴水煙銷日，再有園林秋薦時。", "渭水戰添亡虜血，秦人生覩舊朝儀。", "自慚出守辰州畔，不得親隨日月旗。"]'),
('017af722-70e2-4bc6-9a67-d27072e97e52','辰州建中四年多懷','戎昱','唐','唐诗','tang','','[]','荒徼辰陽遠，窮秋瘴雨深。',72,'全唐诗/poet.tang.14000.json','["荒徼辰陽遠，窮秋瘴雨深。", "主恩堪灑血，邊宦更何心。", "海上紅旗滿，生前白髮侵。", "竹寒寧改節，隼靜早因禽。", "務退門多掩，愁來酒獨斟。", "天涯憂國淚，無日不霑襟。"]'),
('476d3cd8-872c-4402-aaaf-1477d6440a41','上桂州李大夫','戎昱','唐','唐诗','tang','','[]','今日辭門館，情將衆別殊。',72,'全唐诗/poet.tang.14000.json','["今日辭門館，情將衆別殊。", "感深翻有淚，仁過曲憐愚。", "晚鏡傷秋鬢，晴寒切病驅。", "煙霞萬里闊，宇宙一身孤。", "倚馬才寧有，登龍意豈無。", "唯於方寸內，暗貯報恩珠。"]'),
('6b54515e-310e-4f31-967a-d27da2ba3991','江城秋霽','戎昱','唐','唐诗','tang','','[]','霽後江城風景涼，豈堪登眺只堪傷。',64,'全唐诗/poet.tang.14000.json','["霽後江城風景涼，豈堪登眺只堪傷。", "遠天螮蝀收殘雨，映水鸕鷀近夕陽。", "萬事無成空過日，十年多難不還鄉。", "不知何處銷茲恨，轉覺愁隨夜夜長。"]'),
('480d7d0b-277f-4ad9-9829-e32b45bca9a7','上李常侍','戎昱','唐','唐诗','tang','','[]','旌旗曉過大江西，七校前驅萬隊齊。',64,'全唐诗/poet.tang.14000.json','["旌旗曉過大江西，七校前驅萬隊齊。", "千里政聲人共喜，三軍令肅馬前嘶。", "恩霑境內風初變，春入城陰柳漸低。", "桃李不須令更種，早知門下舊成蹊。"]'),
('65117882-7972-4508-8f49-8b19e5cf237e','上湖南崔中丞','戎昱','唐','唐诗','tang','','[]','山上青松陌上塵，雲泥豈合得相親。',64,'全唐诗/poet.tang.14000.json','["山上青松陌上塵，雲泥豈合得相親。", "舉世盡嫌良馬瘦，唯君不棄臥龍貧。", "千金未必能移性，一諾從來許殺身。", "莫道書生無感激，寸心還是報恩人。"]'),
('7b72c88d-e4c2-497f-9bba-a37bb3c5060f','早春雪中','戎昱','唐','唐诗','tang','','[]','陰雲萬里晝漫漫，愁坐關心事幾般。',32,'全唐诗/poet.tang.14000.json','["陰雲萬里晝漫漫，愁坐關心事幾般。", "爲報春風休下雪，柳條初放不禁寒。"]'),
('540a0494-c972-4ed4-bae4-8e41cf7ed85e','雲安阻雨','戎昱','唐','唐诗','tang','','["\u957f\u6c5f"]','日長巴峽雨濛濛，又說歸舟路未通。',32,'全唐诗/poet.tang.14000.json','["日長巴峽雨濛濛，又說歸舟路未通。", "遊人不及西江水，先得東流到渚宮。"]'),
('5f467fbb-f8a3-4376-92e9-92b2f15046f6','湖南春日二首 一','戎昱','唐','唐诗','tang','','[]','自憐春日客長沙，江上無人轉憶家。',32,'全唐诗/poet.tang.14000.json','["自憐春日客長沙，江上無人轉憶家。", "光景却添鄉思苦，簷前數片落梅花。"]'),
('b5015a68-8524-4c67-b695-1789956f5084','湖南春日二首 二','戎昱','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','三湘漂寓若流萍，萬里湘鄉隔洞庭。',32,'全唐诗/poet.tang.14000.json','["三湘漂寓若流萍，萬里湘鄉隔洞庭。", "羇客春來心欲碎，東風莫遣柳條青。"]'),
('71d8245b-b88e-4f55-ae81-b876221f74a3','送陸秀才歸覲省','戎昱','唐','唐诗','tang','','[]','武陵何處在，南指楚雲陰。',48,'全唐诗/poet.tang.14000.json','["武陵何處在，南指楚雲陰。", "花蕚連枝近，桃源去路深。", "啼鶯徒寂寂，征馬已駸駸。", "隄上千年柳，條條挂我心。"]'),
('8a9a1fdf-ecbd-4a7c-9fdd-e492202dc13e','戲題秋月','戎昱','唐','唐诗','tang','','[]','秋宵月色勝春宵，萬里天涯靜寂寥。',32,'全唐诗/poet.tang.14000.json','["秋宵月色勝春宵，萬里天涯靜寂寥。", "近來數夜飛霜重，只畏娑婆樹葉凋。"]'),
('9853bee5-ded5-4d64-8ff6-aec3092a97e2','宿湘江','戎昱','唐','唐诗','tang','','[]','九月湘江水漫流，沙邊唯覽月華秋。',32,'全唐诗/poet.tang.14000.json','["九月湘江水漫流，沙邊唯覽月華秋。", "金風浦上吹黃葉，一夜紛紛滿客舟。"]'),
('ed106038-327b-4901-afcc-4ce8c1a8786a','戲贈張使君','戎昱','唐','唐诗','tang','','[]','數載蹉跎罷搢紳，五湖乘興轉迷津。',32,'全唐诗/poet.tang.14000.json','["數載蹉跎罷搢紳，五湖乘興轉迷津。", "如今野客無家第，醉處尋常是主人。"]'),
('9a2be6da-b046-4437-81df-897ace4204e9','別公安賈明府','戎昱','唐','唐诗','tang','','[]','葉縣門前江水深，淺於羇客報恩心。',32,'全唐诗/poet.tang.14000.json','["葉縣門前江水深，淺於羇客報恩心。", "把君詩卷西歸去，一度相思一度吟。"]'),
('d01175b7-4cad-4f15-a884-de6089dc08ad','霽雪','戎昱','唐','唐诗','tang','','["\u5199\u96ea", "\u96ea"]','風卷寒雲暮雪晴，江煙洗盡柳條輕。',32,'全唐诗/poet.tang.14000.json','["風卷寒雲暮雪晴，江煙洗盡柳條輕。", "簷前數片無人埽，又得書窗一夜明。"]'),
('4e519eda-bd1c-4705-982e-b96f19b1a67f','漢陰弔崔員外墳','戎昱','唐','唐诗','tang','','[]','遠別望有歸，葉落望春暉。',84,'全唐诗/poet.tang.14000.json','["遠別望有歸，葉落望春暉。", "所痛泉路人，一去無還期。", "荒墳遺漢陰，墳樹啼子規。", "存沒抱冤滯，孤魂意何依。", "豈無骨肉親，豈無深相知。", "曝露不復問，高名亦何爲。", "相攜慟君罷，春日空遲遲。"]'),
('fc46994f-0a85-42da-ad16-d0dad680e9cd','題槿花','戎昱','唐','唐诗','tang','','[]','自用金錢買槿栽，二年方始得花開。',32,'全唐诗/poet.tang.14000.json','["自用金錢買槿栽，二年方始得花開。", "鮮紅未許佳人見，蝴蝶爭知早到來。"]'),
('ffe1a437-558e-4509-9bd0-fc81f1fb46b0','題宋玉亭','戎昱','唐','唐诗','tang','','[]','宋玉亭前悲暮秋，陽臺路上雨初收。',32,'全唐诗/poet.tang.14000.json','["宋玉亭前悲暮秋，陽臺路上雨初收。", "應緣此處人多別，松竹蕭蕭也帶愁。"]'),
('2e7f084d-492b-4162-9d2d-055ddda51acc','過東平軍','戎昱','唐','唐诗','tang','','[]','畫角初鳴殘照微，營營鞍馬往來稀。',32,'全唐诗/poet.tang.14000.json','["畫角初鳴殘照微，營營鞍馬往來稀。", "相逢士卒皆垂淚，八座朝天何日歸。"]'),
('e26934fb-899d-4d12-aeec-81f11c5e903f','送辰州鄭使君','戎昱','唐','唐诗','tang','','[]','誰人不譴謫，君去獨堪傷。',48,'全唐诗/poet.tang.14000.json','["誰人不譴謫，君去獨堪傷。", "長子家無弟，慈親老在堂。", "驚魂隨驛吏，冒暑向炎方。", "未到猨啼處，參差已斷腸。"]'),
('c76247eb-572b-4fa3-8d38-ab33fe686124','江上柳送人','戎昱','唐','唐诗','tang','','[]','江柳斷腸色，黃絲垂未齊。',48,'全唐诗/poet.tang.14000.json','["江柳斷腸色，黃絲垂未齊。", "人看幾重恨，鳥入一枝低。", "鄉淚正堪落，與君又解攜。", "相思萬里道，春去夕陽西。"]'),
('2f4ea19c-f164-4395-a71a-ba2b615a5cf1','湘南曲','戎昱','唐','唐诗','tang','','[]','虞帝南遊不復還，翠蛾幽怨水雲間。',32,'全唐诗/poet.tang.14000.json','["虞帝南遊不復還，翠蛾幽怨水雲間。", "昨夜月明湘浦宿，閨中珂珮度空山。"]'),
('9f28614a-3847-43c4-beb1-8bdc44216bdf','桂州西山登高上陸大夫','戎昱','唐','唐诗','tang','','[]','登高上山上，高處更堪愁。',48,'全唐诗/poet.tang.14000.json','["登高上山上，高處更堪愁。", "野菊他鄉酒，蘆花滿眼秋。", "風煙連楚郡，兄弟客荆州。", "早晚朝天去，親隨定遠侯。"]'),
('6186f655-bfa7-4d7c-89be-aaf4b2bbe0b2','寄鄭鍊師','戎昱','唐','唐诗','tang','','[]','平生金石友，淪落向辰州。',48,'全唐诗/poet.tang.14000.json','["平生金石友，淪落向辰州。", "已是二年客，那堪終日愁。", "尺書渾不寄，兩鬢計應秋。", "今夜相思月，情人南海頭。"]'),
('73df0a46-898a-42c3-8563-b4fc8bac935c','八月十五日','戎昱','唐','唐诗','tang','','[]','憶昔千秋節，懽娛萬國同。',48,'全唐诗/poet.tang.14000.json','["憶昔千秋節，懽娛萬國同。", "今來六親遠，此日一悲風。", "年少逢胡亂，時平似夢中。", "棃園幾人在，應是涕無窮。"]'),
('49dcf3d5-3f07-42cf-9959-b4d9e34f9ee3','征人歸鄉','戎昱','唐','唐诗','tang','','[]','三月江城柳絮飛，五年遊客送人歸。',32,'全唐诗/poet.tang.14000.json','["三月江城柳絮飛，五年遊客送人歸。", "故將別淚和鄉淚，今日闌干濕汝衣。"]'),
('e3bad56f-a627-4c02-8da4-e59b0a9260a4','駱家亭子納涼','戎昱','唐','唐诗','tang','','[]','江湖思渺然，不離國門前。',48,'全唐诗/poet.tang.14000.json','["江湖思渺然，不離國門前。", "折葦魚沈藻，攀藤鳥出煙。", "生衣宜水竹，小酒入詩篇。", "莫怪侵星坐，神清不欲眠。"]'),
('e1a93d44-c118-4632-ab41-cb284c3f42a4','逢隴西故人憶關中舍弟','戎昱','唐','唐诗','tang','','[]','莫話邊庭事，心摧不欲聞。',48,'全唐诗/poet.tang.14000.json','["莫話邊庭事，心摧不欲聞。", "數年家隴地，舍弟歿胡軍。", "每念支離苦，常嗟骨肉分。", "急難何日見，遙哭隴西雲。"]'),
('005e9a7b-8f96-422b-831e-15334672bcf4','秋夜梁十三廳事','戎昱','唐','唐诗','tang','','[]','今來秋已暮，還恐未成歸。',48,'全唐诗/poet.tang.14000.json','["今來秋已暮，還恐未成歸。", "夢裏家仍遠，愁中葉又飛。", "竹聲風度急，燈影月來微。", "得見梁夫子，心源有所依。"]'),
('bae1f682-4648-483a-ae39-0f8652fe11b8','成都暮雨秋','戎昱','唐','唐诗','tang','','[]','九月龜城暮，愁人閉草堂。',48,'全唐诗/poet.tang.14000.json','["九月龜城暮，愁人閉草堂。", "地卑多雨潤，天暖少秋霜。", "縱欲傾新酒，其如憶故鄉。", "不知更漏意，惟向客邊長。"]'),
('4401141b-88e2-4558-b885-7471d048f527','酬梁二十','戎昱','唐','唐诗','tang','','[]','渚宮無限客，相見獨相親。',48,'全唐诗/poet.tang.14000.json','["渚宮無限客，相見獨相親。", "長路皆同病，無言似一身。", "歲寒唯愛竹，憔悴不堪春。", "細與知音說，攻文恐悞人。"]'),
('1a1771de-2185-4844-869c-9bb5a86f7291','花下宴送鄭鍊師','戎昱','唐','唐诗','tang','','[]','愁裏惜春深，聞幽即共尋。',48,'全唐诗/poet.tang.14000.json','["愁裏惜春深，聞幽即共尋。", "貴看花柳色，圖放別離心。", "客醉花能笑，詩成花伴吟。", "爲君調綠綺，先奏鳳歸林。"]'),
('fdc7375c-009e-4f34-9744-bcbda1b040f6','秋館雨後得弟兄書即事呈李明府','戎昱','唐','唐诗','tang','','[]','弟兄書忽到，一夜喜兼愁。',48,'全唐诗/poet.tang.14000.json','["弟兄書忽到，一夜喜兼愁。", "空館復聞雨，貧家怯到秋。", "坐中孤燭暗，窗外數螢流。", "試以他鄉事，明朝問子游。"]'),
('2c556f12-18ed-483b-a6f3-29e1dfa9dc1e','寄梁淑','戎昱','唐','唐诗','tang','','[]','長憶江頭執別時，論文未有不相思。',64,'全唐诗/poet.tang.14000.json','["長憶江頭執別時，論文未有不相思。", "鴈過經秋無尺素，人來終日見新詩。", "心思食檗何由展，家似流萍任所之。", "悔學秦人南避地，武陵原上又徵師。"]'),
('617a5253-3705-4d08-a743-8a95d7cab1a8','送張秀才之長沙','戎昱','唐','唐诗','tang','','[]','君向長沙去，長沙僕舊諳。',48,'全唐诗/poet.tang.14000.json','["君向長沙去，長沙僕舊諳。", "雖之桂嶺北，終是闕庭南。", "山靄生朝雨，江煙作夕嵐。", "松醪能醉客，慎勿滯湘潭。"]'),
('a83ba434-4d45-4934-90ba-cb9a283c7adf','塞下曲','戎昱','唐','唐诗','tang','','["\u6218\u4e89", "\u8fb9\u585e"]','漢將歸來虜塞空，旌旗初下玉關東。',32,'全唐诗/poet.tang.14000.json','["漢將歸來虜塞空，旌旗初下玉關東。", "高蹄戰馬三千匹，落日平原秋草中。"]'),
('71d73b9a-ef1c-4ba9-90e8-33337c0d3828','送僧法和','戎昱','唐','唐诗','tang','','[]','達士心無滯，他鄉總是家。',36,'全唐诗/poet.tang.14000.json','["達士心無滯，他鄉總是家。", "問經翻貝葉，論法指蓮花。", "欲契真空義，先開智慧芽。"]'),
('a9ecee31-4d9d-4ef2-85c6-d28416d6b482','送嚴十五郎之長安','戎昱','唐','唐诗','tang','','[]','送客身爲客，思家愴別家。',48,'全唐诗/poet.tang.14000.json','["送客身爲客，思家愴別家。", "暫收雙眼淚，遙想五陵花。", "路遠征車迥，山迴劍閣斜。", "長安君到日，春色未應賒。"]'),
('34d04d23-e86c-4f86-bebc-7b01bac06227','冬夜宴梁十三廳','戎昱','唐','唐诗','tang','','[]','故人能愛客，秉燭會吾曹。',48,'全唐诗/poet.tang.14000.json','["故人能愛客，秉燭會吾曹。", "家爲朋徒罄，心緣翰墨勞。", "夜寒銷臘酒，霜冷重綈袍。", "醉臥西窗下，時聞鴈響高。"]'),
('84b06a88-7428-4a32-983c-e38fa9022748','收襄陽城二首 一','戎昱','唐','唐诗','tang','','[]','悲風慘慘雨修修，峴北山低草木愁。',32,'全唐诗/poet.tang.14000.json','["悲風慘慘雨修修，峴北山低草木愁。", "暗發前軍連夜戰，平明旌斾入襄州。"]'),
('ad423cdb-dc3b-4a76-baa9-e9bbe4c42ad6','收襄陽城二首 二','戎昱','唐','唐诗','tang','','[]','五營飛將擁霜戈，百里僵屍滿濜河。',32,'全唐诗/poet.tang.14000.json','["五營飛將擁霜戈，百里僵屍滿濜河。", "日暮歸來看劍血，將軍却恨殺人多。"]'),
('85b2bca2-914a-4f10-91ba-30789d8d1d94','出軍','戎昱','唐','唐诗','tang','','[]','龍繞旌竿獸滿旗，飜營乍似雪中移。',32,'全唐诗/poet.tang.14000.json','["龍繞旌竿獸滿旗，飜營乍似雪中移。", "中軍一隊三千騎，盡是幷州遊俠兒。"]'),
('bf9bf721-cc0b-4b55-85e9-16048840e989','和李尹種葛','戎昱','唐','唐诗','tang','','[]','弱質人皆棄，唯君手自栽。',48,'全唐诗/poet.tang.14000.json','["弱質人皆棄，唯君手自栽。", "藟含霜後竹，香惹臘前梅。", "擬託凌雲勢，須憑接引材。", "清陰如可惜，黃鳥定飛來。"]'),
('cfb4045f-7ced-4d49-8a43-ed45e4360619','送零陵妓','戎昱','唐','唐诗','tang','','[]','寶鈿香蛾翡翠裙，裝成掩泣欲行雲。',32,'全唐诗/poet.tang.14000.json','["寶鈿香蛾翡翠裙，裝成掩泣欲行雲。", "殷勤好取襄王意，莫向陽臺夢使君。"]'),
('201fce61-24c2-4827-b750-b248c13cda8a','採蓮曲二首 一','戎昱','唐','唐诗','tang','','[]','雖聽採蓮曲，詎識採蓮心。',48,'全唐诗/poet.tang.14000.json','["雖聽採蓮曲，詎識採蓮心。", "漾檝愛花遠，回船愁浪深。", "煙生極浦色，日落半江陰。", "同侶憐波靜，看妝墮玉簪。"]'),
('132568c9-a68d-4d29-bfd9-5cf15e080481','採蓮曲二首 二','戎昱','唐','唐诗','tang','','[]','涔陽女兒花滿頭，毿毿同泛木蘭舟。',32,'全唐诗/poet.tang.14000.json','["涔陽女兒花滿頭，毿毿同泛木蘭舟。", "秋風日暮南湖裏，爭唱菱歌不肯休。"]'),
('391be8e3-b30d-4d09-8543-f3bb5ca518eb','塞上曲','戎昱','唐','唐诗','tang','','[]','胡風略地燒連山，碎葉孤城未下關。',32,'全唐诗/poet.tang.14000.json','["胡風略地燒連山，碎葉孤城未下關。", "山頭烽子聲聲呌，知是將軍夜獵還。"]'),
('4df06f66-cbad-4eeb-9ef3-4994697ac17b','寂上人禪房','戎昱','唐','唐诗','tang','','[]','俗塵浮垢閉禪關，百歲身心幾日閑。',32,'全唐诗/poet.tang.14000.json','["俗塵浮垢閉禪關，百歲身心幾日閑。", "安得此生同草木，無營長在四時間。"]'),
('1325f327-c549-4ee8-ad32-5fca704bb474','桂州口號','戎昱','唐','唐诗','tang','','[]','畫角三聲動客愁，曉霜如雪覆江樓。',32,'全唐诗/poet.tang.14000.json','["畫角三聲動客愁，曉霜如雪覆江樓。", "誰道桂林風景暖，到來重著皁貂裘。"]'),
('6a11ee75-1449-47da-9daf-9e950163c0f9','紅槿花','戎昱','唐','唐诗','tang','','[]','花是深紅葉麴塵，不將桃李共爭春。',32,'全唐诗/poet.tang.14000.json','["花是深紅葉麴塵，不將桃李共爭春。", "今日驚秋自憐客，折來持贈少年人。"]'),
('3a1dc503-fff9-4188-90f8-4b337d9411e4','哭黔中薛大夫','戎昱','唐','唐诗','tang','','[]','亞相何年鎮百蠻，生涯萬事瘴雲間。',32,'全唐诗/poet.tang.14000.json','["亞相何年鎮百蠻，生涯萬事瘴雲間。", "夜郎城外誰人哭，昨日空餘旌節還。"]'),
('862104e5-cfeb-4843-9e5f-8bdff6294563','感春','戎昱','唐','唐诗','tang','','[]','看花淚盡知春盡，魂斷看花秪恨春。',32,'全唐诗/poet.tang.14000.json','["看花淚盡知春盡，魂斷看花秪恨春。", "名位未霑身欲老，詩書寧救眼前貧。"]'),
('32c65d8d-2871-4c7f-b2fc-fdeaceefa18e','途中寄李二','戎昱','唐','唐诗','tang','','[]','楊柳煙含灞岸春，年年攀折爲行人。',32,'全唐诗/poet.tang.14000.json','["楊柳煙含灞岸春，年年攀折爲行人。", "好風若借低枝便，莫遣青絲埽路塵。"]'),
('d4ab20d5-7509-4597-b183-d6ac7ff5b596','寄許鍊師','戎昱','唐','唐诗','tang','','[]','埽石焚香禮碧空，露華偏濕蘂珠宮。',32,'全唐诗/poet.tang.14000.json','["埽石焚香禮碧空，露華偏濕蘂珠宮。", "如何說得天壇上，萬里無雲月正中。"]'),
('8dcc6052-2a05-489d-b1b6-468566abe405','下第留辭顧侍郎','戎昱','唐','唐诗','tang','','[]','綺陌彤彤花照塵，王門侯邸盡朱輪。',32,'全唐诗/poet.tang.14000.json','["綺陌彤彤花照塵，王門侯邸盡朱輪。", "城南舊有山村路，欲向雲霞覓主人。"]'),
('671df53a-8f7c-4858-a81b-b940a7f23410','題雲公山房','戎昱','唐','唐诗','tang','','[]','雲公蘭若深山裏，月明松殿微風起。',32,'全唐诗/poet.tang.14000.json','["雲公蘭若深山裏，月明松殿微風起。", "試問空門清淨心，蓮花不著秋潭水。"]'),
('c07af91d-f04b-49d9-bef2-7c385486e059','別離作','戎昱','唐','唐诗','tang','','[]','手把杏花枝，未曾經離別。',24,'全唐诗/poet.tang.14000.json','["手把杏花枝，未曾經離別。", "黃昏掩門後，寂寞自心知。"]'),
('3576fb63-e8ea-41bf-9cec-4b8ac791422c','九日賈明府見訪','戎昱','唐','唐诗','tang','','[]','獨掩衡門秋景閑，洛陽才子訪柴關。',64,'全唐诗/poet.tang.14000.json','["獨掩衡門秋景閑，洛陽才子訪柴關。", "莫嫌濁酒君須醉，雖是貧家菊也斑。", "同人願得長攜手，久客深思一破顏。", "却笑孟嘉吹帽落，登高何必上龍山。"]'),
('699b5dce-f6cd-4580-b5fe-968eaa185c33','開元觀陪杜大夫中元日觀樂','戎昱','唐','唐诗','tang','','[]','今朝歡稱玉京天，況值關東俗理年。',64,'全唐诗/poet.tang.14000.json','["今朝歡稱玉京天，況值關東俗理年。", "舞態疑迴紫陽女，歌聲似遏綵雲仙。", "盤空雙鶴驚几劍，灑砌三花度管弦。", "落日香塵擁歸騎，囗風油幕動高煙。"]'),
('ab4e15ff-7244-4bd0-860e-4622b1feca27','中秋夜登樓望月寄人','戎昱','唐','唐诗','tang','','[]','西樓見月似江城，脈脈悠悠倚檻情。',64,'全唐诗/poet.tang.14000.json','["西樓見月似江城，脈脈悠悠倚檻情。", "萬里此情同皎潔，一年今日最分明。", "初驚桂子從天落，稍誤蘆花帶雪平。", "知稱玉人臨水見，可憐光彩有餘清。"]'),
('922697b6-33fb-4084-bb8f-c3eea4b305d4','贈宜陽張使君','戎昱','唐','唐诗','tang','','[]','暫作宜陽客，深知太守賢。',48,'全唐诗/poet.tang.14000.json','["暫作宜陽客，深知太守賢。", "政移千里俗，人戴兩重天。", "舊郭多新室，閑坡盡辟田。", "倘令黃霸在，今日恥同年。"]'),
('3406eb2f-32d4-432a-95b7-4cdeb6a9aa95','移家別樹','戎昱','唐','唐诗','tang','','[]','千種庭前樹，人移樹不移。',24,'全唐诗/poet.tang.14000.json','["千種庭前樹，人移樹不移。", "看花愁作別，不及未栽時。"]'),
('860346c6-24a9-4614-bc42-eef8b29086d1','成都送嚴十五之江東','戎昱','唐','唐诗','tang','','[]','江東萬里外，別後幾悽悽。',48,'全唐诗/poet.tang.14000.json','["江東萬里外，別後幾悽悽。", "峽路花應發，津亭柳正齊。", "酒傾遲日暮，川闊遠天低。", "心繫征帆上，隨君到剡溪。"]'),
('9d6ae74b-ecff-464d-9692-353e6a83a2a7','送李參軍','戎昱','唐','唐诗','tang','','[]','好住好住王司戶，珍重珍重李參軍。',64,'全唐诗/poet.tang.14000.json','["好住好住王司戶，珍重珍重李參軍。", "一東一西如別鶴，一南一北似浮雲。", "月照疎林千片影，風吹寒水萬里紋。", "別易會難今古事，非是余今獨與君。"]'),
('bf9b9f11-1a5d-492c-a94f-88b9ed59f3eb','題嚴氏竹亭','戎昱','唐','唐诗','tang','','[]','子陵棲遁處，堪繫野人心。',48,'全唐诗/poet.tang.14000.json','["子陵棲遁處，堪繫野人心。", "溪水浸山影，嵐煙向竹陰。", "忘機看白日，留客醉瑤琴。", "愛此多詩興，歸來步步吟。"]'),
('99ab9743-84dc-4e44-a764-cc8d32fae9ec','送王端公之太原歸覲相公','戎昱','唐','唐诗','tang','','[]','柱史今何適，西行詠陟岡。',48,'全唐诗/poet.tang.14000.json','["柱史今何適，西行詠陟岡。", "也知人惜別，終美鴈成行。", "春雨桃花靜，離尊竹葉香。", "到時丞相閣，應喜棣華芳。"]'),
('10b372cf-583f-4e72-9ed6-81bafa8bcdcf','旅次寄湖南張郎中','戎昱','唐','唐诗','tang','','[]','寒江近戶漫流聲，竹影臨窗亂月明。',32,'全唐诗/poet.tang.14000.json','["寒江近戶漫流聲，竹影臨窗亂月明。", "歸夢不知湖水闊，夜來還到洛陽城。"]'),
('1689d325-7e76-4865-862b-6fe65ca9432f','晚次荆江','戎昱','唐','唐诗','tang','','[]','孤舟大江水，水涉無昏曙。',72,'全唐诗/poet.tang.14000.json','["孤舟大江水，水涉無昏曙。", "雨暗迷津時，雲生望鄉處。", "漁翁閑自樂，樵客紛多慮。", "秋色湖上山，歸心日邊樹。", "徒稱竹箭美，未得楓林趣。", "向夕垂釣還，吾從落潮去。"]'),
('4889a0b4-4921-4d09-bab3-b69ae5fb1f5b','同辛衮州巢父虛副端岳相思獻酬之作因紓歸懷兼呈辛魏二院長楊長寧','戎昱','唐','唐诗','tang','','[]','暮角發高城，情人坐中起。',84,'全唐诗/poet.tang.14000.json','["暮角發高城，情人坐中起。", "臨觴不及醉，分散秋風裏。", "雖有明月期，離心若千里。", "前歡反惆悵，後會還如此。", "焉得夜淹留，一回終宴喜。", "羇遊復牽役，館至重湖水。", "早晚泛歸舟，吾從數君子。"]'),
('47d7fa09-8da8-48f0-9f43-f378e4d25fb5','撫州處士湖泛舟送北迴兩指此南昌縣查溪蘭若別','戎昱','唐','唐诗','tang','','[]','移樽鋪山曲，祖帳查溪陰。',72,'全唐诗/poet.tang.14000.json','["移樽鋪山曲，祖帳查溪陰。", "鋪山即遠道，查溪非故林。", "悽然誦新詩，落淚霑素襟。", "郡政我何有，別情君獨深。", "禪庭古樹秋，宿雨清沈沈。", "揮袂故里遠，悲傷去住心。"]'),
('c4e15225-a319-475c-8c6d-7956d09d65b2','耒陽谿夜行','戎昱','唐','唐诗','tang','','[]','乘夕棹歸舟，緣源二轉幽。',48,'全唐诗/poet.tang.14000.json','["乘夕棹歸舟，緣源二轉幽。", "月明看嶺樹，風靜聽溪流。", "嵐氣船間入，霜華衣上浮。", "猨聲雖此夜，不是別家愁。"]'),
('71d4a4e7-c5da-4339-adfe-c1aa309d2dfa','桂城早秋','戎昱','唐','唐诗','tang','','[]','遠客驚秋早，江天夜露新。',48,'全唐诗/poet.tang.14000.json','["遠客驚秋早，江天夜露新。", "滿庭惟有月，空館更何人。", "卜命知身賤，傷寒舞劒頻。", "猨啼曾下淚，可是爲憂貧。"]'),
('7247095c-ceeb-44e4-91e6-663aa7d504f5','桂州歲暮','戎昱','唐','唐诗','tang','','[]','歲暮天涯客，寒窗欲曉時。',48,'全唐诗/poet.tang.14000.json','["歲暮天涯客，寒窗欲曉時。", "君恩空自感，鄉思夢先知。", "重誼人愁別，驚棲鵲戀枝。", "不堪樓上角，南向海風吹。"]'),
('cdea9bf2-da77-4657-a7f7-83521485f165','宿桂州江亭呈康端公','戎昱','唐','唐诗','tang','','[]','獨向東亭坐，三更待月開。',48,'全唐诗/poet.tang.14000.json','["獨向東亭坐，三更待月開。", "螢光入竹去，水影過江來。", "露滴千家靜，年流一葉催。", "龍鐘萬里客，正合故人哀。"]'),
('10bd94bd-1cf5-4974-ac27-163c98993297','寒食日恩賜火','竇叔向','唐','唐诗','tang','','[]','恩光及小臣，華燭忽驚春。',36,'全唐诗/poet.tang.14000.json','["恩光及小臣，華燭忽驚春。", "電影隨中使，星輝拂路人。", "幸因榆柳暖，一照草茅貧。"]'),
('fd50ba7e-1dad-4f2d-bf20-1f00909f5fc2','端午日恩賜百索','竇叔向','唐','唐诗','tang','','[]','仙宮長命縷，端午降殊私。',36,'全唐诗/poet.tang.14000.json','["仙宮長命縷，端午降殊私。", "事盛蛟龍見，恩深犬馬知。", "餘生儻可續，終冀荅明時。"]'),
('a11d8717-13a3-4319-80ca-054d1513be94','貞懿皇后挽歌三首 一','竇叔向','唐','唐诗','tang','','[]','二陵恭婦道，六寢盛皇情。',48,'全唐诗/poet.tang.14000.json','["二陵恭婦道，六寢盛皇情。", "禮遜生前貴，恩追歿後榮。", "幼王親捧土，愛女復連塋。", "東望長如在，誰云向玉京。"]'),
('d4f2beb1-d33f-46b4-9111-aa88723b67a5','貞懿皇后挽歌三首 二','竇叔向','唐','唐诗','tang','','[]','後庭攀畫柳，上陌咽清笳。',48,'全唐诗/poet.tang.14000.json','["後庭攀畫柳，上陌咽清笳。", "命婦羞蘋葉，都人插柰花。", "壽宮星月異，仙路往來賒。", "縱有迎仙術，終悲隔絳紗。"]'),
('5086dcd0-ed5b-47cb-bd82-37664fe4364a','秋砧送邑大夫','竇叔向','唐','唐诗','tang','','[]','斷續長門下，清泠逆旅秋。',48,'全唐诗/poet.tang.14000.json','["斷續長門下，清泠逆旅秋。", "征夫應待信，寒女不勝愁。", "帶月飛城上，因風散陌頭。", "離居偏入聽，況復送歸舟。"]'),
('2fc613af-cb28-4122-9aec-0f6d24954068','過擔石湖','竇叔向','唐','唐诗','tang','','[]','曉發漁門戍，晴看擔石湖。',48,'全唐诗/poet.tang.14000.json','["曉發漁門戍，晴看擔石湖。", "日銜高浪出，天入四空無。", "尺寸分洲島，纖毫指舳艫。", "渺然從此去，誰念客帆孤。"]'),
('d03aa3f4-0260-49c5-8017-e0feffc5e20c','春日早朝應制','竇叔向','唐','唐诗','tang','','[]','紫殿俯千官，春松應合歡。',48,'全唐诗/poet.tang.14000.json','["紫殿俯千官，春松應合歡。", "御爐香焰暖，馳道玉聲寒。", "乳燕翻珠綴，祥烏集露盤。", "宮花一萬樹，不敢舉頭看。"]'),
('e5c55c44-7084-4543-8c1a-98659aec9bfb','酬李袁州嘉祐','竇叔向','唐','唐诗','tang','','[]','少年輕會復輕離，老大開心總是悲。',64,'全唐诗/poet.tang.14000.json','["少年輕會復輕離，老大開心總是悲。", "強說前程聊自慰，未知攜手定何時。", "公才屈指登黃閣，匪服胡顏上赤墀。", "想到長安誦佳句，滿朝誰不念瓊枝。"]'),
('1139c653-caae-4f86-819c-6c990fe83220','夏夜宿表兄話舊','竇叔向','唐','唐诗','tang','','["\u79bb\u522b", "\u8bdd\u65e7", "\u590f\u5929"]','夜合花開香滿庭，夜深微雨醉初醒。',64,'全唐诗/poet.tang.14000.json','["夜合花開香滿庭，夜深微雨醉初醒。", "遠書珍重何曾達，舊事淒涼不可聽。", "去日兒童皆長大，昔年親友半凋零。", "明朝又是孤舟別，愁見河橋酒幔青。"]'),
('366efe25-4e62-4181-89cb-52c3f01b7f3f','句','竇叔向','唐','唐诗','tang','','[]','禁兵環素帟，宮女哭寒雲。',12,'全唐诗/poet.tang.14000.json','["禁兵環素帟，宮女哭寒雲。"]'),
('3a9067ef-c595-412b-8ca7-fff6fb8fdab5','晚次方山精舍却寄張薦員外','竇常','唐','唐诗','tang','','[]','楚臘還無雪，江春又足風。',48,'全唐诗/poet.tang.14000.json','["楚臘還無雪，江春又足風。", "馬羸三逕外，人病四愁中。", "西塞波濤闊，南朝寺舍空。", "猶銜步兵酒，宿醉在除東。"]'),
('63aaf778-c5bd-4d98-a3ec-e223a241d3aa','和裴端公樞蕪城秋夕簡遠近親知','竇常','唐','唐诗','tang','','[]','歲積登朝戀，秋加陋巷貧。',48,'全唐诗/poet.tang.14000.json','["歲積登朝戀，秋加陋巷貧。", "宿酲因夜歇，佳句得愁新。", "盡日憑幽几，何時上軟輪。", "漢廷風憲在，應念匪躬人。"]'),
('49721ff7-6b92-493b-8b57-561c21769727','項亭懷古','竇常','唐','唐诗','tang','','[]','力取誠多難，天亡路亦窮。',48,'全唐诗/poet.tang.14000.json','["力取誠多難，天亡路亦窮。", "有心裁帳下，無面到江東。", "命厄留騅處，年銷逐鹿中。", "漢家神器在，須廢拔山功。"]'),
('f472cf3f-b9c2-4bcb-a4e6-dca80c11bc07','奉使西還早發小磵館寄盧滁州邁','竇常','唐','唐诗','tang','','[]','野棠花覆地，山館夜來陰。',48,'全唐诗/poet.tang.14000.json','["野棠花覆地，山館夜來陰。", "馬蹟穿雲去，雞聲出澗深。", "清風時偃草，久旱或爲霖。", "試與惸嫠話，猶堅借寇心。"]'),
('ff4a8830-564d-4800-849e-102044930605','早發金鉤店寄奚十唐大二茂才','竇常','唐','唐诗','tang','','[]','出門山未曙，風葉暗蕭蕭。',48,'全唐诗/poet.tang.14000.json','["出門山未曙，風葉暗蕭蕭。", "月影臨荒柵，泉聲近廢橋。", "歲經秋後役，程在洛中遙。", "寄謝金門侶，弓旌悞見招。"]'),
('6c71ef5d-2b99-4ece-b3db-deefc25bc346','途中立春寄楊郇伯','竇常','唐','唐诗','tang','','[]','浪跡終年客，驚心此地春。',48,'全唐诗/poet.tang.14000.json','["浪跡終年客，驚心此地春。", "風前獨去馬，澤畔耦耕人。", "老大交情重，悲涼外物親。", "子雲今在宅，應見柳條新。"]'),
('f34943e5-a9e5-4768-8a72-95e6d0b78570','故秘監丹陽郡公延陵包公挽歌詞','竇常','唐','唐诗','tang','','[]','卓絕明時第，孤貞貴後貧。',48,'全唐诗/poet.tang.14000.json','["卓絕明時第，孤貞貴後貧。", "郄詵爲胄子，季札是鄉人。", "筆下調金石，花開領搢紳。", "那堪歸葬日，哭渡柳楊津。"]'),
('3da28c9b-ec8c-469c-ab74-f58aff76b190','涼國惠康公主挽歌','竇常','唐','唐诗','tang','','[]','玉立分堯緒，笄年下相門。',48,'全唐诗/poet.tang.14000.json','["玉立分堯緒，笄年下相門。", "早加于氏對，偏占館陶恩。", "淚有潛成血，香無却返魂。", "共知何駙馬，垂白抱天孫。"]'),
('b4698945-f527-4344-a4b5-af050a413e43','哭張倉曹南史','竇常','唐','唐诗','tang','','[]','萬事竟蹉跎，重泉恨若何。',48,'全唐诗/poet.tang.14000.json','["萬事竟蹉跎，重泉恨若何。", "官臨環衛小，身逐轉蓬多。", "麗藻嘗專席，閑情欲爛柯。", "春風宛陵路，丹旐在滄波。"]'),
('0a5c1cb9-bc53-4eba-97ff-9d7d80910201','北固晚眺','竇常','唐','唐诗','tang','','[]','水國芒種後，梅天風雨涼。',48,'全唐诗/poet.tang.14000.json','["水國芒種後，梅天風雨涼。", "露蠶開晚簇，江燕繞危檣。", "山趾北來固，潮頭西去長。", "年年此登眺，人事幾銷亡。"]'),
('d9caeae0-06ef-4554-9365-9ac1994d91ac','謁三閭廟','竇常','唐','唐诗','tang','','[]','君非三諫寤，禮許一身逃。',48,'全唐诗/poet.tang.14000.json','["君非三諫寤，禮許一身逃。", "自樹終天戚，何裨事主勞。", "衆魚應餌骨，多士盡餔糟。", "有客椒漿奠，文衰不繼騷。"]'),
('57eb4739-d295-4ac7-961e-f7d28f325383','茅山贈梁尊師','竇常','唐','唐诗','tang','','[]','雲屋何年客，青山白日長。',48,'全唐诗/poet.tang.14000.json','["雲屋何年客，青山白日長。", "種花春掃雪，看籙夜焚香。", "上象壺中闊，平生醉裏忙。", "幸承仙籍後，乞取大還方。"]'),
('44c71391-f43b-47cc-836b-038d2d078d30','謁諸葛武侯廟','竇常','唐','唐诗','tang','','[]','永安宮外有祠堂，魚水恩深祚不長。',64,'全唐诗/poet.tang.14000.json','["永安宮外有祠堂，魚水恩深祚不長。", "角立一方初退舍，擬稱三漢更圖王。", "人同過隟無留影，石在窮沙尚啓行。", "歸蜀降吳竟何事，爲陵爲谷共蒼蒼。"]'),
('3ba2af05-1e7d-49cd-98f2-44371a857c6f','奉賀太保岐公承恩致政','竇常','唐','唐诗','tang','','[]','君爲宮保及清時，冠蓋初閑拜武遲。',64,'全唐诗/poet.tang.14000.json','["君爲宮保及清時，冠蓋初閑拜武遲。", "五色詔中宣九德，百僚班外置三師。", "山泉遂性休稱疾，子弟能官各受詞。", "不學鑄金思范蠡，乞言猶許上丹墀。"]'),
('51c06f33-6a09-4f9d-94e1-86d39fd6078a','之任武陵寒食日途次松滋渡先寄劉員外禹錫','竇常','唐','唐诗','tang','','[]','杏花榆莢曉風前，雲際離離上峽船。',64,'全唐诗/poet.tang.14000.json','["杏花榆莢曉風前，雲際離離上峽船。", "江轉數程淹驛騎，楚曾三戶少人煙。", "看春又過清明節，算老重經癸巳年。", "幸得柱山當郡舍，在朝長詠卜居篇。"]'),
('aa155708-e969-4a7f-9a96-800ecc8818b8','奉寄辰州房使君郎中','竇常','唐','唐诗','tang','','[]','漢代文明今盛明，猶將賈傅暫專城。',64,'全唐诗/poet.tang.14000.json','["漢代文明今盛明，猶將賈傅暫專城。", "何妨密旨先符竹，莫是除書誤姓名。", "蝸舍喜時春夢去，隼旟行處瘴江清。", "新年只可三十二，却笑潘郎白髮生。"]'),
('ab240283-ee08-4d82-87d1-6ff1eba30096','立春後言懷招汴州李匡衛推','竇常','唐','唐诗','tang','','[]','閑齋夜擊唾壺歌，試望夷門奈遠何。',64,'全唐诗/poet.tang.14000.json','["閑齋夜擊唾壺歌，試望夷門奈遠何。", "每聽寒笳離夢斷，時窺清鑑旅愁多。", "初驚宵漏丁丁促，已覺春風習習和。", "海內故人君最老，花開鞭馬更相過。"]'),
('e764033f-a731-4cbd-a909-9e1131a02101','奉送職方崔員外攝中丞新羅冊使','竇常','唐','唐诗','tang','','[]','帝命海東使，人行天一涯。',96,'全唐诗/poet.tang.14000.json','["帝命海東使，人行天一涯。", "辨方知木德，開國有金家。", "冊拜申恩重，留歡作限賒。", "順風鯨浪熱，初日錦帆斜。", "夜色潛然火，秋期獨往槎。", "慰安皆喻旨，忠信自無瑕。", "髮美童年髻，簪香子月花。", "便隨琛賮入，正朔在中華。"]'),
('c37dc05d-581f-4234-84e2-06e42f2c733e','酬舍弟牟秋日洛陽官舍寄懷十韻','竇常','唐','唐诗','tang','','[]','幼爲逃難者，纔省用兵初。',120,'全唐诗/poet.tang.14000.json','["幼爲逃難者，纔省用兵初。", "去國三苗外，全生四紀餘。", "老頭親帝里，歸處失吾廬。", "逝水猶嗚咽，祥雲自卷舒。", "正郎曾首拜，亞尹未平除。", "幾變陶家柳，空傳魏闕書。", "思凌天際鶴，言甚轍中魚。", "玉立知求己，金聲乍起予。", "在朝魚水分，多病雪霜居。", "忽報陽春曲，縱橫恨不如。"]'),
('19f067ad-0289-4474-a94a-fe5117350987','求自試','竇常','唐','唐诗','tang','','[]','仙禁祥雲合，高梧彩鳳遊。',72,'全唐诗/poet.tang.14000.json','["仙禁祥雲合，高梧彩鳳遊。", "沈冥求自試，通鑒果蒙收。", "文墨悲無位，詩書誤白頭。", "陳王抗表日，毛遂請行秋。", "雙劍曾埋獄，司空問斗牛。", "希垂拂拭惠，感激願相投。"]'),
('46637ec9-5056-4420-a803-049de567ef82','花發上林','竇常','唐','唐诗','tang','','[]','上苑曉沈沈，花枝亂綴陰。',72,'全唐诗/poet.tang.14000.json','["上苑曉沈沈，花枝亂綴陰。", "色浮雙闕近，春入九門深。", "向暖風初扇，餘寒雪尚侵。", "豔回秦女目，愁處越人心。", "繞繞時縈蝶，關關乍引禽。", "寧知幽谷羽，一舉欲依林。"]'),
('354902b4-ab27-4454-80a8-8b3d63251052','過宋氏五女舊居','竇常','唐','唐诗','tang','','[]','謝庭風韻婕妤才，天縱斯文去不迴。',32,'全唐诗/poet.tang.14000.json','["謝庭風韻婕妤才，天縱斯文去不迴。", "一宅柳花今似雪，鄉人擬築望仙臺。"]'),
('3c13db18-b38e-482f-873e-62fffe754cc0','還京樂歌詞','竇常','唐','唐诗','tang','','[]','百戰初休十萬師，國人西望翠華時。',32,'全唐诗/poet.tang.14000.json','["百戰初休十萬師，國人西望翠華時。", "家家盡唱升平曲，帝幸梨園親製詞。"]'),
('a7351d6b-330a-491a-9180-0251161bead4','商山祠堂即事','竇常','唐','唐诗','tang','','[]','奪嫡心萌事可憂，四賢西笑暫安劉。',32,'全唐诗/poet.tang.14000.json','["奪嫡心萌事可憂，四賢西笑暫安劉。", "後王不敢論珪組，土偶人前枳樹秋。"]'),
('eedd4a88-d1e9-4ec3-a8c3-0f98179658af','七夕','竇常','唐','唐诗','tang','','[]','露盤花水望三星，髣髴虛無爲降靈。',32,'全唐诗/poet.tang.14000.json','["露盤花水望三星，髣髴虛無爲降靈。", "斜漢沒時人不寐，幾條蛛網下風庭。"]'),
('a2a273d6-375f-4d6e-a432-6d6e0a3fb10a','杏山館聽子規','竇常','唐','唐诗','tang','','[]','楚塞餘春聽漸稀，斷猿今夕讓霑衣。',32,'全唐诗/poet.tang.14000.json','["楚塞餘春聽漸稀，斷猿今夕讓霑衣。", "雲埋老樹空山裏，髣髴千聲一度飛。"]'),
('bbd81112-19ef-4466-ae6d-ac8b8c6c30c5','史館候別蔣拾遺不遇','竇牟','唐','唐诗','tang','','[]','千門萬戶迷，佇立月華西。',48,'全唐诗/poet.tang.14000.json','["千門萬戶迷，佇立月華西。", "畫戟晨光動，春松宿露低。", "主文親玉扆，通籍入金閨。", "肯念從戎去，風沙事鼓鞞。"]'),
('9429ffda-4ab2-440b-9d6f-842868680d89','早赴臨臺立馬待漏口號寄弟羣','竇牟','唐','唐诗','tang','','[]','上陌行初盡，嚴城立未開。',48,'全唐诗/poet.tang.14000.json','["上陌行初盡，嚴城立未開。", "人疑早朝去，客是遠方來。", "伏奏徒將命，周行自引才。", "可憐霄漢曙，鴛鷺正徘徊。"]'),
('b0b6e14a-5090-48fc-a8a3-82520d88083b','緱氏拜陵迴道中呈李舍人少尹','竇牟','唐','唐诗','tang','','[]','忽忝諸卿位，仍陪長者車。',48,'全唐诗/poet.tang.14000.json','["忽忝諸卿位，仍陪長者車。", "禮容皆若舊，名籍自憑虛。", "上路花偏早，空山雲甚餘。", "却愁新詠發，酬和不相如。"]'),
('2419551b-8f63-4aec-b422-38c9a9f948a2','陪韓院長韋河南同尋劉師不遇','竇牟','唐','唐诗','tang','','[]','仙客誠難訪，吾人豈易同。',48,'全唐诗/poet.tang.14000.json','["仙客誠難訪，吾人豈易同。", "獨遊應駐景，相顧且吟風。", "藥畹瓊枝秀，齋軒粉壁空。", "不題三五字，何以達壺公。"]'),
('aa856f78-10a9-466e-92d9-12f439b59ed8','送東光呂少府之官連帥奏授','竇牟','唐','唐诗','tang','','[]','遠愛東光縣，平臨若木津。',48,'全唐诗/poet.tang.14000.json','["遠愛東光縣，平臨若木津。", "一城見先日，百里早驚春。", "德禮邀才重，恩輝拜命新。", "幾時裁尺素，滄海有枯鱗。"]'),
('13d84785-9ec0-41b1-baa8-f93cb3ceb566','送劉公達判官赴天德軍幕','竇牟','唐','唐诗','tang','','[]','特建青油幕，量分紫禁師。',48,'全唐诗/poet.tang.14000.json','["特建青油幕，量分紫禁師。", "自然知召子，不用問從誰。", "文武輕車少，腥膻左袵衰。", "北風如有寄，畫取受降時。"]'),
('8e4065e8-4d17-4529-a2c8-21c76c592064','故秘監丹陽郡公延陵包公挽歌','竇牟','唐','唐诗','tang','','[]','台鼎嘗虛位，夔龍莫致堯。',48,'全唐诗/poet.tang.14000.json','["台鼎嘗虛位，夔龍莫致堯。", "德音冥秘府，風韻散清朝。", "天上文星落，林端玉樹凋。", "有吳君子墓，返葬故山遙。"]'),
('b1f2b87d-3dc2-43de-bd75-ef631d40ed64','望終南','竇牟','唐','唐诗','tang','','[]','日愛南山好，時逢夏景殘。',48,'全唐诗/poet.tang.14000.json','["日愛南山好，時逢夏景殘。", "白雲兼似雪，清晝乍生寒。", "九陌峰如墜，千門翠可團。", "欲知形勝盡，都在紫宸看。"]'),
('c95f5bef-8c3c-404d-a4f3-e988c44c3a10','秋夕閑居對雨贈別盧七侍御坦','竇牟','唐','唐诗','tang','','[]','燕燕辭巢蟬蛻枝，窮居積雨壞藩籬。',64,'全唐诗/poet.tang.14000.json','["燕燕辭巢蟬蛻枝，窮居積雨壞藩籬。", "夜長簷霤寒無寢，日晏廚煙溼未炊。", "悟主一言那可學，從軍五首竟徒爲。", "故人驄馬朝天使，洛下秋聲恐要知。"]'),
('2d16a02c-0acb-4699-9d56-1e421e73a01a','晚過敷水驛却寄華州使院張鄭二侍御','竇牟','唐','唐诗','tang','','[]','春雨如煙又若絲，曉來昏處晚晴時。',64,'全唐诗/poet.tang.14000.json','["春雨如煙又若絲，曉來昏處晚晴時。", "仙人掌上芙蓉沼，柱史關西松柏祠。", "幾許歲華銷道路，無窮王事繫戎師。", "迴瞻二妙非吾侶，日對三峰自有期。"]'),
('b33fbf53-eaa8-4223-9712-933d8e4ce990','洛下閑居夜晴觀雪寄四遠諸兄弟','竇牟','唐','唐诗','tang','','[]','雪月相輝雲四開，終風助凍不揚埃。',64,'全唐诗/poet.tang.14000.json','["雪月相輝雲四開，終風助凍不揚埃。", "萬重瓊樹宮中接，一直銀河天上來。", "荆楚歲時知染翰，湘吳醇酎憶銜桮。", "強題縑素無顏色，鴻雁南飛早晚迴。"]'),
('8005e823-4697-4083-b629-431465a59833','天津曉望因寄呈分司一二省郎','竇牟','唐','唐诗','tang','','[]','萬乘西都去，千門正位虛。',72,'全唐诗/poet.tang.14000.json','["萬乘西都去，千門正位虛。", "鑿龍橫碧落，提象出華胥。", "望幸宮嬪老，迎春海燕初。", "保釐纔半仗，容衛盡空廬。", "要自詞難擬，繇來畫不如。", "散郎無所屬，聊事穆清居。"]'),
('a7e6dc31-55cd-4633-bb6c-79a2ea520000','早入朝書事','竇牟','唐','唐诗','tang','','[]','紫陌紛如畫，彤庭鬱未晨。',72,'全唐诗/poet.tang.14000.json','["紫陌紛如畫，彤庭鬱未晨。", "列星沈騎火，殘月暗車塵。", "隱軫排霄翰，差池跨海鱗。", "玉聲繁似樂，香澤散成春。", "歎息驅羸馬，分明識故人。", "一生三不遇，今作老郎身。"]'),
('8522b687-c845-4d15-9e44-b60c3df77707','元日喜聞大禮寄上翰林四學士中書六舍人二十韻','竇牟','唐','唐诗','tang','','[]','有事郊壇畢，無私日月臨。',240,'全唐诗/poet.tang.14000.json','["有事郊壇畢，無私日月臨。", "歲華春更早，天瑞雪猶深。", "玉輦迴時令，金門降德音。", "翰飛鴛別侶，藂植桂爲林。", "粉澤資鴻筆，薰和本素琴。", "禮成戎器下，恩徹鬼方沈。", "麟爵來稱紀，官師退絕箴。", "道風黃閣靜，祥景紫垣陰。", "壽酒朝時獻，農書夜直尋。", "國香煴翠幄，庭燎赩紅衾。", "漢魏文章盛，堯湯雨露霃。", "密辭投水石，精義出沙金。", "宸扆親唯敬，鈞衡近匪侵。", "疾驅千里駿，清唳九霄禽。", "慶賜迎新服，齋莊棄舊簪。", "忽思班女怨，遙聽越人吟。", "末路甘貧病，流年苦滯淫。", "夢中青瑣闥，歸處碧山岑。", "竊抃聞韶濩，觀光想韎任。", "大哉環海晏，不笇子牟心。"]'),
('ad8771af-afaa-4d4e-b342-2c0f00c952c8','奉使至邢州贈李八使君','竇牟','唐','唐诗','tang','','[]','獨占龍岡部，深持虎節居。',96,'全唐诗/poet.tang.14000.json','["獨占龍岡部，深持虎節居。", "盡心敷吏術，含笑掩兵書。", "禮飾華纓重，才牽雅製餘。", "茂陰延驛路，溫液逗官渠。", "南畝行春罷，西樓待客初。", "甕頭開綠蟻，砧下落紅魚。", "牧伯風流足，輶軒若澀虛。", "今宵鈴閣內，醉舞復何如。"]'),
('3b09acbc-a3e5-46bf-ac39-37223c0650e8','秋日洛陽官舍寄上水部家兄','竇牟','唐','唐诗','tang','','[]','洛陽歸老日，此縣忽爲君。',120,'全唐诗/poet.tang.14000.json','["洛陽歸老日，此縣忽爲君。", "白髮兄仍見，丹誠帝豈聞。", "九衢橫逝水，二室散浮雲。", "屈指豪家盡，傷心要地分。", "禁中周幾鼎，源上漢諸墳。", "貔虎今無半，狐狸宿有羣。", "威聲慙北部，仁化樂南薰。", "野檗飢來食，天香靜處焚。", "壯年唯喜酒，幼學便訶文。", "及爾空衰暮，離憂詎可聞。"]'),
('f9446507-663b-42d0-bc29-58689991d1a1','李舍人少尹惠家醖一小榼立書絕句','竇牟','唐','唐诗','tang','','[]','禁瑣天漿嫩，虞行夜月寒。',24,'全唐诗/poet.tang.14000.json','["禁瑣天漿嫩，虞行夜月寒。", "一瓢那可醉，應遣試嘗看。"]'),
('f44beac8-7a2b-46cc-80ba-d0d41254289a','酬舍弟庠罷舉從州辟書','竇牟','唐','唐诗','tang','','[]','之荆且願依劉表，折桂終慙見郄詵。',32,'全唐诗/poet.tang.14000.json','["之荆且願依劉表，折桂終慙見郄詵。", "舍弟未應絲作鬢，園公不用印隨身。"]'),
('bddc3023-f1f9-4dd4-9989-3659395f52a9','奉酬楊侍郎十兄見贈之作','竇牟','唐','唐诗','tang','','[]','翠羽雕蟲日日新，翰林工部欲何神。',32,'全唐诗/poet.tang.14000.json','["翠羽雕蟲日日新，翰林工部欲何神。", "自悲由瑟無彈處，今作關西門下人。"]'),
('578f1206-f3b3-42b3-954a-5c3ce3e0a2c0','杏園渡','竇牟','唐','唐诗','tang','','[]','衛郊多壘少人家，南渡天寒日又斜。',32,'全唐诗/poet.tang.14000.json','["衛郊多壘少人家，南渡天寒日又斜。", "君子素風悲已矣，杏園無復一枝花。"]'),
('f82dfe93-6197-41e4-a77e-a28f715fb498','奉誠園聞笛','竇牟','唐','唐诗','tang','','[]','曾絕朱纓吐錦茵，欲披荒草訪遺塵。',32,'全唐诗/poet.tang.14000.json','["曾絕朱纓吐錦茵，欲披荒草訪遺塵。", "秋風忽灑西園淚，滿目山陽笛裏人。"]'),
('20e24776-a971-4189-a7f0-58ddb785c778','雪中遇直','竇羣','唐','唐诗','tang','','[]','寒光凝雪彩，限直居粉闈。',48,'全唐诗/poet.tang.14000.json','["寒光凝雪彩，限直居粉闈。", "怳疑白雲上，乍覺金印非。", "樹色靄虛空，琴聲諧素徽。", "明晨阻通籍，獨臥挂朝衣。"]'),
('ee2992a9-fe55-4dfc-bde4-4c2493a0fc25','東山月下懷友人','竇羣','唐','唐诗','tang','','[]','東山多喬木，月午始蒼蒼。',96,'全唐诗/poet.tang.14000.json','["東山多喬木，月午始蒼蒼。", "雖殊碧海狀，愛此青苔光。", "高下滅華燭，參差啓洞房。", "佳人夢餘思，寶瑟愁應商。", "皎潔殊未已，沈吟限一方。", "宦情哂雞口，世路倦羊腸。", "彼美金石分，眷言蘭桂芳。", "清暉詎同夕，耿耿但相望。"]'),
('2ea240e7-663a-46c5-894c-e4f529973650','時興','竇羣','唐','唐诗','tang','','[]','夙心曠何許，日暮依林薄。',48,'全唐诗/poet.tang.14000.json','["夙心曠何許，日暮依林薄。", "流水不待人，孤雲時映鶴。", "濛濛千萬花，曷爲神仙藥。", "不遇爛柯叟，報非舊城郭。"]'),
('a7bee2ca-10c5-498b-b577-83265df106c2','題劍','竇羣','唐','唐诗','tang','','[]','丈夫得寶劍，束髮曾書紳。',48,'全唐诗/poet.tang.14000.json','["丈夫得寶劍，束髮曾書紳。", "嗟吁一朝遇，願言千載鄰。", "心許留家樹，辭直斷佞臣。", "焉能爲繞指，拂拭試時人。"]'),
('270bbb78-6460-4d68-82eb-007dd6208f36','黔中書事','竇羣','唐','唐诗','tang','','[]','萬事非京國，千山擁麗譙。',48,'全唐诗/poet.tang.14000.json','["萬事非京國，千山擁麗譙。", "佩刀看日曬，賜馬傍江調。", "言語多重譯，壺觴每獨謠。", "沿流如著翅，不敢問歸橈。"]'),
('3aea5068-c4f2-42ef-9632-69d4ad6c4ad0','冬日曉思寄楊二十七鍊師','竇羣','唐','唐诗','tang','','[]','雨霜地如雪，松桂青參差。',48,'全唐诗/poet.tang.14000.json','["雨霜地如雪，松桂青參差。", "鶴警晨光上，步出南軒時。", "所遇各有適，我懷亦自怡。", "願言緘素封，昨夜夢瓊枝。"]'),
('12d952ff-d24d-4920-86ac-54e2f1404375','貞元末東院嘗接事今西川武相公于茲三周謬領中憲徘徊廳宇多獲文篇夏日即事因寄四韻','竇羣','唐','唐诗','tang','','[]','重軒深似谷，列柏鎮含烟。',48,'全唐诗/poet.tang.14000.json','["重軒深似谷，列柏鎮含烟。", "境絕蒼蠅到，風生白雪前。", "彈冠驚迹近，專席感恩偏。", "霄漢朝來下，油幢路幾千。"]'),
('86f4c1c5-eeb2-4918-b703-19e76a1b4453','北地','竇羣','唐','唐诗','tang','','[]','何事到容州，臨池照白頭。',48,'全唐诗/poet.tang.14000.json','["何事到容州，臨池照白頭。", "興隨年已往，愁與水長流。", "僶俯思逋客，辛勤悔飯牛。", "詩人亦何意，樹草欲忘憂。"]'),
('299e5b62-1036-4f99-83b5-c0759f2fadfa','雨後月下寄懷羊二十七資州','竇羣','唐','唐诗','tang','','[]','夕霽涼飆至，翛然心賞諧。',48,'全唐诗/poet.tang.14000.json','["夕霽涼飆至，翛然心賞諧。", "清光松上月，虛白郡中齋。", "置酒平生在，開衿願見乖。", "殷勤寄雙鯉，夢想入君懷。"]'),
('27acd4eb-d234-4bda-8d30-78c86004f0b6','奉酬西川武相公晨興贈友見示之作','竇羣','唐','唐诗','tang','','[]','碧樹分曉色，宿雨弄清光。',96,'全唐诗/poet.tang.14000.json','["碧樹分曉色，宿雨弄清光。", "猶聞子規啼，獨念一聲長。", "眷眷軫芳思，依依寄遠方。", "情同如蘭臭，惠比返魂香。", "新什驚變雅，古瑟代沈湘。", "殷勤見知己，掩抑繞中腸。", "隙駟不我待，路人易相忘。", "孤老空許國，幽報期蒼蒼。"]'),
('a50c0aa1-9b96-4b81-a58d-5cb371a84d3c','晨游昌師院','竇羣','唐','唐诗','tang','','[]','深庭芳草濃，曉井山泉溢。',72,'全唐诗/poet.tang.14000.json','["深庭芳草濃，曉井山泉溢。", "林馥亂沈煙，石潤侵經室。", "幽巖鳥飛靜，晴嶺雲歸密。", "壁蘚凝蒼華，竹陰滿晴日。", "生期半宵夢，憂緒仍非一。", "若無高世心，安能此終畢。"]'),
('af7a392e-edb9-45cf-b88b-8766ca8d1f73','同王晦伯朱遐景宿慧山寺','竇羣','唐','唐诗','tang','','[]','共訪青山寺，曾隱南朝人。',72,'全唐诗/poet.tang.14000.json','["共訪青山寺，曾隱南朝人。", "問古松桂老，開襟言笑新。", "步移月亦出，水映石磷磷。", "予洗腸中酒，君濯纓上塵。", "皓彩入幽抱，清氣逼蒼旻。", "信此澹忘歸，淹留冰玉鄰。"]'),
('d612e9ac-acf9-40b8-a512-5aba64e89f16','草堂夜坐','竇羣','唐','唐诗','tang','','[]','匣中三尺劍，天上少微星。',24,'全唐诗/poet.tang.14000.json','["匣中三尺劍，天上少微星。", "勿謂相去遠，壯心曾不停。"]'),
('81f44085-e123-4f12-b74a-612d79a6439a','經潼關贈宇文十','竇羣','唐','唐诗','tang','','[]','古有弓旌禮，今徴草澤臣。',24,'全唐诗/poet.tang.14000.json','["古有弓旌禮，今徴草澤臣。", "方同白衣見，不是棄繻人。"]'),
('57dd24d0-ec1c-4ebf-acaf-b6a269a1cfaf','觀畫鶴','竇羣','唐','唐诗','tang','','[]','華亭不相識，衛國復誰知。',24,'全唐诗/poet.tang.14000.json','["華亭不相識，衛國復誰知。", "悵望沖天羽，甘心任畫師。"]'),
('45ece60a-ead8-4699-a3fc-827e0090c01a','晚自臺中歸永寧里南望山色悵然有懷呈上右司十一兄','竇羣','唐','唐诗','tang','','[]','白髮侵侵生有涯，青襟曾愛紫河車。',32,'全唐诗/poet.tang.14000.json','["白髮侵侵生有涯，青襟曾愛紫河車。", "自憐悟主難歸去，馬上看山恐到家。"]'),
('eaff274b-27a4-423b-81c4-cf978e8238e9','中牟縣經魯公廟','竇羣','唐','唐诗','tang','','[]','青史編名在篋中，故林遺廟揖仁風。',32,'全唐诗/poet.tang.14000.json','["青史編名在篋中，故林遺廟揖仁風。", "還將文字如顏色，暫下蒲車爲魯公。"]'),
('ca632d53-d4c4-41c3-a8e7-82f9c48cfd29','初入諫司喜家室至','竇羣','唐','唐诗','tang','','[]','一旦悲歡見孟光，十年辛苦伴滄浪。',32,'全唐诗/poet.tang.14000.json','["一旦悲歡見孟光，十年辛苦伴滄浪。", "不知筆硯緣封事，猶問傭書日幾行。"]'),
('ba98bbbe-d045-47a4-a5f5-71e6774a7f10','春雨','竇羣','唐','唐诗','tang','','[]','昨日偷閑看花了，今朝多雨奈人何。',32,'全唐诗/poet.tang.14000.json','["昨日偷閑看花了，今朝多雨奈人何。", "人間盡似逢花雨，莫愛芳菲濕綺羅。"]'),
('6823906c-1d26-47d6-9c5b-7b32f9c222f6','送內弟袁德師','竇羣','唐','唐诗','tang','','[]','南渡登州即水仙，西垣有客思悠然。',32,'全唐诗/poet.tang.14000.json','["南渡登州即水仙，西垣有客思悠然。", "因君相問爲官意，不賣毗陵負郭田。"]'),
('8ec2fe12-1ce8-4362-a646-3ad851f606b8','贈劉大兄院長','竇羣','唐','唐诗','tang','','[]','萬年枝下昔同趨，三事行中半已無。',32,'全唐诗/poet.tang.14000.json','["萬年枝下昔同趨，三事行中半已無。", "路自長沙忽相見，共驚雙鬢別來殊。"]'),
('36303fd2-798f-45a4-998b-8da64a9b592d','假日尋花','竇羣','唐','唐诗','tang','','[]','武陵緣源不可到，河陽帶縣詎堪誇。',32,'全唐诗/poet.tang.14000.json','["武陵緣源不可到，河陽帶縣詎堪誇。", "枝枝如雪南關外，一日休閑盡屬花。"]'),
('1a2d5516-1205-4cd7-ad75-85146f5f0e3d','自京將赴黔南','竇羣','唐','唐诗','tang','','[]','風雨荆州二月天，問人初雇峽中船。',32,'全唐诗/poet.tang.14000.json','["風雨荆州二月天，問人初雇峽中船。", "西南一望雲和水，猶道黔南有四千。"]'),
('a9b8aff6-0170-45b7-8962-49cd4e6d46f3','留守府酬皇甫曙侍御彈琴之什','竇庠','唐','唐诗','tang','','[]','青瑣晝無塵，碧梧陰似水。',120,'全唐诗/poet.tang.14000.json','["青瑣晝無塵，碧梧陰似水。", "高張朱弦琴，靜舉白玉指。", "洞簫又奏繁，寒磬一聲起。", "鶴警風露中，泉飛雪雲裏。", "泠泠分雅鄭，析析諧宮徵。", "座客無俗心，巢禽亦傾耳。", "衛國知有人，齊竽偶相齒。", "有時趨絳紗，盡日隨朱履。", "那令雜繁手，出假求焦尾。", "幾載遺正音，今朝自君始。"]'),
('7408655a-9045-4e1d-8602-a6e9930dda7e','金山行','竇庠','唐','唐诗','tang','','[]','西江中𤃩波四截，湧出一峰青堞㙞。',320,'全唐诗/poet.tang.14000.json','["西江中𤃩波四截，湧出一峰青堞㙞。", "外如削成中缺裂，陽氣發生陰氣結。", "是時炎天五六月，上有火雲下冰雪。", "夜色晨光相蕩沃，積翠流霞滿坑谷。", "龍泓徹底沙布金，鳥道插雲梯甃玉。", "架險凌虛隨指顧，榱桷玲瓏皆固護。", "斡流倒景不可窺，萬仞千崖生跬步。", "日華重重上金牓，丹楹碧砌真珠網。", "此時天海風浪清，吳楚萬家皆在掌。", "瓊樓菌閣紛明媚，曲檻迴軒深且邃。", "海鳥夜上珊瑚枝，江花曉落瑠璃地。", "有時倒影沈江底，萬狀分明光似洗。", "不知水上有樓臺，却就波中看閉啓。", "舟人忘却江水深，水神誤到人間世。", "歘然風生波出沒，瀖濩晶瑩無定物。", "居人相顧非人間，如到日宮經月窟。", "信知靈景長有靈，住者不得無仙骨。", "三神山上蓬萊宮，徒有丹青人未逢。", "何如此處靈山宅，清涼不與囂塵隔。", "曾到金山處處行，夢魂長羨金山客。"]'),
('3368a8d5-11ac-41ab-92d4-c7327b2d9c42','于闐鐘歌送靈徹上人歸越','竇庠','唐','唐诗','tang','','[]','海中有國傾神功，烹金化成九乳鐘。',192,'全唐诗/poet.tang.14000.json','["海中有國傾神功，烹金化成九乳鐘。", "精氣激射聲沖瀜，護持海底諸魚龍。", "聲有感，神無方，連天雲水無津梁。", "不知飛在靈嘉寺，一國之人皆若狂。", "東南之美天下傳，環文萬象無雕鐫。", "有靈飛動不敢懸，鎖在危樓五百年。", "有時清秋日正中，繁霜滿地天無風。", "一聲洞徹八音盡，萬籟悄然星漢空。", "徒言凡質千鈞重，一夫之力能振動。", "大鳴小鳴須在君，不撃不考終不聞。", "高僧訪古稽山曲，終日當之言不足。", "手提文鋒百鍊成，恐刜此鐘無一聲。"]'),
('abbe283c-9c0d-41e4-a4e2-864f693b8389','太原送穆質南遊','竇庠','唐','唐诗','tang','','[]','今朝天景清，秋入晉陽城。',48,'全唐诗/poet.tang.14000.json','["今朝天景清，秋入晉陽城。", "露葉離披處，風蟬三數聲。", "那言苦行役，值此遠徂征。", "莫話心中事，相看氣不平。"]'),
('d09d57f9-e7ee-4088-8cf0-06423f1dede0','四皓驛聽琴送王師簡歸湖南使幕','竇庠','唐','唐诗','tang','','[]','朱弦韻正調，清夜似聞韶。',48,'全唐诗/poet.tang.14000.json','["朱弦韻正調，清夜似聞韶。", "山館月猶在，松枝雪未消。", "城笳三奏曉，別鶴一聲遙。", "明日思君處，春泉翻寂寥。"]'),
('ebd4fddc-e8e9-4168-aafa-f619edab62bb','夜行古戰場','竇庠','唐','唐诗','tang','','[]','山斷塞初平，人言古戰庭。',48,'全唐诗/poet.tang.14000.json','["山斷塞初平，人言古戰庭。", "泉冰聲更咽，陰火燄偏青。", "月落雲沙黑，風迴草木腥。", "不知秦與漢，徒欲弔英靈。"]'),
('6d843e05-dc54-4fd9-beb9-44f188b596b3','奉和王侍郎春日喜李侍郎崔給諫張舍人韋諫議見訪因命觴觀樂之什','竇庠','唐','唐诗','tang','','[]','華館遲嘉賓，逢迎淑景新。',48,'全唐诗/poet.tang.14000.json','["華館遲嘉賓，逢迎淑景新。", "錦筵開絳帳，玉佩下朱輪。", "曲裏三仙會，風前百囀春。", "欲知忘味處，共仰在齊人。"]'),
('cf98fca8-9bf1-4af4-bd35-e51bfe7f09ed','酬謝韋卿二十五兄俯贈輙敢書情','竇庠','唐','唐诗','tang','','[]','大賢持贈一明璫，蓬蓽初驚滿室光。',64,'全唐诗/poet.tang.14000.json','["大賢持贈一明璫，蓬蓽初驚滿室光。", "埋沒劍中生紫氣，塵埃瑟上動清商。", "荆山璞在終應識，楚國人知不是狂。", "莫恨伏轅身未老，會將筋力是王良。"]'),
('73580ea1-a063-4466-8b63-0de5df05f082','奉酬侍御家兄東洛閑居夜晴觀雪之什','竇庠','唐','唐诗','tang','','[]','洛陽宮觀與天齊，雪淨雲消月未西。',64,'全唐诗/poet.tang.14000.json','["洛陽宮觀與天齊，雪淨雲消月未西。", "清淺乍分銀漢近，輝光漸覺玉繩低。", "綠醽乍熟堪聊酌，黃竹篇成好命題。", "應念武關山斷處，空愁簿領候晨雞。"]'),
('6b84e662-24d1-458b-b941-6292d4cebfd3','勅目至家兄蒙淮南僕射杜公奏授祕校兼節度參謀同書寄上','竇庠','唐','唐诗','tang','','[]','朝市三千里，園廬二十春。',96,'全唐诗/poet.tang.14000.json','["朝市三千里，園廬二十春。", "步兵終日飲，原憲四時貧。", "桂樹留人久，蓬山入夢新。", "鶴書承處重，鵲語喜時頻。", "草奏才偏委，嘉謀事最親。", "榻因徐孺解，醴爲穆生陳。", "衛國今多士，荆州好寄身。", "煙霄定從此，非假問陶鈞。"]'),
('58ffa746-f851-44c4-8c0d-03c652af0c08','酬韓愈侍郎登岳陽樓見贈','竇庠','唐','唐诗','tang','','["\u5cb3\u9633\u697c"]','巨浸連空闊，危樓在杳冥。',240,'全唐诗/poet.tang.14000.json','["巨浸連空闊，危樓在杳冥。", "稍分巴子國，欲近老人星。", "昏旦呈新候，川原按舊經。", "地圖封七澤，天限鎖重扃。", "萬象皆歸掌，三光豈遁形。", "月車纔碾浪，日御已翻溟。", "落照金成柱，餘霞翠擁屏。", "夜光疑漢曲，寒韻辨湘靈。", "山晚雲常碧，湖春草徧青。", "軒黃曾舉樂，范蠡幾揚舲。", "有客初留鷁，貪程尚數蓂。", "自當徐孺榻，不是謝公亭。", "雅論冰生水，雄材刃發硎。", "座中瓊玉潤，名下茝蘭馨。", "假手誠知拙，齋心匪蹔寧。", "每慙公府粟，却憶故山苓。", "苦調當三歎，知音願一聽。", "自悲由也瑟，敢墜孔悝銘。", "野杏初成雪，松醪正滿瓶。", "莫辭今日醉，長恨古人醒。"]'),
('737b0475-54f2-49b9-98a4-818210c1daa3','東都嘉量亭獻留守韓僕射','竇庠','唐','唐诗','tang','','[]','卜築三川上，儀刑萬井中。',168,'全唐诗/poet.tang.14000.json','["卜築三川上，儀刑萬井中。", "度材垂後儉，選勝揜前功。", "雲構中央起，煙波四面通。", "乍疑游汗漫，稍似入崆垌。", "廛閈高低盡，山河表裏窮。", "峰戀從地碧，宮觀倚天紅。", "靈檻如朝蜃，飛橋狀晚虹。", "曙霞晴錯落，夕靄溼葱蘢。", "庾亮樓何阨，陳蕃榻更崇。", "有時閑講德，永日靜觀風。", "玉斝飛無算，金鐃奏未終。", "重筵開玳瑁，上客集鵷鴻。", "接武空慙蹇，修文敢並雄。", "豈須登峴首，然後奉羊公。"]'),
('59b12556-e0ae-4efc-b04d-ff84c2a9510a','段都尉別業','竇庠','唐','唐诗','tang','','[]','曾識將軍段匹磾，幾場花下醉如泥。',32,'全唐诗/poet.tang.14000.json','["曾識將軍段匹磾，幾場花下醉如泥。", "春來欲問林園主，桃李無言鳥自啼。"]'),
('c0a32a7d-3522-42e4-be72-40eddf5786c2','靈臺鎮贈丘岑中丞','竇庠','唐','唐诗','tang','','[]','曉日天山雪半晴，紅旗遙識漢家營。',32,'全唐诗/poet.tang.14000.json','["曉日天山雪半晴，紅旗遙識漢家營。", "近來胡騎休南牧，羊馬城邊春草生。"]'),
('c3ef108b-0a12-4a43-81bd-6ac8343e9005','贈道芬上人','竇庠','唐','唐诗','tang','','[]','雲濕烟封不可闚，畫時唯有鬼神知。',32,'全唐诗/poet.tang.14000.json','["雲濕烟封不可闚，畫時唯有鬼神知。", "幾回逢著天台客，認得巖西最老枝。"]'),
('2fea221b-ed32-4a50-96f3-41051ad17d74','金山寺','竇庠','唐','唐诗','tang','','[]','一點青螺白浪中，全依水府與天通。',32,'全唐诗/poet.tang.14000.json','["一點青螺白浪中，全依水府與天通。", "晴江萬里雲飛盡，鼇背參差日氣紅。"]'),
('d4b7a12f-e8cf-4b33-80c4-721c2ed298e5','冬夜寓懷寄王翰林','竇庠','唐','唐诗','tang','','[]','滿地霜蕪葉下枝，幾回吟斷四愁詩。',32,'全唐诗/poet.tang.14000.json','["滿地霜蕪葉下枝，幾回吟斷四愁詩。", "漢家若欲論封禪，須及相如未病時。"]'),
('818b27fd-fde0-41c4-a105-34ccf37b714c','醉中贈符載','竇庠','唐','唐诗','tang','','[]','白社會中嘗共醉，青雲路上未相逢。',32,'全唐诗/poet.tang.14000.json','["白社會中嘗共醉，青雲路上未相逢。", "時人莫小池中水，淺處無妨有臥龍。"]'),
('81ceffd6-17ec-4943-a65a-44722d53b32c','龍門看花','竇庠','唐','唐诗','tang','','[]','無葉無枝不見空，連天撲地逕纔通。',32,'全唐诗/poet.tang.14000.json','["無葉無枝不見空，連天撲地逕纔通。", "山鶯驚起酒醒處，火焰燒人雪噴風。"]'),
('2fb57fa4-2bb1-461a-9a25-608fcd7d98aa','陪留守韓僕射巡內至上陽宮感興二首 一','竇庠','唐','唐诗','tang','','[]','翠輦西歸七十春，玉堂珠綴儼埃塵。',32,'全唐诗/poet.tang.14000.json','["翠輦西歸七十春，玉堂珠綴儼埃塵。", "武皇弓劍埋何處，泣問上陽宮裏人。"]'),
('f7c65d95-22c0-4a97-8d8f-6751499e441f','陪留守韓僕射巡內至上陽宮感興二首 二','竇庠','唐','唐诗','tang','','[]','愁雲漠漠草離離，太乙句陳處處疑。',32,'全唐诗/poet.tang.14000.json','["愁雲漠漠草離離，太乙句陳處處疑。", "薄暮毀垣春雨裏，殘花猶發萬年枝。"]'),
('a00b60a6-b250-4976-a73f-7a9e9143cada','老將行','竇鞏','唐','唐诗','tang','','[]','烽煙猶未盡，年鬢暗相催。',48,'全唐诗/poet.tang.14000.json','["烽煙猶未盡，年鬢暗相催。", "輕敵心空在，彎弓手不開。", "馬依秋草病，柳傍故營摧。", "唯有酬恩客，時聽說劍來。"]'),
('bbd23478-6266-4d6d-8512-2452ab78454d','贈蕭都官','竇鞏','唐','唐诗','tang','','[]','蕭郎自小賢，愛客不言錢。',48,'全唐诗/poet.tang.14000.json','["蕭郎自小賢，愛客不言錢。", "有酒輕寒夜，無愁倚少年。", "閑尋織錦字，醉上看花船。", "好是關身事，從人道性偏。"]'),
('7e12accc-65d0-4e58-8e96-92fc7ebe74e7','忝職武昌初至夏口書事獻府主相公','竇鞏','唐','唐诗','tang','','[]','白髮放橐鞬，梁王愛舊全。',48,'全唐诗/poet.tang.14000.json','["白髮放橐鞬，梁王愛舊全。", "竹籬江畔宅，梅雨病中天。", "時奉登樓讌，閑脩上水船。", "邑人興謗易，莫遣鶴支錢。"]'),
('4a76d057-df50-42d3-982c-130b2714cfa9','早秋江行','竇鞏','唐','唐诗','tang','','[]','迴望湓城遠，西風吹荻花。',48,'全唐诗/poet.tang.14000.json','["迴望湓城遠，西風吹荻花。", "暮潮江勢闊，秋雨鴈行斜。", "多醉渾無夢，頻愁欲到家。", "漸驚雲樹轉，數點是晨鵶。"]'),
('c94fe3c3-46bd-4078-84d6-7a3736a1da9d','題任處士幽居','竇鞏','唐','唐诗','tang','','[]','紅葉江邨夕，孤煙草舍貧。',48,'全唐诗/poet.tang.14000.json','["紅葉江邨夕，孤煙草舍貧。", "水清魚識釣，林靜犬隨人。", "採掇山無主，扶持藥有神。", "客來唯勸酒，蝴蝶是前身。"]'),
('af111f10-be8c-49d8-81ae-66c0ecc9b1bb','漢陰驛與宇文十相遇旋歸西川因以贈別','竇鞏','唐','唐诗','tang','','[]','吳蜀何年別，相逢漢水頭。',48,'全唐诗/poet.tang.14000.json','["吳蜀何年別，相逢漢水頭。", "望鄉心共醉，握手淚先流。", "宿霧千山曉，春霖一夜愁。", "離情方浩蕩，莫說去刀州。"]'),
('1ec72e2d-aafc-455e-9c50-9c9025ebbddc','早春松江野望','竇鞏','唐','唐诗','tang','','[]','江邨風雪霽，曉望忽驚春。',48,'全唐诗/poet.tang.14000.json','["江邨風雪霽，曉望忽驚春。", "畊地人來早，營巢鵲語頻。", "帶花移樹小，插槿作籬新。", "何事勝無事，窮通任此身。"]'),
('8567a02f-6dcb-40a7-9b31-0bb9dacc08fc','少婦詞','竇鞏','唐','唐诗','tang','','[]','坐惜年光變，遼陽信未通。',48,'全唐诗/poet.tang.14000.json','["坐惜年光變，遼陽信未通。", "燕迷新畫屋，春識舊花叢。", "夢繞天山外，愁翻錦字中。", "昨來誰是伴，鸚鵡在簾櫳。"]'),
('033addbc-9038-41fb-b22b-b342d3125092','歲晚喜遠兄弟至書情','竇鞏','唐','唐诗','tang','','[]','幾年滄海別，相見竟多違。',48,'全唐诗/poet.tang.14000.json','["幾年滄海別，相見竟多違。", "鬢髮緣愁白，音書爲嬾稀。", "新詩徒有贈，故國未同歸。", "人事那堪問，無言是與非。"]'),
('f29c7073-7f1c-4772-8f5d-348fe1f71d79','登玉鈎亭奉獻淮南李相公','竇鞏','唐','唐诗','tang','','[]','西南城上高高處，望月分明似玉鈎。',64,'全唐诗/poet.tang.14000.json','["西南城上高高處，望月分明似玉鈎。", "朱檻人雲看鳥滅，綠楊如薺遶江流。", "定知有客嫌陳榻，從此無人上庾樓。", "今日卷簾天氣好，不勞騎馬看揚州。"]'),
('b6bf3b29-a210-4644-9ac4-51c39dac7751','南陽道中作','竇鞏','唐','唐诗','tang','','[]','東風雨洗順陽川，蜀錦花開綠草田。',64,'全唐诗/poet.tang.14000.json','["東風雨洗順陽川，蜀錦花開綠草田。", "彩雉鬬時頻駐馬，酒旗翻處亦留錢。", "新晴日照山頭雪，薄暮人爭渡口船。", "早晚到家春欲盡，今年寒食月初圓。"]'),
('6bb3998d-a042-4f94-a079-1088d91d9896','哭呂衡州八郎中','竇鞏','唐','唐诗','tang','','[]','今朝血淚問蒼蒼，不分先悲旅館喪。',64,'全唐诗/poet.tang.14000.json','["今朝血淚問蒼蒼，不分先悲旅館喪。", "人送劍來歸隴上，鴈飛書去呌衡陽。", "還家路遠兒童小，埋玉泉深晝夜長。", "望盡素車秋草外，欲將身贖返魂香。"]'),
('f33d56e8-fd4d-4ddc-a921-deb26d1c66c3','江陵遇元九李六二侍御紀事書情呈十二韻','竇鞏','唐','唐诗','tang','','[]','自見人相愛，如君愛我稀。',144,'全唐诗/poet.tang.14000.json','["自見人相愛，如君愛我稀。", "好閑容問道，攻短每言非。", "夢想何曾間，追歡未省違。", "看花憐後到，避酒許先歸。", "柳寺春堤遠，津橋曙月微。", "漁翁隨去處，禪客共因依。", "蓬閣初疑義，霜臺晚畏威。", "學深通古字，心直觸危機。", "肯滯荆州掾，猶香柏署衣。", "山連巫峽秀，田傍渚宮肥。", "美玉方齊價，遷鸎尚怯飛。", "佇看霄漢上，連步侍彤闈。"]'),
('caddcfff-de58-4a1f-b9e9-66272b91e3b0','遊仙詞','竇鞏','唐','唐诗','tang','','[]','海上神山綠，溪邊杏樹紅。',24,'全唐诗/poet.tang.14000.json','["海上神山綠，溪邊杏樹紅。", "不知何處去，月照玉樓空。"]'),
('2880523b-e82b-412b-ad58-ef7f091cdc10','贈阿史那都尉','竇鞏','唐','唐诗','tang','','[]','較獵燕山經幾春，雕弓白羽不離身。',32,'全唐诗/poet.tang.14000.json','["較獵燕山經幾春，雕弓白羽不離身。", "年來馬上渾無力，望見飛鴻指似人。"]'),
('69f112a7-d4fd-4d75-abcd-6b844ff50049','陝府賓堂覽房杜二公仁壽年中題紀手跡','竇鞏','唐','唐诗','tang','','[]','仁壽元和二百年，濛籠水墨淡如煙。',32,'全唐诗/poet.tang.14000.json','["仁壽元和二百年，濛籠水墨淡如煙。", "當時憔悴題名日，漢祖龍潛未上天。"]'),
('30428270-29d0-4a3f-9047-04b82a556a3e','早春送宇文十歸吳','竇鞏','唐','唐诗','tang','','[]','春遲不省似今年，二月無花雪滿天。',32,'全唐诗/poet.tang.14000.json','["春遲不省似今年，二月無花雪滿天。", "村店閉門何處宿，夜深遙喚渡江船。"]'),
('7da486ab-de29-4f31-b870-33d7e323d2ce','經竇車騎故城','竇鞏','唐','唐诗','tang','','[]','荒陂古堞欲千年，名振圖書劍在泉。',32,'全唐诗/poet.tang.14000.json','["荒陂古堞欲千年，名振圖書劍在泉。", "今日諸孫拜墳樹，愧無文字續燕然。"]'),
('406e0eed-8fcf-4132-baae-eb8bc64b60b9','贈王氏小兒','竇鞏','唐','唐诗','tang','','[]','竹林會裏偏憐小，淮水清時最覺賢。',32,'全唐诗/poet.tang.14000.json','["竹林會裏偏憐小，淮水清時最覺賢。", "莫倚兒童輕歲月，丈人曾共爾同年。"]'),
('c8362bc0-7333-4d58-a939-23e9e85ab075','唐州東途作','竇鞏','唐','唐诗','tang','','[]','綠林兵起結愁雲，白羽飛書未解紛。',32,'全唐诗/poet.tang.14000.json','["綠林兵起結愁雲，白羽飛書未解紛。", "天子欲開三面網，莫將弓箭射官軍。"]'),
('bf127bb7-0ba6-4ab9-b4bb-58cbd3b25dc2','新羅進白鷹','竇鞏','唐','唐诗','tang','','[]','御馬新騎禁苑秋，白鷹來自東海頭。',32,'全唐诗/poet.tang.14000.json','["御馬新騎禁苑秋，白鷹來自東海頭。", "漢皇無事須游獵，雪亂爭飛錦臂韝。"]'),
('37d095cc-67cc-489b-8446-2a98034a99fa','秋夕','竇鞏','唐','唐诗','tang','','[]','護霜雲映月朦朧，烏鵲爭飛井上桐。',32,'全唐诗/poet.tang.14000.json','["護霜雲映月朦朧，烏鵲爭飛井上桐。", "半夜酒醒人不覺，滿池荷葉動秋風。"]'),
('dfb8c500-4eb8-4816-9b13-91d292ad9c6f','襄陽寒食寄宇文籍','竇鞏','唐','唐诗','tang','','["\u601d\u5ff5", "\u6625\u5929", "\u5199\u666f", "\u5bd2\u98df\u8282"]','煙水初銷見萬家，東風吹柳萬條斜。',32,'全唐诗/poet.tang.14000.json','["煙水初銷見萬家，東風吹柳萬條斜。", "大堤欲上誰相伴，馬踏春泥半是花。"]'),
('1b19c7b4-897a-421d-9e1d-0595c4f9143b','奉使薊門','竇鞏','唐','唐诗','tang','','[]','自從身屬富人侯，蟬噪槐花已四秋。',32,'全唐诗/poet.tang.14000.json','["自從身屬富人侯，蟬噪槐花已四秋。", "今日一莖新白髮，懶騎官馬到幽州。"]'),
('c82d762e-06ba-49f0-a269-a428d788af85','送劉禹錫','竇鞏','唐','唐诗','tang','','[]','十年憔悴武陵溪，鶴病深林玉在泥。',32,'全唐诗/poet.tang.14000.json','["十年憔悴武陵溪，鶴病深林玉在泥。", "今日太行平似砥，九霄初倚入雲梯。"]'),
('2988c85a-0b86-4acd-831d-ed3dbb523a9c','送元稹西歸','竇鞏','唐','唐诗','tang','','[]','南州風土滯龍媒，黃紙初飛勅字來。',32,'全唐诗/poet.tang.14000.json','["南州風土滯龍媒，黃紙初飛勅字來。", "二月曲江連舊宅，阿婆情熟牡丹開。"]'),
('376bb1ed-f0cc-4f98-9a95-a4995eb54bd7','過驪山','竇鞏','唐','唐诗','tang','','[]','翠輦紅旌去不回，蒼蒼宮樹鎖青苔。',32,'全唐诗/poet.tang.14000.json','["翠輦紅旌去不回，蒼蒼宮樹鎖青苔。", "有人說得當時事，曾見長生玉殿開。"]'),
('950a0be4-e2bd-4834-9c1f-f3bc0925c2ea','洛中即事','竇鞏','唐','唐诗','tang','','[]','高梧葉盡鳥巢空，洛水潺湲夕照中。',32,'全唐诗/poet.tang.14000.json','["高梧葉盡鳥巢空，洛水潺湲夕照中。", "寂寂天橋車馬絕，寒鴉飛入上陽宮。"]'),
('44c6924e-ffd3-4606-86df-58614f76dc7c','尋道者所隱不遇','竇鞏','唐','唐诗','tang','','[]','籬外涓涓澗水流，槿花半點夕陽收。',32,'全唐诗/poet.tang.14000.json','["籬外涓涓澗水流，槿花半點夕陽收。", "欲題名字知相訪，又恐芭蕉不奈秋。"]'),
('6a909e96-1fba-40ff-a743-0be626e045a6','寄南游兄弟','竇鞏','唐','唐诗','tang','','[]','書來未報幾時還，知在三湘五嶺間。',32,'全唐诗/poet.tang.14000.json','["書來未報幾時還，知在三湘五嶺間。", "獨立衡門秋水闊，寒鴉飛去日銜山。"]'),
('979a9120-0007-46b3-9b89-fe7ed88f262a','宮人斜','竇鞏','唐','唐诗','tang','','[]','離宮路遠北原斜，生死恩深不到家。',32,'全唐诗/poet.tang.14000.json','["離宮路遠北原斜，生死恩深不到家。", "雲雨今歸何處去，黃鸝飛上野棠花。"]'),
('dfbbe938-68c4-49ba-9868-ae245d49e881','代鄰叟','竇鞏','唐','唐诗','tang','','[]','年來七十罷耕桑，就暖支羸強下牀。',32,'全唐诗/poet.tang.14000.json','["年來七十罷耕桑，就暖支羸強下牀。", "滿眼兒孫身外事，閑梳白髮對殘陽。"]'),
('6ea977bb-f841-413f-a4de-4de2047c2fdc','新營別墅寄家兄','竇鞏','唐','唐诗','tang','','[]','懶性如今成野人，行藏由興不由身。',32,'全唐诗/poet.tang.14000.json','["懶性如今成野人，行藏由興不由身。", "莫驚此度歸來晚，買得西山正值春。"]'),
('2f40d75d-64d0-4baf-9a3c-ab93efa2e720','南游感興','竇鞏','唐','唐诗','tang','','[]','傷心欲問前朝事，惟見江流去不回。',32,'全唐诗/poet.tang.14000.json','["傷心欲問前朝事，惟見江流去不回。", "日暮東風春草綠，鷓鴣飛上越王臺。"]'),
('0513d467-c578-4a77-a793-3789852c09b7','題劍津','竇鞏','唐','唐诗','tang','','[]','風前推折千年劍，巖下澄空萬古潭。',32,'全唐诗/poet.tang.14000.json','["風前推折千年劍，巖下澄空萬古潭。", "雙劍變成龍化去，兩溪相並水歸南。"]'),
('8e44e405-1497-4a50-8d60-2a6d66979a92','放魚','竇鞏','唐','唐诗','tang','','["\u957f\u6c5f"]','金錢贖得免刀痕，聞道禽魚亦感恩。',32,'全唐诗/poet.tang.14000.json','["金錢贖得免刀痕，聞道禽魚亦感恩。", "好去長江千萬里，不須辛苦上龍門。"]'),
('73e9c6a8-0703-4a8f-bc26-b75cba63baab','永寧小園寄接近校書','竇鞏','唐','唐诗','tang','','[]','故里心期奈別何，手栽芳樹憶庭柯。',32,'全唐诗/poet.tang.14000.json','["故里心期奈別何，手栽芳樹憶庭柯。", "東臯黍熟君應醉，梨葉初紅白露多。"]'),
('7677dd13-ce55-4662-a36d-7e4367fe597b','從軍別家','竇鞏','唐','唐诗','tang','','[]','自笑儒生著戰袍，書齋壁上挂弓刀。',32,'全唐诗/poet.tang.14000.json','["自笑儒生著戰袍，書齋壁上挂弓刀。", "如今便是征人婦，好織迴文寄竇滔。"]'),
('f9a86bfc-4d1c-46d2-9672-a68c01bdb546','悼妓東東','竇鞏','唐','唐诗','tang','','[]','芳菲美豔不禁風，未到春殘已墜紅。',32,'全唐诗/poet.tang.14000.json','["芳菲美豔不禁風，未到春殘已墜紅。", "惟有側輪車上鐸，耳邊長似呌東東。"]'),
('7e29d72b-7386-48c6-af3c-9dafd02f0665','木蘭歌','韋元甫','唐','唐诗','tang','','[]','木蘭抱杼嗟，借問復爲誰。',276,'全唐诗/poet.tang.14000.json','["木蘭抱杼嗟，借問復爲誰。", "欲聞所戚戚，感激彊其顏。", "老父隸兵籍，氣力日衰耗。", "豈足萬里行，有子復尚少。", "胡沙沒馬足，朔風裂人膚。", "老父舊羸病，何以彊自扶。", "木蘭代父去，秣馬備戎行。", "易却紈綺裳，洗却鉛粉妝。", "馳馬赴軍幕，慷慨攜干將。", "朝屯雪山下，暮宿青海傍。", "夜襲燕支虜，更攜于闐羌。", "將軍得勝歸，士卒還故鄉。", "父母見木蘭，喜極成悲傷。", "木蘭能承父母顏，却卸巾韝理絲簧。", "昔爲烈士雄，今爲嬌子容。", "親戚持酒賀父母，始知生女與男同。", "門前舊軍都，十年共崎嶇。", "本結弟兄交，死戰誓不渝。", "今者見木蘭，言聲雖是顏貌殊。", "驚愕不敢前，歎息徒嘻吁。", "世有臣子心，能如木蘭節。", "忠孝兩不渝，千古之名焉可滅。"]'),
('4c612a51-0ac3-4166-bad1-90d6e4cb6def','登越王樓見喬公詩偶題','王鋌','唐','唐诗','tang','','[]','雲架重樓出郡城，虹梁雅韻仲宣情。',64,'全唐诗/poet.tang.14000.json','["雲架重樓出郡城，虹梁雅韻仲宣情。", "越王空置千年跡，丞相兼揚萬古名。", "過鳥時時衝客會，閑風往往弄江聲。", "謬將蹇步尋高躅，魚目驪珠豈繼明。"]'),
('6fbf5886-20e6-4195-9899-6519701f126f','清如玉壺冰','潘炎','唐','唐诗','tang','','[]','琰玉性惟堅，成壺體更圓。',96,'全唐诗/poet.tang.14000.json','["琰玉性惟堅，成壺體更圓。", "虛心含景象，應物受寒泉。", "溫潤資天質，清貞稟自然。", "日融光乍散，雪照色逾鮮。", "至鑒功寧宰，無私照豈偏。", "明將冰鏡對，白與粉花連。", "拂拭終爲美，提攜佇見傳。", "勿令毫髪累，遺恨鮑公篇。"]'),
('463d0e24-1294-4095-9126-f63581c7b834','長至日上公獻壽','張叔良','唐','唐诗','tang','','[]','鳳闕晴鐘動，雞人曉漏長。',72,'全唐诗/poet.tang.14000.json','["鳳闕晴鐘動，雞人曉漏長。", "九重初啓鑰，三事正稱觴。", "日至龍顏近，天旋聖曆昌。", "休光連雪淨，瑞氣雜爐香。", "化被君臣洽，恩霑士庶康。", "不因稽舊典，誰得紀朝章。"]'),
('8ac6a38f-b5ff-466b-abc3-6e5b79065dc4','涇渭揚清濁','呂牧','唐','唐诗','tang','','[]','涇渭橫秦野，逶迤近帝城。',72,'全唐诗/poet.tang.14000.json','["涇渭橫秦野，逶迤近帝城。", "二渠通作潤，萬戶映皆清。", "明晦看殊色，潺湲聽一聲。", "岸虛深草掩，波五曉煙輕。", "御獵思投釣，漁歌好濯纓。", "合流知禹力，同共到滄瀛。"]'),
('085a79ec-8601-4046-864b-b57fc3b42a21','別張賈','韋夏卿','唐','唐诗','tang','','[]','束簡下高閣，買符驅短轅。',48,'全唐诗/poet.tang.14000.json','["束簡下高閣，買符驅短轅。", "故人惜分袂，結念醉芳罇。", "切切別思纏，蕭蕭征騎煩。", "臨歸無限意，相視却忘言。"]'),
('c1b16e7a-797f-4fae-bba1-6c32ab049271','送顧況歸茅山','韋夏卿','唐','唐诗','tang','','[]','聖代爲遷客，虛皇作近臣。',48,'全唐诗/poet.tang.14000.json','["聖代爲遷客，虛皇作近臣。", "法尊稱大洞，學淺忝初真。", "鸞鳳文章麗，煙霞翰墨新。", "羨君尋句曲，白鵠是三神。"]'),
('4f05eaa6-cf58-4b2d-9f01-6f727e93195f','和丘員外題湛長史舊居','韋夏卿','唐','唐诗','tang','','[]','道勝物能齊，累輕身易退。',72,'全唐诗/poet.tang.14000.json','["道勝物能齊，累輕身易退。", "苟安一丘上，何必三山外。", "雲霞長若綺，松石常如黛。", "徒有昔王過，竟遺青史載。", "詩因埜寺詠，酒向山椒酹。", "異時逢爾知，茲辰駐余斾。"]'),
('edd69f24-037f-4b76-bedb-ad0318728fb3','同韋夏卿送顧況歸茅山','綦毋誠','唐','唐诗','tang','','[]','謫宦聞嘗賦，遊仙便作詩。',48,'全唐诗/poet.tang.14000.json','["謫宦聞嘗賦，遊仙便作詩。", "白銀雙闕戀，青竹一龍騎。", "先入茅君洞，旋過葛稚陂。", "無然列禦寇，五日有還期。"]'),
('8ec90746-56f1-4b99-88f6-e50eb1370c0f','感秋','姚倫','唐','唐诗','tang','','[]','試向疎林望，方知節候殊。',48,'全唐诗/poet.tang.14000.json','["試向疎林望，方知節候殊。", "亂聲千葉下，寒影一巢孤。", "不蔽秋天雁，驚飛夜月烏。", "霜風與春日，幾度遣榮枯。"]'),
('e00c3fe2-c986-42d1-82ae-545dc80ba583','過章秀才洛陽客舍','姚倫','唐','唐诗','tang','','[]','達人心自適，旅舍當閑居。',48,'全唐诗/poet.tang.14000.json','["達人心自適，旅舍當閑居。", "不出來時徑，重看讀了書。", "晚山嵐色近，斜日樹陰疎。", "盡是忘言客，聽君誦子虛。"]'),
('8c04f1f8-3b37-480a-9d10-9b900fc31055','賦得生芻一束','于結','唐','唐诗','tang','','[]','比玉人應重，爲芻物自輕。',72,'全唐诗/poet.tang.14000.json','["比玉人應重，爲芻物自輕。", "向風傾弱葉，裛露示纖莖。", "蒨練宜春景，芊綿對雨情。", "每慙蘋藻用，多謝𦶜蘭榮。", "孺子才雖遠，公孫策未行。", "諮詢如不棄，終冀及微生。"]'),
('bf49a4f6-6042-42b4-9597-952a754996a1','賦得生芻一束','鄭孺華','唐','唐诗','tang','','[]','孫弘期射策，長倩贈生芻。',72,'全唐诗/poet.tang.14000.json','["孫弘期射策，長倩贈生芻。", "至潔心將比，忘憂道不孤。", "芝蘭方入室，蕭艾莫同途。", "馥馥香猶在，青青色更殊。", "芳寧九春歇，薰豈十年無。", "葑菲如堪採，山苗自可逾。"]'),
('75da1e65-31e2-42b3-b58c-82c8dc22efe3','空靈岸','張叔卿','唐','唐诗','tang','','[]','寒盡鴻先去，江迴客未歸。',48,'全唐诗/poet.tang.14000.json','["寒盡鴻先去，江迴客未歸。", "早知名是幻，不敢繡爲衣。", "霧積川原暗，山多郡縣稀。", "今朝下湘岸，更逐鷓鴣飛。"]'),
('b1d0fce9-3927-4646-85b1-89e1ba7b5af6','流桂州','張叔卿','唐','唐诗','tang','','[]','莫問蒼梧遠，而今世路難。',24,'全唐诗/poet.tang.14000.json','["莫問蒼梧遠，而今世路難。", "胡塵不到處，即是小長安。"]'),
('348d058b-22e9-44c4-9645-8c736626ee14','酬竇大閑居見寄','房孺復','唐','唐诗','tang','','[]','來自三湘到五溪，青楓無樹不猨啼。',64,'全唐诗/poet.tang.14000.json','["來自三湘到五溪，青楓無樹不猨啼。", "名慙竹使宦情少，路隔桃源歸思迷。", "鵩鳥賦成知性命，鯉魚書至恨暌攜。", "煩君強著潘年比，騎省風流詎可齊。"]'),
('93f2be4f-627b-4451-84fb-590727d5b8a5','送妓人出家','楊郇伯','唐','唐诗','tang','','[]','盡出花鈿與四隣，雲鬟剪落厭殘春。',64,'全唐诗/poet.tang.14000.json','["盡出花鈿與四隣，雲鬟剪落厭殘春。", "暫驚風燭難留世，便是蓮花不染身。", "貝葉欲翻迷錦字，梵聲初學悞梁塵。", "從今豔色歸空後，湘浦應無解珮人。"]'),
('2fa7f347-fca0-4972-8cd9-3f792f76418a','宿北樂館','陳潤','唐','唐诗','tang','','[]','欲眠不眠夜深淺，越鳥一聲空山遠。',64,'全唐诗/poet.tang.14000.json','["欲眠不眠夜深淺，越鳥一聲空山遠。", "庭木蕭蕭落葉時，溪聲雨聲聽不辨。", "溪流潺潺雨習習，燈影山光滿窗入。", "棟里不知渾是雲，曉來但覺衣裳濕。"]'),
('7ef56b5d-6cad-4297-bae0-712a661e30a2','東都所居寒食下作','陳潤','唐','唐诗','tang','','[]','江南寒食早，二月杜鵑鳴。',48,'全唐诗/poet.tang.14000.json','["江南寒食早，二月杜鵑鳴。", "日暖山初綠，春寒雨欲晴。", "浴蠶當社日，改火待清明。", "更喜瓜田好，令人憶邵平。"]'),
('aa479a59-7529-4209-86e5-33f0eec4678c','登西靈塔','陳潤','唐','唐诗','tang','','[]','塔廟出招提，登臨碧海西。',48,'全唐诗/poet.tang.14000.json','["塔廟出招提，登臨碧海西。", "不知人意遠，漸覺鳥飛低。", "稍與雲霞近，如將日月齊。", "遷喬未得意，徒欲躡雲梯。"]'),
('0cb7c128-e0d0-427e-9d8d-d2e07185e6a8','送駱徵君','陳潤','唐','唐诗','tang','','[]','野人膺辟命，溪上掩柴扉。',48,'全唐诗/poet.tang.14000.json','["野人膺辟命，溪上掩柴扉。", "黃卷猶將去，青山豈更歸。", "馬留苔蘚迹，人脫薜蘿衣。", "他日相思處，天邊望少微。"]'),
('8fca99c7-a467-43a6-8893-4f2151ec902a','賦得浦外虹送人','陳潤','唐','唐诗','tang','','[]','日影化爲虹，彎彎出浦東。',48,'全唐诗/poet.tang.14000.json','["日影化爲虹，彎彎出浦東。", "一條微雨後，五色片雲中。", "輪勢隨天度，橋形跨海通。", "還將飲水處，持送使車雄。"]'),
('01ccb79c-73c2-4109-9ff5-f10c302fe5d6','賦得秋河曙耿耿','陳潤','唐','唐诗','tang','','[]','晚望秋高夜，微明欲曙河。',48,'全唐诗/poet.tang.14000.json','["晚望秋高夜，微明欲曙河。", "橋成鵲已去，機罷女應過。", "月上殊開練，雲行類動波。", "尋源不可到，耿耿復如何。"]'),
('2fb6ad8a-32a4-4c59-b0ff-01abe0e3db65','賦得池塘生春草','陳潤','唐','唐诗','tang','','[]','謝公遺詠處，池水夾通津。',48,'全唐诗/poet.tang.14000.json','["謝公遺詠處，池水夾通津。", "古往人何在，年來草自春。", "色宜波際綠，香愛雨中新。", "今日青青意，空悲行路人。"]'),
('49f054a5-f141-4fe7-94d6-7f7b43d7f494','闕題','陳潤','唐','唐诗','tang','','[]','丈夫不感恩，感恩寧有淚。',24,'全唐诗/poet.tang.14000.json','["丈夫不感恩，感恩寧有淚。", "心頭感恩血，一滴染天地。"]'),
('3182d857-499a-4f62-89f1-aa628eaf63e3','哭長孫侍郎','杜誦','唐','唐诗','tang','','[]','道爲詩書重，名因賦頌雄。',48,'全唐诗/poet.tang.14000.json','["道爲詩書重，名因賦頌雄。", "禮闈曾擢桂，憲府既乘驄。", "流水生涯盡，浮雲世事空。", "唯餘舊臺柏，蕭瑟九原中。"]'),
('fdeaedca-0899-4ffb-b368-a3396acdd350','明皇帝挽歌','鄭丹','唐','唐诗','tang','','[]','律曆千年會，車書萬里同。',50,'全唐诗/poet.tang.14000.json','["律曆千年會，車書萬里同。", "固期常戴日，豈意厭觀風。", "地慘新[疆]理，城摧舊戰功。", "山河萬古壯，今夕盡歸空。"]'),
('5f985fc4-d1f2-46e5-a6e3-4670d491f802','肅宗挽歌','鄭丹','唐','唐诗','tang','','[]','國以重明受，天從諒闇移。',48,'全唐诗/poet.tang.14000.json','["國以重明受，天從諒闇移。", "諸侯方北面，白日忽西馳。", "龍影當泉落，鴻名向廟垂。", "永言青史上，還見戴無爲。"]'),
('4d11fa50-fb4a-41b0-b664-cde7559db342','落花','鄭昈','唐','唐诗','tang','','[]','早春見花枝，朝朝恨發遲。',48,'全唐诗/poet.tang.14000.json','["早春見花枝，朝朝恨發遲。", "直看花落盡，却意未開時。", "以此方人世，彌令感盛衰。", "始知山簡遶，頻向習家池。"]'),
('2ed9d032-88fc-465d-a637-3a344fcad426','宿新安江深渡館寄鄭州王使君','朱長文','唐','唐诗','tang','','[]','霜飛十月中，搖落衆山空。',36,'全唐诗/poet.tang.14000.json','["霜飛十月中，搖落衆山空。", "孤館閉寒木，大江生夜風。", "賦詩忙有意，沈約在關東。"]'),
('31c61891-a0a4-498c-94e0-14c21e58c55e','春眺揚州西上崗寄徐員外','朱長文','唐','唐诗','tang','','[]','蕪城西眺極蒼流，漠漠春煙間曙樓。',48,'全唐诗/poet.tang.14000.json','["蕪城西眺極蒼流，漠漠春煙間曙樓。", "瓜步早潮吞建業，蒜山晴雪照揚州。", "隋家故事不能問，鶴在仙池期我游。"]'),
('da9e6e6d-2045-449f-873b-df89c5f651dc','送李司直歸浙東幕兼寄鮑將軍','朱長文','唐','唐诗','tang','','[]','翩翩書記早曾聞，二十年來願見君。',64,'全唐诗/poet.tang.14000.json','["翩翩書記早曾聞，二十年來願見君。", "今日相逢悲白髮，同時幾許在青雲。", "人從北固山邊去，水到西陵渡口分。", "會作王門曳裾客，爲余前謝鮑將軍。"]'),
('b23745d0-e2f1-4f9b-b5b7-84a392435426','望中有懷','朱長文','唐','唐诗','tang','','[]','龍向洞中銜雨出，鳥從花里帶香飛。',32,'全唐诗/poet.tang.14000.json','["龍向洞中銜雨出，鳥從花里帶香飛。", "白雲斷處見明月，黃葉落時聞擣衣。"]'),
('62c7a1de-a9e7-467f-8b9c-1a99461197b4','題虎丘山西寺','朱長文','唐','唐诗','tang','','[]','王氏家山昔在茲，陸機爲賦陸雲詩。',32,'全唐诗/poet.tang.14000.json','["王氏家山昔在茲，陸機爲賦陸雲詩。", "青蓮香匝東西宇，日月與僧無盡時。"]'),
('cb5fee21-36d3-4208-ad6e-662a54617b79','吳興送梁補闕歸朝賦得荻花','朱長文','唐','唐诗','tang','','[]','柳家汀洲孟冬月，雲寒水清荻花發。',32,'全唐诗/poet.tang.14000.json','["柳家汀洲孟冬月，雲寒水清荻花發。", "一枝持贈朝天人，願比蓬萊殿前雪。"]'),
('ad873e5d-356a-4a12-a846-392768fb408a','句','朱長文','唐','唐诗','tang','','[]','夜靜忽疑身是夢，更聞寒雨滴芭蕉。',16,'全唐诗/poet.tang.14000.json','["夜靜忽疑身是夢，更聞寒雨滴芭蕉。"]'),
('657adab1-891f-4ad7-8570-10676fef36ec','獨不見','戴叔倫','唐','唐诗','tang','','[]','前宮路非遠，舊苑春將遍。',60,'全唐诗/poet.tang.14000.json','["前宮路非遠，舊苑春將遍。", "玉戶看早梅，雕梁數飛燕。", "身輕逐舞袖，香暖傳歌扇。", "自和秋風詞，長侍昭陽殿。", "誰信後庭人，年年獨不見。"]'),
('00f98159-5ac5-4f50-8d26-d4089f3f37d1','去婦怨','戴叔倫','唐','唐诗','tang','','[]','出戶不敢啼，風悲日悽悽。',72,'全唐诗/poet.tang.14000.json','["出戶不敢啼，風悲日悽悽。", "心知恩義絕，誰忍分明別。", "下坂車轔轔，畏逢鄉里親。", "空持牀前幔，却寄家中人。", "忽辭王吉去，爲是秋胡死。", "若比今日情，煩冤不相似。"]'),
('429c51a1-78e9-4603-9efa-b8e829358610','古意','戴叔倫','唐','唐诗','tang','','[]','悠悠南山雲，濯濯東流水。',72,'全唐诗/poet.tang.14000.json','["悠悠南山雲，濯濯東流水。", "念我平生歡，託居在東里。", "失既不足憂，得亦不爲喜。", "安貧固其然，處賤寧獨恥。", "雲閑虛我心，水清澹吾味。", "雲水俱無心，斯可長伉儷。"]'),
('c79193be-38e8-4c79-8ac1-b7d3a4fb7933','南野','戴叔倫','唐','唐诗','tang','','[]','治田長山下，引流坦溪曲。',120,'全唐诗/poet.tang.14000.json','["治田長山下，引流坦溪曲。", "東山有遺塋，南野起新築。", "家世素業儒，子孫鄙食祿。", "披雲朝出畊，帶月夜歸讀。", "身勩竟亡疲，團團欣在目。", "野芳綠可採，泉美清可掬。", "茂樹延晚涼，早田候秋熟。", "茶烹松火紅，酒吸荷杯綠。", "解佩臨清池，撫琴看修竹。", "此懷誰與同，此樂君所獨。"]'),
('127a633c-22c0-45a6-af3f-21a31f284d5a','曾遊','戴叔倫','唐','唐诗','tang','','[]','泊舟古城下，高閣快登眺。',72,'全唐诗/poet.tang.14000.json','["泊舟古城下，高閣快登眺。", "大江會彭蠡，羣峰豁玄嶠。", "清影涵空明，黛色凝遠照。", "碑留太史書，詞刻長公調。", "絕粒感楚囚，丹衷猶照耀。", "懷哉不可招，憑闌一悲嘯。"]'),
('8d6c1cb6-7549-4bd4-922d-fc9fb9ba2340','江行','戴叔倫','唐','唐诗','tang','','[]','漾舟晴川裏，挂席候風生。',72,'全唐诗/poet.tang.14000.json','["漾舟晴川裏，挂席候風生。", "臨泛何容與，愛此江水清。", "蘆洲隱遙嶂，露日映孤城。", "自顧疎野性，屢忘鷗鳥情。", "聊復於時顧，暫欲解塵纓。", "驅馳非吾願，虛懷浩已盈。"]'),
('63dd89a3-64b9-4705-9fd8-53ee15cdff0f','孤鴻篇','戴叔倫','唐','唐诗','tang','','[]','江上雙飛鴻，飲啄行相隨。',120,'全唐诗/poet.tang.14000.json','["江上雙飛鴻，飲啄行相隨。", "翔風一何厲，中道傷其雌。", "顧影明月下，哀鳴聲正悲。", "已無矰𥐊患，豈乏稻梁資。", "嗈嗈慕儔匹，遠集清江湄。", "中有孤文鵷，翩翩好容儀。", "共欣相知遇，畢志同棲遲。", "野田鴟鴞鳥，相妒復相疑。", "鴻志不汝較，奮翼起高飛。", "焉隨腐鼠欲，負此雲霄期。"]'),
('3c54e9c9-a444-4f49-b8a2-b55e5ae801cc','感懷二首 一','戴叔倫','唐','唐诗','tang','','[]','尺帛無長裁，淺水無長流。',72,'全唐诗/poet.tang.14000.json','["尺帛無長裁，淺水無長流。", "水淺易成枯，帛短誰人收。", "人生取舍間，趨競固非優。", "舊交跡雖疎，中心自云稠。", "新交意雖密，中道生怨尤。", "踟躕復踟躕，世路今悠悠。"]'),
('2d36c933-4e04-4829-8a6f-6adc77204e84','感懷二首 二','戴叔倫','唐','唐诗','tang','','[]','主人飲君酒，勸君弗相違。',72,'全唐诗/poet.tang.14000.json','["主人飲君酒，勸君弗相違。", "但當盡弘量，觴至無復辭。", "人生百年中，會合能幾時。", "不見枝上花，昨滿今漸稀。", "花落還再開，人老無少期。", "古來賢達士，飲酒不復疑。"]'),
('8b6db087-2999-4f42-9877-67c2a4cfde45','喜雨','戴叔倫','唐','唐诗','tang','','[]','閑居倦時燠，開軒俯平林。',84,'全唐诗/poet.tang.14000.json','["閑居倦時燠，開軒俯平林。", "雷聲殷遙空，雲氣布層陰。", "川上風雨來，灑然滌煩襟。", "田家共歡笑，溝澮亦已深。", "團團聚鄰曲，斗酒相與斟。", "樵歌野田中，漁釣滄江潯。", "蒼天暨有念，悠悠終我心。"]'),
('a6f2e24d-b2cb-412e-b579-a48f0e20b961','歎葵花','戴叔倫','唐','唐诗','tang','','[]','今日見花落，明日見花開。',36,'全唐诗/poet.tang.14000.json','["今日見花落，明日見花開。", "花開能向日，花落委蒼苔。", "自不同凡卉，看時幾日迴。"]'),
('19a657e3-0b2b-4c6b-b69b-14057f346891','從軍行','戴叔倫','唐','唐诗','tang','','[]','丈夫四方志，結髮事遠游。',96,'全唐诗/poet.tang.14000.json','["丈夫四方志，結髮事遠游。", "遠游歷燕薊，獨戍邊城陬。", "西風壠水寒，明月關山悠。", "酬恩仗孤劍，十年弊貂裘。", "封侯屬何人，磋跎雪盈頭。", "老馬思故櫪，窮鱗憶深流。", "彈鋏動深慨，浩歌氣橫秋。", "報國期努力，功名良見收。"]');
